(function() {
var et_ch_1_Verses = [
  {num:1,words:[["Ma o lenei,", "And now I,"], ["o au, o Moronae ,", "Moroni,"], ["ou te faaauau e tuu atu se tala e uiga ia i latou o tagata anamua o e na faaumatia e le aao o le Alii i luga o lenei laueleele i matu.", "proceed to give an account of those ancient inhabitants who were destroyed by the hand of the Lord upon the face of this north country."]]},
  {num:2,words:[["Ma ou te sii mai lau tala mai papatusi e luasefulu ma le fa ia na maua e tagata o Limae,", "And I take mine account from the twenty and four plates which were found by the people of Limhi,"], ["lea ua taua o le Tusi a Eteru.", "which is called the Book of Ether."]]},
  {num:3,words:[["Ma ona ua ou manatu o le vaega muamua o lenei talafaamaumau,", "And as I suppose that the first part of this record,"], ["lea ua tautala e uiga i le foafoaga o le lalolagi,", "which speaks concerning the creation of the world,"], ["ma Atamu foi,", "and also of Adam,"], ["ma se tala mai lena taimi e oo mai lava i le olo tele,", "and an account from that time even to the great tower,"], ["ma soo se mea na tupu i totonu o le fanauga a tagata seia oo mai i le taimi lena,", "and whatsoever things transpired among the children of men until that time,"], ["ua i ai i totonu o tagata Iutaia—", "is had among the Jews—"]]},
  {num:4,words:[["O lea ou te le tusia ai mea ia na tutupu mai aso o Atamu seia oo mai i le taimi lena;", "Therefore I do not write those things which transpired from the days of Adam until that time;"], ["ae ua i ai i latou i luga o papatusi;", "but they are had upon the plates;"], ["ma o soo se tasi na te mauaina i latou,", "and whoso findeth them,"], ["o ia lava lea o le a ia mauaina le mana e mafai ai ona ia maua o le tala atoa.", "the same will have power that he may get the full account."]]},
  {num:5,words:[["Ae faauta,", "But behold,"], ["ou te le tuuina atu le tala atoa,", "I give not the full account,"], ["ae ou te tuuina atu se vaega o le tala,", "but a part of the account I give,"], ["mai le olo i lalo seia oo ina faaumatiaina i latou.", "from the tower down until they were destroyed."]]},
  {num:6,words:[["Ma i luga o lenei mafuaaga ou te tuuina atu ai le tala: O le na tusia lenei talafaamaumau o Eteru ,", "And on this wise do I give the account. He that wrote this record was Ether,"], ["ma o ia o se e tupuga mai ia Korianetoa.", "and he was a descendant of Coriantor."]]},
  {num:7,words:[["O Korianetoa o le atalii o Morona.", "Coriantor was the son of Moron."]]},
  {num:8,words:[["Ma o Morona o le atalii o Etema.", "And Moron was the son of Ethem."]]},
  {num:9,words:[["Ma o Etema o le atalii o Asa.", "And Ethem was the son of Ahah."]]},
  {num:10,words:[["Ma o Asa o le atalii o Setu.", "And Ahah was the son of Seth."]]},
  {num:11,words:[["Ma o Setu o le atalii o Sipelona.", "And Seth was the son of Shiblon."]]},
  {num:12,words:[["Ma o Sipelona o le atalii o Komi.", "And Shiblon was the son of Com."]]},
  {num:13,words:[["Ma o Komi o le atalii o Korianetumu.", "And Com was the son of Coriantum."]]},
  {num:14,words:[["Ma o Korianetumu o le atalii o Aminikata.", "And Coriantum was the son of Amnigaddah."]]},
  {num:15,words:[["Ma o Aminikata o le atalii o Arona.", "And Amnigaddah was the son of Aaron."]]},
  {num:16,words:[["Ma o Arona o se e tupuga mai ia Hetu,", "And Aaron was a descendant of Heth,"], ["o le atalii ia o Heatoma.", "who was the son of Hearthom."]]},
  {num:17,words:[["Ma o Heatoma o le atalii o Lipi.", "And Hearthom was the son of Lib."]]},
  {num:18,words:[["Ma o Lipi o le atalii o Kiso.", "And Lib was the son of Kish."]]},
  {num:19,words:[["Ma o Kiso o le atalii o Koruma.", "And Kish was the son of Corom."]]},
  {num:20,words:[["Ma o Koruma o le atalii o Levi.", "And Corom was the son of Levi."]]},
  {num:21,words:[["Ma o Levi o le atalii o Kimo.", "And Levi was the son of Kim."]]},
  {num:22,words:[["Ma o Kimo o le atalii o Morianetona.", "And Kim was the son of Morianton."]]},
  {num:23,words:[["Ma o Morianetona o le suli o Ripelakiso.", "And Morianton was a descendant of Riplakish."]]},
  {num:24,words:[["Ma o Ripelakiso o le atalii o Sesa.", "And Riplakish was the son of Shez."]]},
  {num:25,words:[["Ma o Sesa o le atalii o Hetu.", "And Shez was the son of Heth."]]},
  {num:26,words:[["Ma o Hetu o le atalii o Komi.", "And Heth was the son of Com."]]},
  {num:27,words:[["Ma o Komi o le atalii o Korianetumu.", "And Com was the son of Coriantum."]]},
  {num:28,words:[["Ma o Korianetumu o le atalii o Emera.", "And Coriantum was the son of Emer."]]},
  {num:29,words:[["Ma o Emera o le atalii o Omera.", "And Emer was the son of Omer."]]},
  {num:30,words:[["Ma o Omera o le atalii o Sule.", "And Omer was the son of Shule."]]},
  {num:31,words:[["Ma o Sule o le atalii o Kipi.", "And Shule was the son of Kib."]]},
  {num:32,words:[["Ma o Kipi o le atalii o Oraea,", "And Kib was the son of Orihah,"], ["o le atalii o Iareto;", "who was the son of Jared;"]]},
  {num:33,words:[["O Iareto lea na o mai ma lona uso,", "Which Jared came forth with his brother and their families,"], ["ma o laua aiga, faatasi ma isi ma o latou aiga,", "with some others and their families,"], ["mai le olo tele,", "from the great tower,"], ["i le taimi na faaeseese ai e le Alii le gagana a tagata,", "at the time the Lord confounded the language of the people,"], ["ma tauto ai i lona toasa o le a faataapeapeina i latou i luga o le lalolagi atoa; ma e tusa ma le fetalaiga a le Alii,", "and swore in his wrath that they should be scattered upon all the face of the earth;"], ["sa faataapeapeina lava tagata.", "and according to the word of the Lord the people were scattered."]]},
  {num:34,words:[["Ma ona o le uso o Iareto o se tagata tino ese ma malosi,", "And the brother of Jared being a large and mighty man,"], ["ma o se tagata na faapitoa tele e le Alii,", "and a man highly favored of the Lord,"], ["sa fai atu Iareto,", "Jared,"], ["lona uso,", "his brother,"], ["ia te ia:", "said unto him:"], ["Tagi atu i le Alii,", "Cry unto the Lord,"], ["ina ia le faafenumiaiina e ia i tatou ina ia le mafai ona tatou malamalama ia tatou upu.", "that he will not confound us that we may not understand our words."]]},
  {num:35,words:[["Ma sa oo ina tagi atu le uso o Iareto i le Alii,", "And it came to pass that the brother of Jared did cry unto the Lord,"], ["ma sa agaalofa mai le Alii ia Iareto;", "and the Lord had compassion upon Jared;"], ["o lea na le faaeseeseina ai e ia le gagana a Iareto;", "therefore he did not confound the language of Jared;"], ["ma sa le faafenumiaiina Iareto ma lona uso.", "and Jared and his brother were not confounded."]]},
  {num:36,words:[["Ona fai atu ai lea o Iareto i lona uso:", "Then Jared said unto his brother:"], ["Toe tagi atu i le Alii,", "Cry again unto the Lord,"], ["ma atonu o le a ia liliu ese ai lona toasa mai ia te i latou o a tatou uo,", "and it may be that he will turn away his anger from them who are our friends,"], ["ina ia le faaeseeseina e ia la latou gagana.", "that he confound not their language."]]},
  {num:37,words:[["Ma sa oo ina tagi atu le uso o Iareto i le Alii,", "And it came to pass that the brother of Jared did cry unto the Lord,"], ["ma sa agaalofa mai le Alii ia laua uo, ma o latou aiga foi,", "and the Lord had compassion upon their friends and their families also,"], ["sa le faafenumiaiina i latou.", "that they were not confounded."]]},
  {num:38,words:[["Ma sa oo ina toe fai atu Iareto i lona uso,", "And it came to pass that Jared spake again unto his brother,"], ["ua fai atu:", "saying:"], ["Alu ma ole atu i le Alii, pe o le a ia tutuli ese i tatou i fafo o le laueleele,", "Go and inquire of the Lord whether he will drive us out of the land,"], ["ma afai o le a ia tutuli ese i tatou i fafo o le laueleele,", "and if he will drive us out of the land,"], ["tagi atu ia te ia po o fea o le a tatou o i ai.", "cry unto him whither we shall go."], ["Ma o ai na te iloa ae o le a le taitaiina atu i tatou e le Alii i se laueleele ua silisili ona lelei i luga o le lalolagi atoa? Ma afai e faapea,", "And who knoweth but the Lord will carry us forth into a land which is choice above all the earth? And if it so be,"], ["ia tatou faamaoni i le Alii,", "let us be faithful unto the Lord,"], ["ina ia tatou mauaina lena laueleele mo o tatou tofi.", "that we may receive it for our inheritance."]]},
  {num:39,words:[["Ma sa oo ina tagi atu le uso o Iareto i le Alii e tusa ma le mea na fetalaia e le fofoga o Iareto.", "And it came to pass that the brother of Jared did cry unto the Lord according to that which had been spoken by the mouth of Jared."]]},
  {num:40,words:[["Ma sa oo ina faafofoga mai le Alii i le uso o Iareto,", "And it came to pass that the Lord did hear the brother of Jared,"], ["ma agaalofa mai ia te ia,", "and had compassion upon him,"], ["ma fetalai mai ia te ia:", "and said unto him:"]]},
  {num:41,words:[["Ina alu ia ma faapotopoto faatasi au lafu manu,", "Go to and gather together thy flocks,"], ["o manu poa ma manu fafine,", "both male and female,"], ["o ituaiga eseese uma;", "of every kind;"], ["ma fatu foi o ituaiga eseese uma o le eleele;", "and also of the seed of the earth of every kind;"], ["ma ou aiga ; ma lou uso foi o Iareto,", "and thy families;"], ["ma lona aiga;", "and also Jared thy brother and his family;"], ["ma au uo foi ma o latou aiga,", "and also thy friends and their families,"], ["ma uo a Iareto ma o latou aiga.", "and the friends of Jared and their families."]]},
  {num:42,words:[["Ma a uma ona e faia lenei mea, ia e alu atu i luma o i latou i lalo i le vanu lea e i le itu i matu.", "And when thou hast done this thou shalt go at the head of them down into the valley which is northward."], ["Ma o iina o le a ou feiloai ai ma oe,", "And there will I meet thee,"], ["ma o le a ou alu atu ai i ou luma i se laueleele ua silisili ona lelei i luga o laueleele uma o le lalolagi.", "and I will go before thee into a land which is choice above all the lands of the earth."]]},
  {num:43,words:[["Ma o iina o le a ou faamanuia ai oe ma au fanau,", "And there will I bless thee and thy seed,"], ["ma faatutu mai mo au mai au fanau,", "and raise up unto me of thy seed,"], ["ma mai fanau a lou uso,", "and of the seed of thy brother,"], ["ma mai ia i latou o e o le a o atu faatasi ma oe,", "and they who shall go with thee,"], ["se atunuu tele. Ma o le a leai se atunuu e silisili atu i lo le atunuu lea o le a ou faatu mai mo au mai lau fanau,", "a great nation. And there shall be none greater than the nation which I will raise up unto me of thy seed,"], ["i luga o le lalolagi atoa. Ma o le a faapea ona ou faia ia te oe ona o lenei taimi umi ua e tagi mai ai ia te au.", "upon all the face of the earth. And thus I will do unto thee because this long time ye have cried unto me."]]},
];
renderVerseSet(et_ch_1_Verses, 'et-ch1-verses');

var et_ch_2_Verses = [
  {num:1,words:[["Ma sa oo ina o atu Iareto ma lona uso,", "And it came to pass that Jared and his brother,"], ["ma o laua aiga,", "and their families,"], ["ma uo foi a Iareto ma lona uso,", "and also the friends of Jared and his brother and their families,"], ["ma o latou aiga,", "went down into the valley which was northward,"], ["i lalo i le vanu lea sa i le itu i matu, (ma o le igoa o le vanu o Nimarota ,", "(and the name of the valley was Nimrod,"], ["ua faaigoa i le tagata tulimanu malosi) faatasi ma a latou lafu manu ia sa latou faapotopoto faatasi,", "being called after the mighty hunter) with their flocks which they had gathered together,"], ["o manu poa ma manu fafine,", "male and female,"], ["o ituaiga eseese uma.", "of every kind."]]},
  {num:2,words:[["Ma sa latou tatao foi mailei ma tapue manu felelei o le ea;", "And they did also lay snares and catch fowls of the air;"], ["ma sa latou saunia foi se faatanoa,", "and they did also prepare a vessel,"], ["na latou ave ai faatasi ma i latou ia o vai.", "in which they did carry with them the fish of the waters."]]},
  {num:3,words:[["Ma sa latou ave foi faatasi ma i latou o tesareta,", "And they did also carry with them deseret,"], ["ia a faamatalaina,", "which,"], ["o le lago meli;", "by interpretation, is a honey bee;"], ["ma sa faapea ona latou ave faatasi ma i latou faamoega o lagomeli,", "and thus they did carry with them swarms of bees,"], ["ma ituaiga o mea uma sa i ai i luga o le laueleele,", "and all manner of that which was upon the face of the land,"], ["o fatu o ituaiga taitasi uma.", "seeds of every kind."]]},
  {num:4,words:[["Ma sa oo ina ua latou o mai i lalo i le vanu o Nimarota sa afio ifo i le Alii ma fetautalatalaai ma le uso o Iareto;", "And it came to pass that when they had come down into the valley of Nimrod the Lord came down and talked with the brother of Jared;"], ["ma sa i ai o ia i totonu o se ao ,", "and he was in a cloud,"], ["ma sa le vaai atu le uso o Iareto ia te ia.", "and the brother of Jared saw him not."]]},
  {num:5,words:[["Ma sa oo ina poloaiina i latou e le Alii e tatau ona latou o atu i le vao,", "And it came to pass that the Lord commanded them that they should go forth into the wilder– ness,"], ["ioe,", "yea,"], ["i le vaega lena e leai ai lava se tagata na oo i ai. Ma sa oo ina afio atu le Alii i o latou luma,", "into that quarter where there never had man been. And it came to pass that the Lord did go before them,"], ["ma fetalai mai ia te i latou ao tu o ia i totonu o se ao ,", "and did talk with them as he stood in a cloud,"], ["ma tuu mai faatonuga i le mea e tatau ona latou malaga ai.", "and gave directions whither they should travel."]]},
  {num:6,words:[["Ma sa oo ina latou malaga i le vao,", "And it came to pass that they did travel in the wilderness,"], ["ma fauina ni vaa,", "and did build barges,"], ["ia na latou sopoia ai vai e tele,", "in which they did cross many waters,"], ["ma taitaiina pea e le aunoa e le aao o le Alii.", "being directed conti– nually by the hand of the Lord."]]},
  {num:7,words:[["Ma sa le tuuina i latou e le Alii ia latou taofi i le sami i tala atu o le vao,", "And the Lord would not suffer that they should stop beyond the sea in the wilderness,"], ["ae sa ia finagalo ia latou o mai seia oo mai lava i le laueleele o le folafolaga,", "but he would that they should come forth even unto the land of promise,"], ["lea ua silisili ona lelei i luga o isi laueleele uma,", "which was choice above all other lands,"], ["lea na faasaosaoina e le Alii le Atua mo tagata amiotonu.", "which the Lord God had preserved for a righteous people."]]},
  {num:8,words:[["Ma sa ia tauto i le uso o Iareto i lona toasa,", "And he had sworn in his wrath unto the brother of Jared,"], ["o soo se tasi na te mauaina lenei laueleele o le folafolaga,", "that whoso should possess this land of promise,"], ["mai lena taimi e oo mai i luma ma le faavavau,", "from that time henceforth and forever,"], ["e tatau ona auauna atu ia te ia,", "should serve him,"], ["le Atua moni ma toatasi nao ia,", "the true and only God,"], ["a leai o le a tafi ese i latou pe a oo mai le atoatoa o lona toasa i luga o i latou.", "or they should be swept off when the fulness of his wrath should come upon them."]]},
  {num:9,words:[["Ma o lenei,", "And now,"], ["e mafai ona tatou vaaia fetalaiga faatulafonoina a le Atua e faatatau i lenei laueleele;", "we can behold the decrees of God concerning this land,"], ["e faapea o se laueleele o le folafolaga;", "that it is a land of promise;"], ["ma o soo se atunuu latou te mauaina ia auauna atu i le Atua,", "and whatsoever nation shall possess it shall serve God,"], ["a leai o le a tafi ese i latou pe a oo mai le atoatoa o lona toasa i luga o i latou. Ma e oo mai le atoatoa o lona toasa i luga o i latou pe a matua i latou i le amioletonu.", "or they shall be swept off when the  fulness of his wrath shall come upon them. And the fulness of his wrath cometh upon them when they are ripened in iniquity."]]},
  {num:10,words:[["Aua faauta,", "For behold,"], ["o se laueleele lenei ua silisili atu ona lelei i luga o isi laueleele uma;", "this is a land which is choice above all other lands;"], ["o le mea lea o ia o le na te mauaina ia auauna atu i le Atua a leai o le a tafiesea o ia;", "wherefore he that doth possess it shall serve God or shall be swept off;"], ["ona o le fetalaiga faatulafonoina tumau-faavavau lea a le Atua.", "for it is the everlasting decree of God."], ["Ma o le a le tafiesea i latou seia oo ina oo mai le atoatoa o le amioletonu i fanau a le laueleele.", "And it is not until the fulness of iniquity among the children of the land, that they are swept off."]]},
  {num:11,words:[["Ma e oo mai ia te outou lenei talafaamaumau,", "And this cometh unto you,"], ["outou Nuuese e,", "O ye Gentiles,"], ["ina ia outou iloa fetalaiga faatulafonoina a le Atua—ina ia outou salamo,", "that ye may know the decrees of God—that ye may repent,"], ["ma aua tou te faaauau pea ia outou amioletonu seia oo ina oo mai le atoatoa,", "and not continue in your iniquities until the fulness come,"], ["ina ia outou le aumaia i lalo le atoatoa o le toasa o le Atua i o outou luga e pei ona faia e tagata mau o le laueleele e oo mai i le taimi nei.", "that ye may not bring down the fulness of the wrath of God upon you as the inhabitants of the land have hitherto done."]]},
  {num:12,words:[["Faauta,", "Behold,"], ["o se laueleele silisili ona lelei lenei,", "this is a choice land,"], ["ma o soo se atunuu e mauaina o le a saoloto mai le pologa,", "and whatsoever nation shall possess it shall be free from bon– dage,"], ["ma mai le faatagataotaua,", "and from captivity,"], ["ma mai i isi atunuu uma e i lalo ifo o le lagi,", "and from all other nations under heaven,"], ["pe afai latou te auauna i le Atua o le laueleele,", "if they will but serve the God of the land,"], ["o ia lea o Iesu Keriso,", "who is Jesus Christ,"], ["o le ua faaalia atu i mea ua matou tusia.", "who hath been manifested by the things which we have written."]]},
  {num:13,words:[["Ma o lenei o le a ou faasolo atu i lau talafaamaumau;", "And now I proceed with my record;"], ["aua faauta,", "for behold,"], ["sa oo ina aumai e le Alii Iareto ma ona uso seia oo atu lava i le sami tele lena ua vavae laueleele. Ma ina ua latou oo mai i le sami sa latou faatutu o latou faleie;", "it came to pass that the Lord did bring Jared and his brethren forth even to that great sea which divideth the lands. And as they came to the sea they pitched their tents;"], ["ma sa latou faaigoaina le igoa o le nofoaga o Morianekumeri;", "and they called the name of the place Moriancumer;"], ["ma sa latou nonofo i faleie,", "and they dwelt in tents,"], ["ma nonofo i faleie i luga o le matafaga mo le va o tausaga e fa.", "and dwelt in tents upon the seashore for the space of four years."]]},
  {num:14,words:[["Ma sa oo i le faaiuga o tausaga e fa, sa toe afio mai le Alii i le uso o Iareto,", "And it came to pass at the end of four years that the Lord came again unto the brother of Jared,"], ["ma afio i totonu o se ao ma fetalai mai ia te ia.", "and stood in a cloud and talked with him."], ["Ma sa fetalai le Alii i le uso o Iareto mo le va o le tolu itula,", "And for the space of three hours did the Lord talk with the brother of Jared,"], ["ma aoai o ia ona sa ia le manatua e valaau atu i le suafa o le Alii.", "and chastened him because he remembered not to call upon the name of the Lord."]]},
  {num:15,words:[["Ma sa salamo le uso o Iareto i lea mea leaga na ia faia,", "And the brother of Jared repented of the evil which he had done,"], ["ma ia valaau atu ai i le suafa o le Alii mo ona uso o e na faatasi ma ia. Ma sa fetalai mai le Alii ia te ia:", "and did call upon the name of the Lord for his brethren who were with him. And the Lord said unto him:"], ["O le a ou faamagaloina oe ma ou uso ia latou agasala;", "I will forgive thee and thy brethren of their sins;"], ["ae aua e te toe agasala,", "but thou shalt not sin any more,"], ["aua ia outou manatua o lou Agaga e le galue pea i le tagata;", "for ye shall remember that my Spirit will not always strive with man;"], ["o le mea lea,", "where– fore,"], ["afai tou te agasala seia oo ina outou matua atoatoa o le a vavae ese outou mai luma o le Alii. Ma o ou manatu ia e uiga i le laueleele lea o le a ou tuu atu ia te outou mo o outou tofi;", "if ye will sin until ye are fully ripe ye shall  be cut off from the presence of the Lord. And these are my thoughts upon the land which I shall give you for your inheritance;"], ["ona o se laueleele o le a silisili ona lelei i luga o isi laueleele uma.", "for it shall be a land choice above all other lands."]]},
  {num:16,words:[["Ma sa fetalai mai le Alii:", "And the Lord said:"], ["Alu e galue ma fau ni vaa,", "Go to work and build,"], ["e pei o vaa ia ua uma ona outou fausia. Ma sa oo ina alu atu le uso o Iareto e galue,", "after the manner of barges which ye have hither– to built. And it came to pass that the brother of Jared did go to work,"], ["ma ona uso foi,", "and also his brethren,"], ["ma fausia vaa e pei o vaa ia ua uma ona latou fausia,", "and built barges after the manner which they had built,"], ["e tusa ma faatonuga a le Alii. Ma sa laiti i latou,", "according to the instruct– tions of the Lord. And they were small,"], ["ma sa mama i latou i luga o le vai,", "and they were light upon the water,"], ["e pei lava o le mama o se manulele i luga o le vai.", "even like unto the lightness of a fowl upon the water."]]},
  {num:17,words:[["Ma sa fausia i latou i se ala sa matua malu tele ai i latou,", "And they were built after a manner that they were exceedingly tight,"], ["e mafai ona mau o le vai i totonu o i latou e pei lava o se ipu:", "even that they would hold water like unto a dish;"], ["ma o o latou lalo sa malu e pei o se ipu;", "and the bottom thereof was tight like unto a dish;"], ["ma o o latou itu sa malu e pei o se ipu;", "and the sides thereof were tight like unto a dish;"], ["ma o o latou taumua ma taumuli sa taufaasiusiu;", "and the ends thereof were peaked;"], ["ma o o latou fogavaa sa malu e pei o se ipu;", "and the top thereof was tight like unto a dish;"], ["ma o o latou uumi o le umi o se laau;", "and the length thereof was the length of a tree;"], ["ma o o latou faitotoa,", "and the door thereof,"], ["pe a tapunipuni,", "when it was shut,"], ["sa malu e pei o se ipu.", "was tight like unto a dish."]]},
  {num:18,words:[["Ma sa oo ina tagi atu le uso o Iareto i le Alii,", "And it came to pass that the brother of Jared cried unto the Lord,"], ["ua fai atu:", "saying:"], ["Le Alii e,", "O Lord,"], ["ua uma ona ou faia o le galuega na e poloaiina ai au,", "I have performed the work which thou hast commanded me,"], ["ma ua ou faia vaa e tusa e pei ona e faatonuina ai au.", "and I have made the barges according as thou hast directed me."]]},
  {num:19,words:[["Faauta foi,", "And behold,"], ["le Alii e,", "O Lord,"], ["ua leai se malamalama i totonu o i latou;", "in them there is no light;"], ["o fea matou te uli atu i ai? Ma o le a matou fano foi,", "whither shall we steer? And also we shall perish,"], ["ona e le mafai ona matou manava i totonu o i latou,", "for in them we cannot breathe,"], ["vagana le ea lea ua i totonu;", "save it is the air which is in them;"], ["o lea o le a matou fano ai.", "therefore we shall perish."]]},
  {num:20,words:[["Ma sa fetalai mai le Alii i le uso o Iareto:", "And the Lord said unto the brother of Jared:"], ["Faauta,", "Behold,"], ["ia e faia se pu i luga o le fogavaa,", "thou shalt make a hole in the top,"], ["ma lalo foi;", "and also in the bottom;"], ["ma a oo ina outou manaomia se ea ia outou tatala le pu ma maua ai le ea. Ma afai e faapea e sau le vai i o outou luga,", "and when thou shalt suffer for air thou shalt unstop the hole and receive air. And if it be so that the water come in upon thee,"], ["faauta,", "behold,"], ["ia outou tapuni le pu,", "ye shall stop the hole,"], ["ina ia outou le fano i le lolo.", "that ye may not perish in the flood."]]},
  {num:21,words:[["Ma sa oo ina faapea ona faia e le uso o Iareto,", "And it came to pass that the brother of Jared did so,"], ["e pei ona poloaiina ai e le Alii.", "according as the Lord had commanded."]]},
  {num:22,words:[["Ma sa toe tagi atu o ia i le Alii ua fai atu:", "And he cried again unto the Lord saying:"], ["Le Alii e,", "O Lord,"], ["faauta ua uma ona ou faia e pei ona e poloaiina ai au; ma ua ou saunia vaa mo ou tagata,", "behold I have done even as thou hast commanded me;"], ["faauta foi,", "and I have prepared the vessels for my people,"], ["ua leai se malamalama i totonu o i latou.", "and behold there is no light in them."], ["Faauta,", "Behold,"], ["le Alii e,", "O Lord,"], ["pe e te tuu ea i matou ia matou sopoia lenei vai tele i le pogisa?", "wilt thou suffer that we shall cross this great water in darkness?"]]},
  {num:23,words:[["Ma sa fetalai mai le Alii i le uso o Iareto:", "And the Lord said unto the brother of Jared:"], ["O le a se mea tou mananao ia ou faia ina ia outou maua se malamalama i totonu o o outou vaa? Aua faauta,", "What will ye that I should do that ye may have light in your vessels? For behold,"], ["e le mafai ona outou faia ni faamalama,", "ye cannot have windows,"], ["ona o le a taia nutililii;", "for they will be dashed in pieces;"], ["pe tou te ave foi afi faatasi ma outou,", "neither shall ye take fire with you,"], ["ona tou te le o i le malamalama o le afi;", "for ye shall not go by the light of fire."]]},
  {num:24,words:[["Aua faauta,", "For behold,"], ["o le a pei outou o se tafola i totonu o le sami;", "ye shall be as a whale in the midst of the sea;"], ["ona o le a fafati galu mauga i luga o outou. E ui i lea,", "for the mountain waves shall dash upon you. Nevertheless,"], ["o le a ou toe aumai outou i fafo mai le loloto o le sami;", "I will bring you up again out of the depths of the sea;"], ["ona ua o atu matagi i fafo mai lou gutu,", "for the winds have gone forth out of my mouth,"], ["ma ua ou auina atu foi uaga ma lologa.", "and also the rains and the floods have I sent forth."]]},
  {num:25,words:[["Faauta foi,", "And behold,"], ["ua ou saunia outou e faasaga i ia mea;", "I prepare you against these things;"], ["ona e le mafai ona outou sopoia lenei moana tele vagana ai ua ou saunia outou aua galu o le sami,", "for ye cannot cross this great deep save I prepare you against the waves of the sea,"], ["ma matagi ua o atu,", "and the winds which have gone forth,"], ["ma lologa o le a oo mai. O lea o le a se mea tou te mananao ia ou saunia mo outou ina ia outou maua le malamalama pe a tofatumoanaina outou i loloto o le sami?", "and the floods which shall come. Therefore what will ye that I should prepare for you that ye may have light when ye are swallowed up in the depths of the sea?"]]},
];
renderVerseSet(et_ch_2_Verses, 'et-ch2-verses');

var et_ch_3_Verses = [
  {num:1,words:[["Ma sa oo ina alu atu le uso o Iareto,", "And it came to pass that the brother of Jared,"], ["(o lenei o le aofai o vaa ia ua uma ona saunia e valu) i le mauga,", "(now the number of the vessels which had been prepared was eight) went forth unto the mount,"], ["lea sa latou taua o le mauga o Selema,", "which they called the mount Shelem,"], ["ona o lona maualuga tele,", "because of its exceeding height,"], ["ma ia gaosi mai se papa ni maa laiti e sefulu ma le ono;", "and did molten out of a  rock sixteen small stones;"], ["ma sa papae ma manino ia maa,", "and they were white and clear,"], ["e pei lava o le tioata manino;", "even as transparent glass;"], ["ma sa ia ave ia maa i ona lima i luga i le tumutumu o le mauga,", "and he did carry them in his hands upon the top of the mount,"], ["ma toe tagi atu i le Alii,", "and cried again unto the Lord,"], ["ua fai atu:", "saying:"]]},
  {num:2,words:[["Le Alii e,", "O Lord,"], ["na e fetalai mai o le a siomia i matou i lologa. O lenei faauta,", "thou hast said that we must be encompassed about by the floods. Now behold,"], ["Le Alii e,", "O Lord,"], ["ma aua e te toatamai mai i lau auauna ona o lona vaivai i ou luma;", "and do not be angry with thy servant because of his weakness before thee;"], ["aua ua matou iloa ua paia oe ma ua e afio i le lagi,", "for we know that thou art holy and dwellest in the heavens,"], ["ma ua matou le agavaa i ou luma;", "and that we are unworthy before thee;"], ["o le pau o o matou natura ua matou leaga ai pea e le aunoa;", "because of the fall our natures have become evil continually;"], ["e ui i lea,", "nevertheless,"], ["Le Alii e,", "O Lord,"], ["ua e tuu mai ia te i matou se poloaiga e ao ina matou valaau atu ia te oe,", "thou hast given us a commandment that we must call upon thee,"], ["ona o oe matou te maua mai ai e tusa ma o matou manao.", "that from thee we may receive according to our desires."]]},
  {num:3,words:[["Faauta,", "Behold,"], ["Le Alii e,", "O Lord,"], ["na e taiaina i matou ona o lo matou amioletonu,", "thou hast smitten us because of our iniquity,"], ["ma ua e tutuli ese i matou,", "and hast driven us forth,"], ["ma ua matou i ai i le vao mo nei tausaga e tele;", "and for these many years we have been in the wilder– ness;"], ["e ui i lea,", "nevertheless,"], ["ua e alofa mutimutivale mai pea ia te i matou. Le Alii e,", "thou hast been merciful unto us. O Lord,"], ["silasila mai ia ia te au i le alofa,", "look upon me in pity,"], ["ma liliu ese lou toasa mai i ou nei tagata,", "and turn away thine anger from this thy people,"], ["ma aua e te tuu i latou e sopo atu i luga o lenei moana sousou i le pogisa;", "and suffer not that they shall go forth across this raging deep in darkness;"], ["ae faauta mai i nei mea na ou gaosia mai le papa.", "but behold these things which I have molten out of the rock."]]},
  {num:4,words:[["Ma ua ou iloa,", "And I know,"], ["Le Alii e,", "O Lord,"], ["ua ia te oe le mana uma,", "that thou hast all power,"], ["ma e mafai ona e faia o soo se mea e te finagalo i ai mo le manuia o tagata;", "and can do whatsoever thou wilt for the benefit of man;"], ["o lea, pai mai i nei maa,", "therefore touch these stones,"], ["Le Alii e,", "O Lord,"], ["i lou tamatamaiaao,", "with thy finger,"], ["ma saunia i latou ina ia susulu atu i le pogisa;", "and prepare them that they may shine forth in darkness;"], ["ma o le a latou susulu mai ia te i matou i totonu o vaa ua matou saunia,", "and they shall shine forth unto us in the vessels which we have prepared,"], ["ina ia matou maua le malamalama ao matou sopo atu i le sami.", "that we may have light while we shall cross the sea."]]},
  {num:5,words:[["Faauta,", "Behold,"], ["Le Alii e,", "O Lord,"], ["e mafai ona e faia lenei mea. Ua matou iloa e mafai ona e faaali mai le mana tele,", "thou canst do this. We know that thou art able to show forth great power,"], ["lea ua foliga faatauvaa i le malamalamaaga o tagata.", "which looks small unto the understanding of men."]]},
  {num:6,words:[["Ma sa oo ina ua uma ona fai atu e le uso o Iareto o nei upu,", "And it came to pass that when the brother of Jared had said these words,"], ["faauta,", "behold,"], ["sa faaloloa mai e le Alii lona aao ma sa pai i maa taitasi i lona tamatamaiaao.", "the Lord stretched forth his hand and touched the stones one by one with his finger."], ["Ma sa aveeseina le veli mai mata o le uso o Iareto,", "And the veil was taken from off the eyes of the brother of Jared,"], ["ma sa ia vaai i le tamatamaiaao o le Alii;", "and he saw the finger of the Lord;"], ["ma sa pei o le tamatamailima o se tagata, e pei o le o,", "and it was as the finger of a man,"], ["aano ma le toto;", "like unto flesh and blood;"], ["ma sa pau i lalo le uso o Iareto i luma o le Alii,", "and the brother of Jared fell down before the Lord,"], ["ona sa taia o ia i le matau.", "for he was struck with fear."]]},
  {num:7,words:[["Ma sa silasila mai le Alii ua pau i le eleele le uso o Iareto;", "And the Lord saw that the brother of Jared had fallen to the earth;"], ["ma sa fetalai mai le Alii ia te ia:", "and the Lord said unto him:"], ["Tulai ia,", "Arise,"], ["aisea ua e pau ai?", "why hast thou fallen?"]]},
  {num:8,words:[["Ma sa ia fai atu i le Alii:", "And he saith unto the Lord:"], ["Sa ou vaai i le tamatamaiaao o le Alii,", "I saw the finger of the Lord,"], ["ma sa ou fefe nei taia au e ia;", "and I feared lest he should smite me;"], ["ona sa ou le iloa ua i ai i le Alii le aano ma le toto.", "for I knew not that the Lord had flesh and blood."]]},
  {num:9,words:[["Ma sa fetalai mai le Alii ia te ia:", "And the Lord said unto him:"], ["Ona o lou faatuatua ua e vaai ai o le a ou ave i luga ia te a'u se tino aano ma le toto;", "Because of thy faith thou hast seen that I shall take upon me flesh and blood;"], ["ma e lei sau lava i ou luma se tagata ma se faatuatua tele faapea e pei ona e sau;", "and never has man come before me with such exceeding faith as thou hast;"], ["aua a na le faapea po ua le mafai ona e vaai i lou tamatamailima. Pe na e vaai ea i se mea e sili atu nai lo lenei?", "for were it not so ye could not have seen my finger. Sawest thou more than this?"]]},
  {num:10,words:[["Ma sa tali atu o ia:", "And he answered:"], ["E leai;", "Nay;"], ["le Alii e,", "Lord,"], ["faaali mai ia oe lava ia te au.", "show thyself unto me."]]},
  {num:11,words:[["Ma sa fetalai mai le Alii ia te ia:", "And the Lord said unto him:"], ["E te talitonu ea i upu o le a ou tautala atu ai?", "Believest thou the words which I shall speak?"]]},
  {num:12,words:[["Ma sa tali atu o ia:", "And he answered:"], ["Ioe,", "Yea,"], ["le Alii e,", "Lord,"], ["ua ou iloa e te fetalai i le upumoni,", "I know that thou speakest the truth,"], ["ona o oe o se Atua o le upumoni,", "for thou art a God of truth,"], ["ma e le mafai ona pepelo.", "and canst not lie."]]},
  {num:13,words:[["Ma ina ua uma ona fai atu e ia o ia upu,", "And when he had said these words,"], ["faauta,", "behold,"], ["sa faaali mai e le Alii o ia lava ia te ia,", "the Lord showed himself unto him,"], ["ma fetalai mai: Ona ua e iloa nei mea,", "and said:"], ["ua togiolaina oe mai le pau;", "Because thou knowest these things ye are redeemed from the fall;"], ["o lea ua toe aumai ai oe i ou luma;", "therefore ye are brought back into my presence;"], ["o lea ou te faaali atu ai au lava ia te oe.", "therefore I show myself unto you."]]},
  {num:14,words:[["Faauta,", "Behold,"], ["o au o le na saunia mai le faavaega o le lalolagi e togiola lou nuu. Faauta,", "I am he who was prepared from the foundation of the world to redeem my people. Behold,"], ["o au o Iesu Keriso. O au o le Tamā ma le Atalii. O au e maua ai e tagata uma le ola ,", "I am Jesus Christ. I am the Father and the Son. In me shall all mankind have life,"], ["ma e faavavau,", "and that eternally,"], ["ia i latou lava o e e talitonu i lou igoa;", "even they who shall believe on my name;"], ["ma o le a avea i latou ma ou atalii ma ou afafine.", "and they shall become my sons and my daughters."]]},
  {num:15,words:[["Ma ou te lei faaalia au lava i se tagata o se na ou foafoaina,", "And never have I showed myself unto man whom I have created,"], ["ona e leai se tagata sa talitonu mai ia te au e pei ona e talitonu mai. Pe ua e vaai ea ua foafoaina oe i lou lava faatusa ? Ioe,", "for never has man believed in me as thou hast. Seest thou that ye are created after mine own image? Yea,"], ["e oo i tagata uma sa foafoaina i le amataga i lou lava faatusa.", "even all men were created in the beginning after mine own image."]]},
  {num:16,words:[["Faauta,", "Behold,"], ["o lenei tino,", "this body,"], ["lea ua e vaai mai nei i ai,", "which ye now behold,"], ["o le tino lea o lou agaga ;", "is the body of my spirit;"], ["ma ua ou foafoaina le tagata e tusa ma le tino o lou agaga;", "and man have I created after the body of my spirit;"], ["ma e pei ona ou foliga atu ia te oe i la le agaga o le a faapea lava ona ou foliga atu i lou nuu i la le tino.", "and even as I appear unto thee to be in the spirit will I appear unto my people in the flesh."]]},
  {num:17,words:[["Ma o lenei,", "And now,"], ["o au, o Moronae,", "as I,"], ["e pei ona ou fai atu,", "Moroni,"], ["ua le mafai ona ou faia se tala atoa o nei mea ua tusia, o lea ua lava ai ia te au ona ou fai atu sa faaali mai e Iesu o ia lava i lenei tagata i la le agaga,", "said I could not make a full account of these things which are written therefore it sufficeth me to say that Jesus showed himself unto this man in the spirit,"], ["e tusa lava ma le faatusa ma foliga o le tino lava lea e tasi na ia faaali mai ai o ia lava i tagata sa Nifaē.", "even after the manner and in the likeness of the same body even as he showed himself unto the Nephites."]]},
  {num:18,words:[["Ma sa ia auauna mai ia te ia e pei lava ona ia auauna mai i tagata sa Nifaē;", "And he ministered unto him even as he ministered unto the Nephites;"], ["na faia nei mea uma,", "and all this,"], ["ina ia iloa e lenei tagata o ia o le Atua,", "that this man might know that he was God,"], ["ona o le tele o galuega tetele na faaalia e le Alii ia te ia.", "because of the many great works which the Lord had showed unto him."]]},
  {num:19,words:[["Ma ona o le malamalama o lenei tagata sa le mafai ai ona taofi o ia mai le vaai atu i totonu o le veli ;", "And because of the knowledge of this man he could not be kept from beholding within the veil;"], ["ma sa vaai o ia i le tamatamaiaao o Iesu,", "and he saw the finger of Jesus,"], ["lea,", "which,"], ["ina ua ia vaai i ai,", "when he saw,"], ["na pau ai o ia i lalo i le matau;", "he fell with fear;"], ["aua sa ia iloa o le tamatamaiaao lea o le Alii;", "for he knew that it was the finger of the Lord;"], ["ma sa le toe ia te ia le faatuatua,", "and he had faith no longer,"], ["ona ua ia mautinoa,", "for he knew,"], ["ua le masalosalo i se mea.", "nothing doubting."]]},
  {num:20,words:[["O le mea lea,", "Wherefore,"], ["ona ua maua e ia lenei malamalama atoatoa o le Atua,", "having this perfect knowledge of God,"], ["sa le mafai ona taofia o ia mai totonu o le veli;", "he could not be kept from within the veil;"], ["o lea na ia vaai ai ia Iesu,", "therefore he saw Jesus;"], ["ma sa auauna mai o ia ia te ia.", "and he did minister unto him."]]},
  {num:21,words:[["Ma sa oo ina fetalai mai le Alii i le uso o Iareto:", "And it came to pass that the Lord said unto the brother of Jared:"], ["Faauta,", "Behold,"], ["aua e te tuu nei mea na e vaaia ma faalogoina ia o atu i le lalolagi,", "thou shalt not suffer these things which ye have seen and heard to go forth unto the world,"], ["seia oo i le taimi o le a ou faamamaluina ai lou igoa i la le tino;", "until the time cometh that I shall glorify my name in the flesh;"], ["o le mea lea,", "wherefore,"], ["ia e teu ai ia mea na e vaaia ma faalogoina,", "ye shall treasure up the things which ye have seen and heard,"], ["ma ia le faaalia atu i se tagata.", "and show it to no man."]]},
  {num:22,words:[["Faauta foi,", "And behold,"], ["a oo ina e sau ia te au,", "when ye shall come unto me,"], ["ia e tusia i latou ma faamaufaailogaina,", "ye shall write them and shall seal them up,"], ["ina ia leai se tasi e mafai ona faaliliuina i latou;", "that no one can interpret them;"], ["ona o le a e tusia i latou i se gagana e le mafai ona faitauina ai i latou.", "for ye shall write them in a language that they cannot be read."]]},
  {num:23,words:[["Faauta foi,", "And behold,"], ["ou te tuu atu ia te oe maa nei e lua,", "these two stones will I give unto thee,"], ["ma ia e faamaufaailogaina foi i laua faatasi ma mea o le a e tusia.", "and ye shall seal them up also with the things which ye shall write."]]},
  {num:24,words:[["Aua faauta,", "For behold,"], ["ua ou faaeseina le gagana o le a e tusi ai; o le mea lea o le a ou faia ai i lau lava taimi e tatau ai,", "the language which ye shall write I have confounded;"], ["ia faamalamalama atu e nei maa o i mata o tagata mea o le a e tusia.", "wherefore I will cause in my own due time that these stones shall magnify to the eyes of men these things which ye shall write."]]},
  {num:25,words:[["Ma ina ua uma ona fetalai mai e le Alii o nei upu,", "And when the Lord had said these words,"], ["sa ia faaali mai i le uso o Iareto tagata uma o le lalolagi o e na i ai,", "he showed unto the brother of Jared all the inhabitants of the earth which had been,"], ["ma i latou uma foi o le a i ai;", "and also all that would be;"], ["ma sa ia le taofia i latou mai lana vaai,", "and he withheld them not from his sight,"], ["e oo lava i tuluiga o le lalolagi.", "even unto the ends of the earth."]]},
  {num:26,words:[["Ona sa ia fetalai mai ia te ia i taimi muamua,", "For he had said unto him in times before,"], ["afai e talitonu o ia ia te ia e mafai e ia ona faaali mai ia te ia mea uma —o le a faaali mai ia te ia;", "that if he would believe in him that he could show unto him all things—it should be shown unto him;"], ["ona le mafai ai e le Alii ona taofi o se mea mai ia te ia,", "therefore the Lord could not withhold anything from him,"], ["aua sa ia iloa e mafai e le Alii ona faaali mai o mea uma ia te ia.", "for he knew that the Lord could show him all things."]]},
  {num:27,words:[["Ma sa fetalai mai le Alii ia te ia:", "And the Lord said unto him:"], ["Ia tusi nei mea ma faamaufaailogaina ; ma o le a ou faaali atu i latou i lau lava taimi e tatau ai,", "Write these things and seal them up;"], ["i le fanauga a tagata.", "and I will show them in mine own due time unto the children of men."]]},
  {num:28,words:[["Ma sa oo ina poloaiina o ia e le Alii ia faamaufaailogaina e ia maa e lua ia na ia maua mai,", "And it came to pass that the Lord commanded him that he should seal up the two stones which he had received,"], ["ma ia le faaalia atu i laua,", "and show them not,"], ["seia oo ina faaali atu i latou e le Alii i le fanauga a tagata.", "until the Lord should show them unto the children of men."]]},
];
renderVerseSet(et_ch_3_Verses, 'et-ch3-verses');

var et_ch_4_Verses = [
  {num:1,words:[["Ma sa poloaiina e le Alii le uso o Iareto ia alu ifo i lalo i fafo mai le mauga mai luma o le Alii,", "And the Lord commanded the brother of Jared to go down out of the mount from the presence of the Lord,"], ["ma tusi mea na ia vaaia;", "and write the things which he had seen;"], ["ma sa faasa ona oo mai i latou i le fanauga a tagata seia mavae ona sii ae o ia i luga o le satauro;", "and they were forbidden to come unto the children of men until after that he should be lifted up upon the cross;"], ["ma o le pogai lea na tausia ai i latou e le tupu o Mosaea,", "and for this cause did king Mosiah keep them,"], ["ina ia latou le oo mai i le lalolagi seia mavae ona faaali mai e Keriso o ia lava i ona tagata.", "that they should not come unto the world until after Christ should show himself unto his people."]]},
  {num:2,words:[["Ma ina ua mavae ona faaali moni mai e Keriso o ia lava i ona tagata sa ia poloaiina ia faaalia i latou.", "And after Christ truly had showed himself unto his people he commanded that they should be made manifest."]]},
  {num:3,words:[["Ma o lenei,", "And now,"], ["ina ua mavae lena,", "after that,"], ["ua faaitiitia i latou uma i le le talitonu;", "they have all dwindled in unbelief;"], ["ma ua leai se tasi vagana ai sa Lamanā,", "and there is none save it be the Lamanites,"], ["ma ua latou teena le talalelei a Keriso;", "and they have rejected the gospel of Christ;"], ["o lea ua poloaiina ai au ia ou toe natiaina i latou i le eleele.", "therefore I am commanded that I should hide them up again in the earth."]]},
  {num:4,words:[["Faauta,", "Behold,"], ["ua ou tusia i nei papatusi mea moni lava ia na vaai i ai le uso o Iareto;", "I have written upon these plates the very things which the brother of Jared saw;"], ["ma e lei i ai lava ni mea tetele silisili atu ua faaali mai nai lo mea na faaalia i le uso o Iareto.", "and there never were greater things made manifest than those which were made manifest unto the brother of Jared."]]},
  {num:5,words:[["O le mea lea na poloaiina ai au e le Alii e tusia i latou;", "Wherefore the Lord hath commanded me to write them;"], ["ma ua ou tusiaina i latou. Ma ua ia poloaiina au ia ou faamaufaailogaina i latou;", "and I have written them. And he commanded me that I should seal them up;"], ["ma ua ia poloaiina foi au ia ou faamaufaailogaina lo latou faaliliuga;", "and he also hath commanded that I should seal up the  interpretation thereof;"], ["o le mea lea ua ou faamaufaailogaina ai faaliliu gagana,", "wherefore I have sealed up the interpreters,"], ["e tusa ma le poloaiga a le Alii.", "according to the commandment of the Lord."]]},
  {num:6,words:[["Ona sa fetalai mai le Alii ia te au:", "For the Lord said unto me:"], ["O le a le oo atu i latou i Nuuese seia oo i le aso latou te salamo ai i lo latou amioletonu,", "They shall not go forth unto the Gentiles until the day that they shall repent of their iniquity,"], ["ma faamama i luma o le Alii.", "and become clean before the Lord."]]},
  {num:7,words:[["Ma i lena aso o le a latou faaaoga ai le faatuatua ia te au,", "And in that day that they shall exercise faith in me,"], ["ua fetalai mai ai le Alii,", "saith the Lord,"], ["e pei ona faia e le uso o Iareto,", "even as the brother of Jared did,"], ["ina ia mafai ona faapaiaina i latou ia te au,", "that they may become sanctified in me,"], ["o le ou faaali atu ai ia te i latou mea na vaai i ai le uso o Iareto,", "then will I manifest unto them the things which the brother of Jared saw,"], ["e oo lava i le fofola atu o au faaaliga uma ia te i latou,", "even to the unfolding unto them all my revelations,"], ["ua fetalai mai ai Iesu Keriso,", "saith Jesus Christ,"], ["le Alo o le Atua,", "the Son of God,"], ["o le Tamā o le lagi ma le lalolagi,", "the Father of the heavens and of the earth,"], ["ma mea uma o i ai.", "and all things that in them are."]]},
  {num:8,words:[["Ma o ia o le e finau tetee i le afioga a le Alii,", "And he that will contend against the word of the Lord,"], ["ia anatema o ia;", "let him be accursed;"], ["ma ia o le e faafitia nei mea,", "and he that shall deny these things,"], ["ia anatema o ia;", "let him be accursed;"], ["ona o le a ou le faaalia ia te i latou ni mea silisili atu,", "for unto them will I show no greater things,"], ["ua fetalai mai ai Iesu Keriso;", "saith Jesus Christ;"], ["ona o au o le ua tautala atu.", "for I am he who speaketh."]]},
  {num:9,words:[["Ma o lau poloaiga e tatala ma tapunia ai le lagi;", "And at my command the heavens are opened and are shut;"], ["ma o lau upu e lulu ai le lalolagi ;", "and at my word the earth shall shake;"], ["ma o lau poloaiga e mavae atu ai tagata o i ai,", "and at my command the inhabitants thereof shall pass away,"], ["e pei lava e mavae atu i se afi.", "even so as by fire."]]},
  {num:10,words:[["Ma o ia o le e le talitonu i au upu,", "And he that believeth not my words believeth not my disciples;"], ["e le talitonu i ou soo;", "and if it so be that I do not speak,"], ["ma afai e faapea ou te le o tautala atu, faamasino outou;", "judge ye;"], ["aua o le a outou iloa i le aso gataaga,", "for ye shall know that it is I that speaketh,"], ["o au lava lea o ia o loo tautala atu.", "at the last day."]]},
  {num:11,words:[["Ae o ia o le e talitonu i nei mea ua ou tautala atu ai,", "But he that believeth these things which I have spoken,"], ["o ia o le a ou asiasi atu i ai i faaaliga mai lou Agaga,", "him will I visit with the manifes– tations of my Spirit,"], ["ma o le a ia iloa ma molimauina.", "and he shall know and bear record."], ["Ma o le a iloa e ia ua moni nei mea, ona o lou Agaga;", "For because of my Spirit he shall know that these things are true;"], ["ona e tauanauina e ia tagata ia latou faia le lelei.", "for it persuadeth men to do good."]]},
  {num:12,words:[["Ma soo se mea e tauanauina tagata e fai le lelei, e mai ia te au lea;", "And whatsoever thing persuadeth men to do good is of me;"], ["ona ua leai se tasi e sau ai le lelei vagana ai ua mai ia te au.", "for good cometh of none save it be of me."], ["O au lava lea o le e taitaia tagata i mea lelei uma;", "I am the same that leadeth men to all good;"], ["o ia o le e le talitonu i au upu o le a le talitonu mai ia ia te au—ua Ou i ai;", "he that will not believe my words will not believe me—that I am;"], ["ma o ia e le talitonu mai ia te au o le a le talitonu i le Tamā o le na auina mai au.", "and he that will not believe me will not believe the Father who sent me."], ["Aua faauta,", "For behold,"], ["o au o le Tamā,", "I am the Father,"], ["o au o le malamalama ,", "I am the light,"], ["ma le ola ,", "and the life,"], ["ma le upumoni o le lalolagi.", "and the truth of the world."]]},
  {num:13,words:[["O mai ia ia te au,", "Come unto me,"], ["outou e o Nuuese,", "O ye Gentiles,"], ["ma o le a ou faailoa atu ia te outou mea tetele silisili atu,", "and I will show unto you the greater things,"], ["le malamalama lea ua natia ona o le le talitonu.", "the know– ledge which is hid up because of unbelief."]]},
  {num:14,words:[["O mai ia ia te au,", "Come unto me,"], ["outou le aiga e o Isaraelu,", "O ye house of Israel,"], ["ma o le a faaali atu ia te outou le tetele naua o mea ua teuina e le Tamā mo outou,", "and it shall be made manifest unto you how great things the Father hath laid up for you,"], ["mai le faavaega o le lalolagi;", "from the foundation of the world;"], ["ma sa lei oo mai ia te outou,", "and it hath not come unto you,"], ["ona o le le talitonu.", "because of unbelief."]]},
  {num:15,words:[["Faauta,", "Behold,"], ["pe a outou saeia lena veli o le le talitonu lea ua pogai ai ona tumau pea i lo outou tulaga leaga o le amioleaga,", "when ye shall rend that veil of unbelief which doth cause you to remain in your awful state of wickedness,"], ["ma le maaa o le loto,", "and hardness of heart,"], ["ma le tauaso o le mafaufau,", "and blindness of mind,"], ["ona faaali mai ai lea ia te outou o mea tetele ma ofoofogia ia sa natia mau mai le faavaega o le lalolagi mai ia te outou—ioe,", "then shall the great and marvelous things which have been hid up from the foundation of the world from you—yea,"], ["pe a outou valaau atu i le Tama i lou igoa,", "when ye shall call upon the Father in my name,"], ["ma le loto momomo ma le agaga salamo,", "with a broken heart and a contrite spirit,"], ["ona outou iloa ai lea ua manatua e le Tama le feagaiga lea na ia faia i o outou tamā,", "then shall ye know that the Father hath remem–  bered the covenant which he made unto your fathers,"], ["le aiga e o Isaraelu.", "O house of Israel."]]},
  {num:16,words:[["Ma ona fofola atu ai lea i mata o tagata uma au faaaliga, faaaliga ia na ou poloaiina ia tusia e lau auauna o Ioane.", "And then shall my revelations which I have caused to be written by my servant John be unfolded in the eyes of all the people."], ["Ia manatua,", "Remember,"], ["pe a outou vaai i nei mea,", "when ye see these things,"], ["o le a outou iloa ua oo mai lava le taimi o le a faaali tino moni mai ai i latou.", "ye shall know that the time is at hand that they shall be made manifest in very deed."]]},
  {num:17,words:[["O lea,", "Therefore,"], ["pe a outou maua lenei talafaamaumau o le a mafai ona outou iloa ua amataina le galuega a le Tamā i luga o le laueleele atoa.", "when ye shall receive this record ye may know that the work of the Father has commenced upon all the face of the land."]]},
  {num:18,words:[["O lea,", "Therefore,"], ["ia outou salamo ai outou tuluiga uma o le lalolagi,", "repent all ye ends of the earth,"], ["ma o mai ia te au,", "and come unto me,"], ["ma talitonu i lau talalelei,", "and believe in my gospel,"], ["ma papatiso i lou igoa;", "and be baptized in my name;"], ["aua o ia o le e talitonu ma papatiso o le a faaolaina;", "for he that believeth and is baptized shall be saved;"], ["ae o ia o le e le talitonu o le a faasalaina;", "but he that believeth not shall be damned;"], ["ma o le a mulimuli atu faailoga ia te i latou o e e talitonu i lou igoa.", "and signs shall follow them that believe in my name."]]},
  {num:19,words:[["Ma amuia lava o ia o le e maua o faamaoni i lou igoa i le aso gataaga,", "And blessed is he that is found faithful unto my name at the last day,"], ["ona o le a sii ae o ia i luga e mau i le malo ua saunia mo ia mai le faavaega o le lalolagi.", "for he shall be lifted up to dwell in the kingdom prepared for him from the foundation of the world."], ["Faauta foi, o au lava o le ua tautala atu.", "And behold it is I that hath spoken it."], ["Amene.", "Amen."]]},
];
renderVerseSet(et_ch_4_Verses, 'et-ch4-verses');

var et_ch_5_Verses = [
  {num:1,words:[["Ma o lenei,", "And now I,"], ["o au,", "Moroni,"], ["o Moronae,", "have written the words which were commanded me,"], ["ua ou tusia upu ia na poloaiina ai au,", "according to my memory;"], ["e tusa ma lou manatua; ma ua uma ona ou tau atu ia te oe mea ia ua ou faamaufaailogaina ;", "and I have told you the things which I have sealed up;"], ["o lea aua e te tago i ai ina ia e faaliliuina;", "therefore touch them not in order that ye may translate;"], ["ona ua faasaina lena mea ia te oe,", "for that thing is forbidden you,"], ["vagana ua oo mai le taimi e tatau ai i le poto o le Atua.", "except by and by it shall be wisdom in God."]]},
  {num:2,words:[["Faauta foi,", "And behold,"], ["atonu o le a mafai ona e maua o le avanoa e faaali atu ai papatusi ia te i latou o e o le a fesoasoani e aumai lenei galuega;", "ye may be privileged that ye may show the plates unto those who shall assist to bring forth this work;"]]},
  {num:3,words:[["Ma o le a faaali atu i latou i se toatolu e le mana o le Atua;", "And unto three shall they be shown by the power of God;"], ["o lea o le a latou iloa ai ma le mautinoa ua moni nei mea.", "wherefore they shall know of a surety that these things are true."]]},
  {num:4,words:[["Ma o fofoga o molimau e toatolu o le a faamaumaututu ai nei mea;", "And in the mouth of three witnesses shall these things be established;"], ["ma o le molimau a le toatolu,", "and the testimony of three,"], ["ma lenei galuega,", "and this work,"], ["lea o le a faaali atu ai le mana o le Atua ma lana afioga foi,", "in the which shall be shown forth the power of God and also his word,"], ["lea ua molimau i ai le Tamā,", "of which the Father,"], ["ma le Alo,", "and the Son,"], ["ma le Agaga Paia—ma o nei mea uma o le a tutu o se molimau e faasaga i le lalolagi i le aso gataaga.", "and the Holy Ghost bear record—and all this shall stand as a testimony against the world at the last day."]]},
  {num:5,words:[["Ma afai e faapea o le a latou salamo ma o mai i le Tamā i le suafa o Iesu,", "And if it so be that they repent and come unto the Father in the name of Jesus,"], ["o le a taliaina i latou i le malo o le Atua.", "they shall be received into the kingdom of God."]]},
  {num:6,words:[["Ma o lenei,", "And now,"], ["afai ua leai se pule o ia te au mo nei mea,", "if I have no authority for these things,"], ["faamasino outou;", "judge ye;"], ["aua o le a outou iloa ua ia te au le pule pe a outou vaai mai ia te au,", "for ye shall know that I have authority when ye shall see me,"], ["ma o le a tatou tutu i luma o le Atua i le aso gataaga. Amene.", "and we shall stand before God at the last day. Amen."]]},
];
renderVerseSet(et_ch_5_Verses, 'et-ch5-verses');

var et_ch_6_Verses = [
  {num:1,words:[["Ma o lenei,", "And now I,"], ["o au, o Moronae,", "Moroni,"], ["ou te faasolo pea e tuu atu le talafaamaumau o Iareto ma lona uso.", "proceed to give the record of Jared and his brother."]]},
  {num:2,words:[["Aua sa oo ina ua uma ona saunia e le Alii maa ia na ave e le uso o Iareto i le mauga,", "For it came to pass after the Lord had prepared the stones which the brother of Jared had carried up into the mount,"], ["sa sau i lalo le uso o Iareto i fafo mai le mauga,", "the brother of Jared came  down out of the mount,"], ["ma sa ia tuu i totonu o vaa maa ia na saunia,", "and he did put forth the stones into the vessels which were prepared,"], ["e tasi i o latou pito taitasi;", "one in each end thereof;"], ["faauta foi,", "and behold,"], ["sa latou tuuina atu le malamalama i vaa.", "they did give light unto the vessels."]]},
  {num:3,words:[["Ma sa faapea ona faia e le Alii maa ia susulu atu i le pouliuli,", "And thus the Lord caused stones to shine in darkness,"], ["e tuu atu ai le malamalama i tane,", "to give light unto men,"], ["fafine,", "women,"], ["ma tamaiti,", "and children,"], ["ina ia latou le sopoina le moana tele i le pogisa.", "that they might not cross the great waters in darkness."]]},
  {num:4,words:[["Ma sa oo ina ua uma ona latou saunia o ituaiga o meaai uma eseese,", "And it came to pass that when they had prepared all manner of food,"], ["ina ia mafai ona latou ola ai i luga o le vai,", "that thereby they might subsist upon the water,"], ["ma meaai foi mo a latou lafu ma fagaga,", "and also food for their flocks and herds,"], ["ma soo se meaola po o se manu po o se manu lele sa tatau ona latou ave faatasi ma i latou—ma sa oo ina ua uma ona latou faia o nei mea uma sa latou o atu i o latou auala po o vaa,", "and whatsoever beast or animal or fowl that they should carry with them—and it came to pass that when they had done all these things they got aboard of their vessels or barges,"], ["ma tuuvaa atu i le sami,", "and set forth into the sea,"], ["ma tuu atu i latou lava i le Alii lo latou Atua.", "commending themselves unto the Lord their God."]]},
  {num:5,words:[["Ma sa oo ina faia e le Alii le Atua ia i ai se matagi malosi e agi mai i luga o vai,", "And it came to pass that the Lord God caused that there should be a furious wind blow upon the face of the waters,"], ["agai i le laueleele na folafolaina;", "towards the promised land;"], ["ma sa faapea ona felafoaiina ai i latou i luga o galu o le sami i luma o le matagi.", "and thus they were tossed upon the waves of the sea before the wind."]]},
  {num:6,words:[["Ma sa oo ina tele taimi sa tanumia ai i latou i le loloto o le sami,", "And it came to pass that they were many times buried in the depths of the sea,"], ["ona o galu mauga sa fati i o latou luga,", "because of the mountain waves which broke upon them,"], ["ma afa tetele foi ma matautia na pogai mai i le malosi tele o le matagi.", "and also the great and terrible tempests which were caused by the fierceness of the wind."]]},
  {num:7,words:[["Ma sa oo ina ua tanumia i latou i le moana sa leai se vai sa afaina ai latou,", "And it came to pass that when they were buried in the deep there was no water that could hurt them,"], ["ona sa malu lelei o latou vaa e pei o se ipu,", "their vessels being tight like unto a dish,"], ["ma sa malu lelei foi i latou e pei o le vaa o Noa;", "and also they were tight like unto the ark of Noah;"], ["o lea a siomiaina faataamilo i latou i vai e tele sa latou tagi atu i le Alii,", "therefore when they were encom– passed about by many waters they did cry unto the Lord,"], ["ma sa ia toe aumaia i latou i luga o vai.", "and he did bring them forth again upon the top of the waters."]]},
  {num:8,words:[["Ma sa oo ina lei pe lava le agi mai o le matagi agai i le laueleele na folafolaina ao latou i ai i luga o vai;", "And it came to pass that the wind did never cease to blow towards the promised land while they were upon the waters;"], ["ma sa faapea ona latou lelea atu i luma o le matagi.", "and thus they were driven forth before the wind."]]},
  {num:9,words:[["Ma sa latou pepese atu viiga i le Alii;", "And they did sing praises unto the Lord;"], ["ioe,", "yea,"], ["sa pese atu le uso o Iareto viiga i le Alii,", "the brother of Jared did sing praises unto the Lord,"], ["ma sa ia faafetai ma vivii atu i le Alii i le aso atoa;", "and he did thank and praise the Lord all the day long;"], ["ma ina ua oo mai le po,", "and when the night came,"], ["sa latou le taofia le vivii atu i le Alii.", "they did not cease to praise the Lord."]]},
  {num:10,words:[["Ma sa faapea ona latou lelea atu i luma;", "And thus they were driven forth;"], ["ma sa leai se sauai o le sami sa mafai ona faamalepeina vaa,", "and no monster of the sea could break them,"], ["pe o se tafola e mafai ona faaleagaina i latou;", "neither whale that could mar them;"], ["ma sa latou maua pea le malamalama e le aunoa,", "and they did have light continually,"], ["pe o luga o le vai po o lalo o le vai.", "whether it was above the water or under the water."]]},
  {num:11,words:[["Ma sa faapea ona latou lelea atu i luma,", "And thus they were driven forth,"], ["i le tolu selau fasefulu ma le fa aso i luga o le vai.", "three hundred and forty and four days upon the water."]]},
  {num:12,words:[["Ma sa latou taunuu i luga o le matafaga o le laueleele na folafolaina. Ma ina ua latou tuvae i luga o le matafaga o le laueleele na folafolaina sa latou punonou i lalo i luga o le laueleele,", "And they did land upon the shore of the promised land. And when they had set their feet upon the shores of the promised land they bowed themselves down upon the face of the land,"], ["ma faamaualalalo i latou lava i luma o le Alii,", "and did humble themselves before the Lord,"], ["ma tutulu i loimata o le olioli i luma o le Alii,", "and did shed tears of joy before the Lord,"], ["ona o le tele o lona alofa mutimutivale agamalu ia te i latou.", "because of the multitude of his tender mercies over them."]]},
  {num:13,words:[["Ma sa oo ina latou o atu i luga o le laueleele,", "And it came to pass that they went forth upon the face of the land,"], ["ma amata ona galueaiina le eleele.", "and began to till the earth."]]},
  {num:14,words:[["Ma sa i ai ia Iareto ni atalii e toafa;", "And Jared had four sons;"], ["ma sa faaigoa i latou ia Iakoma,", "and they were called Jacom,"], ["ma Kilikā,", "and Gilgah,"], ["ma Mi'a,", "and Mahah,"], ["ma Oraea.", "and Orihah."]]},
  {num:15,words:[["Ma sa fanaua foi e le uso o Iareto ni atalii ma afafine.", "And the brother of Jared also begat sons and daughters."]]},
  {num:16,words:[["Ma o le aofai o uo a Iareto ma lona uso pe tusa ma le luasefulu ma le lua tagata;", "And the friends of Jared and his brother were in number about twenty and two souls;"], ["ma sa latou fanauina foi atalii ma afafine ae latou te lei o mai i le laueleele na folafolaina;", "and they also begat sons and daughters before they came to the promised land;"], ["o lea sa amata ona toatele i latou.", "and therefore they began to be many."]]},
  {num:17,words:[["Ma sa aoaoina i latou ia savavali faamaualalalo i luma o le Alii;", "And they were taught to walk humbly before the Lord;"], ["ma sa aoaoina foi i latou mai luga.", "and they were also taught from on high."]]},
  {num:18,words:[["Ma sa oo ina amata ona latou salalau atu i luga o le laueleele,", "And it came to pass that they began to spread upon the face of the land,"], ["ma uluola ma galueaiina le eleele;", "and to multiply and to till the earth;"], ["ma sa latou faasolo malolosi i le laueleele.", "and they did wax strong in the land."]]},
  {num:19,words:[["Ma sa amata ona toeaina o le uso o Iareto,", "And the brother of Jared began to be old,"], ["ma vaai ua lata ona alu ifo o ia i lalo i le tuugamau;", "and saw that he must soon go down to the grave;"], ["o le mea lea na ia fai atu ai ia Iareto:", "wherefore he said unto Jared:"], ["Ta faapotopoto faatasi lo ta nuu ina ia ta faitauina i latou,", "Let us gather together our people that we may number them,"], ["ina ia ta iloa mai ia te i latou le mea latou te mananao i ai mai ia i taua ae ta te lei o ifo i lalo i o taua tuugamau.", "that we may know of them what they will desire of us before we go down to our graves."]]},
  {num:20,words:[["Ma sa faapea lava ona faapotopoto faatasi o le nuu. O lenei o le aofai o atalii ma afafine o le uso o Iareto e toaluasefulu ma le lua tagata;", "And accordingly the people were gathered together. Now the number of the sons and the daughters of the brother of Jared were twenty and two souls;"], ["ma o le aofai o atalii ma afafine o Iareto e toasefulu ma le lua,", "and the number of sons and daughters of Jared were twelve,"], ["e toafa ona atalii.", "he having four sons."]]},
  {num:21,words:[["Ma sa oo ina la faitauina o laua tagata;", "And it came to pass that they did number their people;"], ["ma ina ua uma ona la faitauina i latou,", "and after that they had numbered them,"], ["sa laua mananaomia mai ia te i latou mea latou te mananao ia la faia ae la te lei o ifo i lalo i o laua tuugamau.", "they did desire of them the things which they would that they should do before they went down to their graves."]]},
  {num:22,words:[["Ma sa oo ina mananao mai le nuu ia te i laua ia laua faauuina se tasi o o laua atalii e avea ma tupu i luga o i latou.", "And it came to pass that the people desired of them that they should anoint one of their sons to be a king over them."]]},
  {num:23,words:[["Ma o lenei faauta,", "And now behold,"], ["sa faanoanoa tele i laua ona o lenei mea. Ma sa fai atu le uso o Iareto ia te i latou:", "this was grievous unto them. And the brother of Jared said unto them:"], ["E tau moni lava lenei mea i le faatagataotauaina.", "Surely this thing leadeth into captivity."]]},
  {num:24,words:[["Peitai sa fai atu Iareto i lona uso:", "But Jared said unto his brother:"], ["Tuu atu ia ia te i latou e fai so latou tupu. Ma o lea na ia fai atu ai ia te i latou:", "Suffer them that they may have a king. And therefore he said unto them:"], ["Ia outou filifili mai totonu o o maua atalii,", "Choose ye out from among our sons a king,"], ["le ua outou loto i ai.", "even whom ye will."]]},
  {num:25,words:[["Ma sa oo ina latou filifilia le atalii ulumatua lava o le uso o Iareto,", "And it came to pass that they chose even the firstborn of the brother of Jared;"], ["o lona igoa o Pakaka. Ma sa oo ina musu o ia ma le manao e avea mo o latou tupu. Ma sa mananao le nuu ia faamalosia o ia e lona tamā,", "and his name was Pagag. And it came to pass that he refused and would not be their king. And the people would that his father should constrain him,"], ["ae sa le loto i ai lona tamā;", "but his father would not;"], ["ma sa ia poloaiina i latou e le tatau ona latou faamalosia se tagata e avea mo o latou tupu.", "and he commanded them that they should constrain no man to be their king."]]},
  {num:26,words:[["Ma sa oo ina latou filifilia uso uma o Pakaka,", "And it came to pass that they chose all the brothers of Pagag,"], ["ma sa latou le mananao i ai.", "and they would not."]]},
  {num:27,words:[["Ma sa oo ina sa le mananao foi i ai atalii o Iareto,", "And it came to pass that neither would the sons of Jared,"], ["i latou uma lava, vagana ai le toatasi;", "even all save it were one;"], ["ma sa faauuina Oraea e avea ma tupu i luga o le nuu.", "and Orihah was anointed to be king over the people."]]},
  {num:28,words:[["Ma sa amata ona nofotupu o ia,", "And he began to reign,"], ["ma sa amata ona manuia o le nuu;", "and the people began to prosper;"], ["ma sa oo ina latou mauoa tele lava.", "and they became exceedingly rich."]]},
  {num:29,words:[["Ma sa oo ina maliu Iareto,", "And it came to pass that Jared died,"], ["ma lona uso foi.", "and his brother also."]]},
  {num:30,words:[["Ma sa oo ina savali Oraea ma le faamaualalo i luma o le Alii,", "And it came to pass that Orihah did walk humbly before the Lord,"], ["ma ia manatua mea tetele na faia e le Alii mo lona tamā,", "and did remember how great things the Lord had done for his father,"], ["ma sa ia aoaoina foi lona nuu e uiga i mea tetele na faia e le Alii mo o latou tamā.", "and also taught his people how great things the Lord had done for their fathers."]]},
];
renderVerseSet(et_ch_6_Verses, 'et-ch6-verses');

var et_ch_7_Verses = [
  {num:1,words:[["Ma sa oo ina faia e Oraea faamasinoga ma le amiotonu i luga o le laueleele i ona aso uma,", "And it came to pass that Orihah did execute judgment upon the land in righteousness all his days,"], ["o le sa matua tele lava ona aso.", "whose days were exceedingly many."]]},
  {num:2,words:[["Ma sa fanaua e ia atalii ma afafine;", "And he begat sons and daughters;"], ["ioe,", "yea,"], ["sa ia fanauina le tolu sefulu ma le tasi,", "he begat thirty and one,"], ["sa i ai i totonu o i latou ni atalii e lua sefulu ma le tolu.", "among whom were twenty and three sons."]]},
  {num:3,words:[["Ma sa oo ina fanauina foi e ia Kipi i tausaga o lona toeaina. Ma sa oo ina nofotupu Kipi i lona tulaga;", "And it came to pass that he also begat Kib in his old age. And it came to pass that Kib reigned in his stead;"], ["ma sa fanauina e Kipi Kori'oa.", "and Kib begat Corihor."]]},
  {num:4,words:[["Ma ina ua tolusefulu ma le lua tausaga o Kori'oa,", "And when Corihor was thirty and two years old he rebelled against his father,"], ["sa fouvale o ia i lona tamā,", "and went over and dwelt in the land of Nehor;"], ["ma sa alu atu o ia ma nofo i le laueleele o Ne'oa; ma sa fanauina e ia atalii ma afafine,", "and he begat sons and daughters,"], ["ma sa oo ina lalelei lava i latou;", "and they became exceedingly fair;"], ["o le mea lea na faatosina atu ai e Kori'oa tagata e toatele ia mulimuli atu ia te ia.", "wherefore Corihor drew away many people after him."]]},
  {num:5,words:[["Ma ina ua uma ona ia faapotopotoina faatasi o se autau,", "And when he had gathered together an army he came up unto the land of Moron where the king dwelt,"], ["sa alu ae o ia i le laueleele o Morona lea sa nofo ai le tupu, ma ave o ia faatagataotaua,", "and took him captive,"], ["lea na taunuu ai le upu a le uso o Iareto o le a aumai i latou i le faatagataotaua.", "which brought to pass the saying of the brother of Jared that they would be brought into captivity."]]},
  {num:6,words:[["O lenei o le laueleele o Morona,", "Now the land of Moron,"], ["lea sa nofo ai le tupu,", "where the king dwelt,"], ["sa latalata i le laueleele lea sa taua o Tuufua e sa Nifaē.", "was near the land which is called Desolation by the Nephites."]]},
  {num:7,words:[["Ma sa oo ina nofo Kipi faatagataotaua,", "And it came to pass that Kib dwelt in captivity,"], ["ma lona nuu, i lalo o le pule a Kori'oa,", "and his people under Corihor his son,"], ["lona atalii,", "until he became exceedingly old;"], ["seia oo ina toeaina lava o ia; e ui i lea sa fanauina e Kipi ia Sule i tausaga o lona toeaina lava,", "nevertheless Kib begat Shule in his old age,"], ["ao i ai pea o ia i le faatagataotauaina.", "while he was yet in captivity."]]},
  {num:8,words:[["Ma sa oo ina ita Sule i lona uso;", "And it came to pass that Shule was angry with his brother;"], ["ma sa faasolo ina malosi Sule,", "and Shule waxed strong,"], ["ma sa oo ina malosi tele e tusa ma le malosi o le tagata matua;", "and became mighty as to the strength of a man;"], ["ma sa malosi tele foi o ia i le faautauta.", "and he was also mighty in judgment."]]},
  {num:9,words:[["O le mea lea, na alu atu ai o ia i le mauga o Efaraima,", "Wherefore,"], ["ma ia faaliusuavaia le oa mai le mauga,", "he came to the hill Ephraim,"], ["ma fai ai pelu mai le sila mo i latou o e na ia tosina ese faatasi ma ia;", "and he did molten out of the hill,"], ["ma ina ua uma ona ia faaauupegaina o i latou i pelu, sa ia toe foi mai i le aai o Ne'oa,", "and made swords out of steel for those whom he had drawn away with him;"], ["ma tau ma lona uso o Kori'oa, lea na ia maua ai le malo,", "and after he had armed them with swords he returned to the city Nehor and gave battle unto his brother Corihor,"], ["ma toefuatai atu i lona tamā o Kipi.", "by which means he obtained the kingdom and restored it unto his father Kib."]]},
  {num:10,words:[["Ma o lenei ona o le mea na faia e Sule,", "And now because of the thing which Shule had done,"], ["sa faaee e lona tamā i luga o ia le malo;", "his father bestowed upon him the kingdom;"], ["o lea na amata ai ona nofotupu o ia i le tulaga o lona tamā.", "therefore he began to reign in the stead of his father."]]},
  {num:11,words:[["Ma sa oo ina faia e ia faamasinoga i le amiotonu;", "And it came to pass that he did execute judgment in righteousness;"], ["ma sa ia faasosolo lona malo i luga o le laueleele,", "and he did spread his kingdom upon all the face of the land,"], ["ona ua matua toatele lava tagata.", "for the people had become exceedingly numerous."]]},
  {num:12,words:[["Ma sa oo ina fanauina foi e Sule atalii ma afafine e toatele.", "And it came to pass that Shule also begat many sons and daughters."]]},
  {num:13,words:[["Ma sa oo ina salamo Kori'oa i le tele o mea leaga na ia faia;", "And Corihor repented of the many evils which he had done;"], ["o le mea lea na tuu atu ai e Sule ia te ia se pule i lona malo.", "wherefore Shule gave him power in his kingdom."]]},
  {num:14,words:[["Ma sa oo ina i ai ia Kori'oa atalii ma afafine e toatele. Ma sa i ai i totonu o atalii o Kori'oa se tasi na igoa ia Noa.", "And it came to pass that Corihor had many sons and daughters. And among the sons of Corihor there was one whose name was Noah."]]},
  {num:15,words:[["Ma sa oo ina fouvale Noa ia Sule,", "And it came to pass that Noah rebelled against Shule,"], ["le tupu,", "the king,"], ["ma lona tamā foi o Kori'oa, ma ia faatosina ese Ko'oro,", "and also his father Corihor,"], ["lona uso,", "and drew away Cohor his brother,"], ["ma ona uso uma ma le toatele o le nuu.", "and also all his brethren and many of the people."]]},
  {num:16,words:[["Ma sa tau o ia ma Sule,", "And he gave battle unto Shule the king,"], ["le tupu, lea na ia maua ai le laueleele o lo latou tofi muamua;", "in which he did obtain the land of their first inheritance;"], ["ma sa avea o ia ma tupu i luga o le vaega lena o le laueleele.", "and he became a king over that part of the land."]]},
  {num:17,words:[["Ma sa oo ina toe tau o ia ma Sule,", "And it came to pass that he gave battle again unto Shule,"], ["le tupu;", "the king;"], ["ma sa ia ave Sule,", "and he took Shule,"], ["le tupu,", "the king,"], ["ma ave o ia faatagataotaua i Morona.", "and carried him away captive into Moron."]]},
  {num:18,words:[["Ma sa oo ina o le a ia fasioti ia te ia,", "And it came to pass as he was about to put him to death,"], ["sa tolotolo atu atalii o Sule i le fale o Noa i le po ma fasioti o ia,", "the sons of Shule crept into the house of Noah by night and slew him,"], ["ma talepe i lalo le faitotoa o le falepuipui ma aumai i fafo lo latou tamā,", "and broke down the door of the prison and brought out their father,"], ["ma tuu o ia i luga o lona nofoalii i lona lava malo.", "and placed him upon his throne in his own kingdom."]]},
  {num:19,words:[["O le mea lea,", "Wherefore,"], ["na atiae ai e le atalii o Noa lona malo e sui ia te ia;", "the son of Noah did build up his kingdom in his stead;"], ["e ui i lea sa latou le toe maua se mana i luga o Sule le tupu,", "nevertheless they did not gain power any more over Shule the king,"], ["ma sa oo ina manuia ma faasolo malolosi tagata o e sa i lalo o le pule a Sule le tupu.", "and the people who were under the reign of Shule the king did prosper exceedingly and wax great."]]},
  {num:20,words:[["Ma sa vaeluaina le atunuu;", "And the country was divided;"], ["ma sa i ai ni malo se lua,", "and there were two kingdoms,"], ["o le malo o Sule,", "the kingdom of Shule,"], ["ma le malo o Ko'oro,", "and the kingdom of Cohor,"], ["le atalii o Noa.", "the son of Noah."]]},
  {num:21,words:[["Ma sa faatonu e Ko'oro,", "And Cohor,"], ["le atalii o Noa,", "the son of Noah,"], ["lona nuu, ia tau ma Sule,", "caused that his people should give battle unto Shule,"], ["i le taua lea na manumalo ai Sule ia te i latou ma fasiotia Ko'oro.", "in which Shule did beat them and did slay Cohor."]]},
  {num:22,words:[["Ma o lenei sa i ai se atalii o Ko'oro na igoa ia Nimarota;", "And now Cohor had a son who was called Nimrod;"], ["ma sa tuu mai e Nimarota le malo o Ko'oro ia Sule,", "and Nimrod gave up the kingdom of Cohor unto Shule,"], ["ma sa fiafia Sule ia te ia;", "and he did gain favor in the eyes of Shule;"], ["o le mea lea na faaee ai e Sule agalelei tele i ona luga,", "wherefore Shule did bestow great favors upon him,"], ["ma sa ia faia i le malo o Sule e tusa ma ona manao.", "and he did do in the kingdom of Shule according to his desires."]]},
  {num:23,words:[["Ma o le nofoaiga foi a Sule na o mai ai perofeta i totonu o le nuu,", "And also in the reign of Shule there came prophets among the people,"], ["o e na auina mai e le Alii,", "who were sent from the Lord,"], ["ma vavalo mai o le amioleaga ma le ifo i tupua o tagata ua aumai ai se fetuu i luga o le laueleele,", "prophesying that the wickedness and idolatry of the people was bringing a curse upon the land,"], ["ma o le a faaumatia i latou pe afai latou te le salamo.", "and they should be destroyed if they did not repent."]]},
  {num:24,words:[["Ma sa oo ina faifai tagata e faasaga i perofeta,", "And it came to pass that the people did revile against the prophets,"], ["ma faatauemu ia te i latou. Ma sa oo ina faia e le tupu o Sule faamasinoga e faasaga ia te i latou o e na faifai e faasaga i perofeta.", "and did mock them. And it came to pass that king Shule did execute judgment against all those who did revile against the prophets."]]},
  {num:25,words:[["Ma sa ia faia se tulafono i le laueleele atoa,", "And he did execute a law throughout all the land,"], ["lea na tuu atu ai le pule i perofeta latou te o atu ai i soo se mea latou te loto i ai;", "which gave power unto the prophets that they should go whithersoever they would;"], ["ma o lenei mea na aumai ai tagata i le salamo.", "and by this cause the people were brought unto repentance."]]},
  {num:26,words:[["Ma ona sa salamo tagata ia latou amioletonu ma ifoga i tupua o lea na faasaoina ai i latou e le Alii,", "And because the people did repent of their iniquities and idolatries the Lord did spare them,"], ["ma sa amata ona latou toe manuia i le laueleele. Ma sa oo ina fanauina e Sule atalii ma afafine i tausaga o lona toeaina.", "and they began to prosper again in the land. And it came to pass that Shule begat sons and daughters in his old age."]]},
  {num:27,words:[["Ma sa le toe i ai ni taua i aso o Sule;", "And there were no more wars in the days of Shule;"], ["ma sa ia manatua mea tetele na faia e le Alii mo ona tamā i le aumaia o i latou e sopo mai i le moana tele i le laueleele na folafolaina;", "and he remembered the great things that the Lord had done for his fathers in bringing them across the great deep into the promised land;"], ["o le mea lea na ia faia faamasinoga i le amiotonu i ona aso uma.", "wherefore he did execute judgment in righteousness all his days."]]},
];
renderVerseSet(et_ch_7_Verses, 'et-ch7-verses');

var et_ch_8_Verses = [
  {num:1,words:[["Ma sa oo ina fanauina e ia Omera,", "And it came to pass that he begat Omer,"], ["ma sa nofotupu Omera i lona tulaga. Ma sa fanauina e Omera Iareto;", "and Omer reigned in his stead. And Omer begat Jared;"], ["ma sa fanauina e Iareto atalii ma afafine.", "and Jared begat sons and daughters."]]},
  {num:2,words:[["Ma sa fouvale Iareto i lona tamā,", "And Jared rebelled against his father,"], ["ma ua sau ma ua nofo i le laueleele o Hetu. Ma sa oo ina ia viivii faaoleole tagata e toatele,", "and came and dwelt in the land of Heth. And it came to pass that he did flatter many people,"], ["ona o ana upu poto,", "because of his cunning words,"], ["seia oo ina ia maua le afa o le malo.", "until he had gained the half of the kingdom."]]},
  {num:3,words:[["Ma ina ua uma ona ia maua o le afa o le malo sa ia sii taua atu i lona tamā,", "And when he had gained the half of the kingdom he gave battle unto his father,"], ["ma sa ia ave ai lona tamā faatagataotaua,", "and he did carry away his father into captivity,"], ["ma faia o ia ia auauna i le faatagataotauaina;", "and did make him serve in captivity;"]]},
  {num:4,words:[["Ma o lenei, i aso o le nofoaiga a Omera,", "And now,"], ["sa i ai o ia i le faatagataotauaina i le afa o ona aso.", "in the days of the reigns of Omer he was in captivity the half of his days."], ["Ma sa oo ina fanauina e ia atalii ma afafine, sa i ai i totonu o i latou Esoroma ma Korianetuma.", "And it came to pass that he begat sons and daughters among whom were Esrom and Coriantumr;"]]},
  {num:5,words:[["Ma sa laua feita tele i mea na fai e Iareto lo laua uso,", "And they were exceedingly angry because of the doings of Jared their brother,"], ["sa oo ina laua faatu se autau ma tau ma Iareto. Ma sa oo ina laua tau ma ia i le po.", "insomuch that they did raise an army and gave battle unto Jared. And it came to pass that they did give battle unto him by night."]]},
  {num:6,words:[["Ma sa oo ina ua uma ona laua fasioti o le autau a Iareto sa fai o le a laua fasioti foi o ia;", "And it came to pass that when they had slain the army of Jared they were about to slay him also;"], ["ma sa ia aioi mai ia te i laua e aua la te fasiotia o ia,", "and he plead with them that they would not slay him,"], ["ma o le a ia tuu atu le malo i lona tamā. Ma sa oo ina la tuu atu ia te ia lona ola.", "and he would give up the kingdom unto his father. And it came to pass that they did grant unto him his life."]]},
  {num:7,words:[["Ma o lenei sa matua faanoanoa tele Iareto ona o le aveesea o le malo,", "And now Jared became exceedingly sorrowful because of the loss of the kingdom,"], ["ona sa ia tuu atu lona loto atoa i le malo ma le mamalu o le lalolagi.", "for he had set his heart upon the kingdom and upon the glory of the world."]]},
  {num:8,words:[["O lenei, o le afafine o Iareto,", "Now the daughter of Jared being exceedingly expert,"], ["o se sa atamai tele,", "and seeing the sorrows of her father,"], ["ma ina ua vaai atu i le faanoanoa o lona tamā, sa mafaufau e fai se fuafuaga e mafai ai ona ia toe faafoi mai le malo i lona tamā.", "thought to devise a plan whereby she could redeem the kingdom unto her father."]]},
  {num:9,words:[["O lenei sa lalelei tele le afafine o Iareto. Ma sa oo ina talanoa o ia ma lona tamā,", "Now the daughter of Jared was exceedingly fair. And it came to pass that she did talk with her father,"], ["ma fai atu ia te ia:", "and said unto him:"], ["Aisea ea ua faanoanoa tele ai lou tamā? Na te lei faitauina ea talafaamaumau ia na aumai e o tatou tamā mai le isi itu i luga o le moana loloto? Faauta,", "Whereby hath my father so much sorrow? Hath he not read the record which our fathers brought across the great deep? Behold,"], ["e le o i ai ea se tala iina e uiga ia i latou o e anamua,", "is there not an account  concerning them of old,"], ["e faapea sa latou maua malo ma le mamalu tele e ala ia latou fuafuaga faalilolilo?", "that they by their secret plans did obtain kingdoms and great glory?"]]},
  {num:10,words:[["Ma o lenei,", "And now,"], ["o lea,", "therefore,"], ["ia aami e lou tamā Akiso,", "let my father send for Akish,"], ["le atalii o Kimino;", "the son of Kimnor;"], ["faauta foi,", "and behold,"], ["ua aulelei au,", "I am fair,"], ["ma o le a ou siva i ona luma, ma o le a ou faafiafia ia te ia,", "and I will dance before him,"], ["o le a fia faiava ai o ia ia te au;", "and I will please him,"], ["o le mea lea,", "that he will desire me to wife;"], ["afai e manao mai o ia ia te oe ia e te tuu atu au e avea ma ana ava,", "wherefore if he shall desire of thee that ye shall give unto him me to wife,"], ["ona e fai atu lea:", "then shall ye say:"], ["O le a ou tuuina atu o ia pe afai e te aumaia ia te au le ulu o lo'u tamā,", "I will give her if ye will bring unto me the head of my father,"], ["le tupu.", "the king."]]},
  {num:11,words:[["Ma o lenei o Omera o se sa avea ma uo ia Akiso;", "And now Omer was a friend to Akish;"], ["o le mea lea,", "wherefore,"], ["ina ua amia mai Akiso e Iareto,", "when Jared had sent for Akish,"], ["sa siva le afafine o Iareto i ona luma sa faafiafia ai o ia ia te ia,", "the daughter of Jared danced before him that she pleased him,"], ["sa oo ina manao o ia ia te ia e avea ma ana ava. Ma sa oo ina fai mai o ia ia Iareto:", "insomuch that he desired her to wife. And it came to pass that he said unto Jared:"], ["Tuu mai o ia ia te au e avea ma au ava.", "Give her unto me to wife."]]},
  {num:12,words:[["Ma sa fai atu Iareto ia te ia:", "And Jared said unto him:"], ["O le a ou avatu o ia ia te oe,", "I will give her unto you,"], ["pe afai e te aumaia ia te au le ulu o lo'u tamā,", "if ye will bring unto me the head of my father,"], ["le tupu.", "the king."]]},
  {num:13,words:[["Ma sa oo ina faapotopoto mai e Akiso i le fale o Iareto lona aiga uma,", "And it came to pass that Akish gathered in unto the house of Jared all his kinsfolk,"], ["ma fai atu ia te i latou:", "and said unto them:"], ["Tou te tauto mai ea ia te au o le a outou faamaoni mai ia te au i le mea lea o le a ou manao i ai mai ia te outou?", "Will ye swear unto me that ye will be faithful unto me in the thing which I shall desire of you?"]]},
  {num:14,words:[["Ma sa oo ina latou tauto uma ia te ia,", "And it came to pass that they all sware unto him,"], ["i le Atua o le lagi,", "by the God of heaven,"], ["ma i le lagi foi,", "and also by the heavens,"], ["ma le lalolagi ma o latou ulu,", "and also by the earth, and by their heads,"], ["o soo se tasi e ese mai le fesoasoani ua manao i ai Akiso o le a vaea lona ulu;", "that whoso should vary from the assistance which Akish desired should lose his head;"], ["ma o soo se tasi na te faailoa atu soo se mea o le a faailoa mai e Akiso ia te i latou,", "and whoso should divulge whatsoever thing Akish made known unto them,"], ["o ia lava lea o le a toesea lona ola.", "the same should lose his life."]]},
  {num:15,words:[["Ma sa oo ina faapea ona latou ioe faatasi ma Akiso. Ma sa tuu atu e Akiso ia te i latou tautoga ia na tuuina mai e i latou o anamua o e sa latou saili foi le pule,", "And it came to pass that thus they did agree with Akish. And Akish did administer unto them the oaths which were given by them of old who also sought power,"], ["lea na tuulima faasolo mai lava i lalo mai ia Kaino ,", "which had been handed down even from Cain,"], ["o le o se fasioti tagata mai le amataga.", "who was a murderer from the beginning."]]},
  {num:16,words:[["Ma sa faatumauina i latou e le mana o le tiapolo e tuu atu ia tautoga i tagata,", "And they were kept up by the power of the devil to administer these oaths unto the people,"], ["e taofi ai i latou i le pouliuli,", "to keep them in darkness,"], ["e fesoasoani i e faapena e saili i le pule ia latou maua le pule,", "to help such as sought power to gain power,"], ["ma fasioti tagata,", "and to murder,"], ["ma vete,", "and to plunder,"], ["ma pepelo,", "and to lie,"], ["ma fai amioleaga ma faitaaga uiga eseese uma.", "and to commit all manner of wickedness and whoredoms."]]},
  {num:17,words:[["Ma o le afafine o Iareto o le na ia tuuina i lona loto le manatu ia saili i nei mea mai anamua;", "And it was the daughter of Jared who put it into his heart to search up these things of old;"], ["ma o Iareto na tuuina i le loto o Akiso;", "and Jared put it into the heart of Akish;"], ["o le mea lea,", "wherefore,"], ["na tuu atu ai e Akiso i lona aiga ma ana uo,", "Akish administered it unto his kindred and friends,"], ["ma taitai ese atu ai i latou e ala i folafolaga logomalie e fai soo se mea sa manao i ai o ia.", "leading them away by fair promises to do whatsoever thing he desired."]]},
  {num:18,words:[["Ma sa oo ina latou faatuina se faapotopotoga faalilolilo,", "And it came to pass that they formed a secret combination,"], ["e pei lava o i latou anamua;", "even as they of old;"], ["o se faapotopotoga lea ua sili ona inosia ma amioleaga i mea uma,", "which combination is most abominable and wicked above all,"], ["i le silafaga a le Atua;", "in the sight of God;"]]},
  {num:19,words:[["Aua e le galue le Alii e ala i faapotopotoga faalilolilo,", "For the Lord worketh not in secret combi– nations,"], ["pe finagalo foi o ia ia faamasaa e tagata le toto,", "neither doth he will that man should shed blood,"], ["ae ua ia faasaina i mea uma,", "but in all things hath forbidden it,"], ["mai lava i le amataga o tagata.", "from the beginning of man."]]},
  {num:20,words:[["Ma o lenei o au,", "And now I,"], ["o Moronae,", "Moroni,"], ["ou te le tusia le uiga o a latou tautoga ma faapotopotoga faalilolilo,", "do not write the manner of their oaths and combinations,"], ["ona ua faailoa mai ia te au ua i ai ia mea i totonu o tagata uma,", "for it hath been made known unto me that they are had among all people,"], ["ma ua i ai i latou i totonu o sa Lamanā.", "and they are had among the Lamanites."]]},
  {num:21,words:[["Ma o ia mea na mafua ai le faafanoga o nei tagata ua ou talatala atu ai nei,", "And they have caused the destruction of this people of whom I am now speaking,"], ["ma le faafanoga foi o le nuu o Nifae.", "and also the destruction of the people of Nephi."]]},
  {num:22,words:[["Ma o soo se malo na te lagolagoina faapotopotoga faalilolilo faapea,", "And whatsoever nation shall uphold such secret combinations,"], ["e maua ai le pule ma le oa,", "to get power and gain,"], ["seia oo ina lolofi i luga o le atunuu,", "until they shall spread over the nation,"], ["faauta,", "behold,"], ["o le a faaumatia i latou;", "they shall be destroyed;"], ["aua o le a le tuuina e le Alii le toto o lana au paia,", "for the Lord will not suffer that the blood of his saints,"], ["lea o le a latou faamasaaina,", "which shall be shed by them,"], ["ia tagi mai pea ia te ia mai le eleele mo le tauimasui i luga o i latou ae na te le tauia.", "shall always cry unto him from the ground for vengeance upon them and yet he avenge them not."]]},
  {num:23,words:[["O le mea lea,", "Wherefore,"], ["outou Nuuese e,", "O ye Gentiles,"], ["o le poto o le Atua ua tatau ai ona faailoa atu o nei mea ia te outou,", "it is wisdom in God that these things should be shown unto you,"], ["ina ia outou salamo ai ia outou agasala,", "that thereby ye may repent of your sins,"], ["ma le tuuina ia faapotopotoga fasioti tagata ia oo ae i luga o outou,", "and suffer not that these murderous combinations shall get above you,"], ["ia ua atiae ia maua ai le pule ma le oa—ma o le a oo mai i o outou luga le galuega, ioe,", "which are built up to get power and gain—and the work,"], ["le galuega lava o le faafanoga,", "yea,"], ["ioe,", "even the work of destruction come upon you,"], ["o le a pau ifo lava le pelu o le faamasinotonu o le Atua Faavavau i o outou luga,", "yea,"], ["e faatoilalo ma faaumatia outou,", "even the sword of the justice of the Eternal God shall fall upon you,"], ["pe afai tou te tuu ia mea ia oo mai.", "to your overthrow and destruct– tion if ye shall suffer these things to be."]]},
  {num:24,words:[["O le mea lea,", "Wherefore,"], ["ua poloaiina ai outou e le Alii,", "the Lord commandeth you,"], ["pe a outou vaai ua oo mai nei mea i totonu ia te outou o le a outou feala mai i se lagona o lo outou tulaga leaga matautia,", "when ye shall see these things come among you that ye shall awake to a sense of your awful situation,"], ["ona o lenei faapotopotoga faalilolilo o le a i ai i totonu o outou;", "because of this secret combination which shall be among you;"], ["a leai oi talofa i lena faapotopotoga faalilolilo,", "or wo be unto it,"], ["ona o le toto o i latou o e ua fasiotia;", "because of the blood of them who have been slain;"], ["ona ua latou tagi mai i le eleele mo le tauimasui i i luga o lea faapotopotoga faalilolilo,", "for they cry from the dust for vengeance upon it,"], ["ma luga foi o i latou o e na atiinaeina i luga.", "and also upon those who built it up."]]},
  {num:25,words:[["Aua o soo se tasi na te atiina ae i luga,", "For it cometh to pass that whoso buildeth it up seeketh to overthrow the freedom of all lands,"], ["ua saili o ia e faatoilalo le saolotoga o laueleele uma,", "nations,"], ["malo, ma atunuu;", "and countries;"], ["ma o le a ia aumai le faafanoga o nuu uma,", "and it bringeth to pass the destruction of all people,"], ["ona ua atiae e le tiapolo,", "for it is built up by the devil,"], ["o le o le tamā o pepelo uma lava;", "who is the father of all lies;"], ["le pepelo lava lena na ia faaseseina o tatou uluai matua,", "even that same liar who beguiled our first parents,"], ["ioe,", "yea,"], ["le pepelo lava lea na ia uunaia le tagata mai le amataga ia fasioti tagata;", "even that same liar who hath caused man to commit murder from the beginning;"], ["o le na faamaaaina loto o tagata na latou fasioti ai perofeta, ma fetogia i latou i maa,", "who hath hardened the hearts of men that they have murdered the prophets,"], ["ma tutuli ese i latou,", "and stoned them,"], ["mai le amataga.", "and cast them out from the beginning."]]},
  {num:26,words:[["O le mea lea,", "Wherefore,"], ["na poloaiina ai au,", "I,"], ["o Moronae,", "Moroni,"], ["ia ou tusia nei mea, ina ia aveesea le leaga,", "am commanded to write these things that evil may be done away,"], ["ma ina ia oo mai ai le taimi e le mafai ai e Satani ona toe maua se mana i loto o le fanauga a tagata,", "and that the time may come that Satan may have no power upon the hearts of the children of men,"], ["ae ina ia mafai ona faatauanauina o i latou ia latou faia le lelei e le aunoa,", "but that they may be persuaded to do good continually,"], ["ina ia mafai ona latou o mai i le puna o le amiotonu uma ma faaolaina i latou.", "that they may come unto the fountain of all righteousness and be saved."]]},
];
renderVerseSet(et_ch_8_Verses, 'et-ch8-verses');

var et_ch_9_Verses = [
  {num:1,words:[["Ma o lenei o au,", "And now I,"], ["o Moronae,", "Moroni,"], ["ou te faasolo atu i lau talafaamaumau. O lea,", "proceed with my record. Therefore,"], ["faauta,", "behold,"], ["ona o faalapotopotoga faalilolilo a Akiso ma ana uo,", "it came to pass that because of the secret combinations of Akish and his friends,"], ["faauta,", "behold,"], ["sa oo ai ina latou faatoilaloina le malo o Omera.", "they did overthrow the kingdom of Omer."]]},
  {num:2,words:[["E ui i lea,", "Nevertheless,"], ["sa alofa mutimutivale le Alii ia Omera,", "the Lord was merciful unto Omer,"], ["ma ona atalii foi ma ona afafine o e sa latou le saili lona faaumatiaga.", "and also to his sons and to his daughters who did not seek his destruction."]]},
  {num:3,words:[["Ma sa lapataia Omera e le Alii i se miti e tatau ona ia alu ese atu i fafo mai le laueleele;", "And the Lord warned Omer in a dream that he should depart out of the land;"], ["o le mea lea na alu ese atu ai Omera i fafo mai le laueleele faatasi ma lona aiga,", "wherefore Omer departed out of the land with his family,"], ["ma malaga i aso e tele,", "and traveled many days,"], ["ma o mai i luga ma ui ane i tafatafa o le maupuepue o Semi ,", "and came over and passed by the hill of Shim,"], ["ma o mai i tafatafa ane o le nofoaga lea sa faaumatia ai sa Nifaē,", "and came over by the place where the Nephites were destroyed,"], ["ma mai iina i sasae,", "and from thence eastward,"], ["ma o atu i se nofoaga sa taua o Apeloma,", "and came to a place which was called Ablom,"], ["i tala ane o le matafaga,", "by the seashore,"], ["ma o iina na ia faatu ai lona faleie,", "and there he pitched his tent,"], ["ma ona atalii foi ma ona afafine,", "and also his sons and his daughters,"], ["ma lona auaiga uma,", "and all his household,"], ["vagana ai Iareto ma lona aiga.", "save it were Jared and his family."]]},
  {num:4,words:[["Ma sa oo ina faauuina Iareto o se tupu i luga o le nuu,", "And it came to pass that Jared was anointed king over the people,"], ["e le lima o le amioleaga;", "by the hand of wicked– ness;"], ["ma tuu atu ia Akiso lona afafine e avea ma ana ava.", "and he gave unto Akish his daughter to wife."]]},
  {num:5,words:[["Ma sa oo ina saili e Akiso le ola o le tamā o lana ava;", "And it came to pass that Akish sought the life of his father– in– law;"], ["ma sa ia talanoa atu ia i latou o e na ia faatautoina i le tautoga a tagata anamua,", "and he applied unto those whom he had sworn by the oath of the ancients,"], ["ma sa latou mauaina le ulu o le tamā o lana ava,", "and they obtained the head of his father– in– law,"], ["ao nofo o ia i luga o lona nofoalii,", "as he sat upon his throne,"], ["ao alo faafofoga atu i ona tagata.", "giving audience to his people."]]},
  {num:6,words:[["Ona sa matua tele lava le sosolo o lenei sosaiete amioleaga ma faalilolilo sa faaleaga ai loto o tagata uma;", "For so great had been the spreading of this wicked and secret society that it had corrupted the hearts of all the people;"], ["o lea na fasiotia ai Iareto i luga o lona nofoalii,", "therefore Jared was murdered upon his throne,"], ["ma nofotupu ai Akiso i lona tulaga.", "and Akish reigned in his stead."]]},
  {num:7,words:[["Ma sa oo ina amata ona fua o Akiso i lona atalii,", "And it came to pass that Akish began to be jealous of his son,"], ["o lea na ia tapunia ai o ia i le falepuipui,", "therefore he shut him up in prison,"], ["ma tausi o ia i nai meaai itiiti po o le leai foi seia oo ina mafatia o ia i le oti.", "and kept him upon little or no food until he had suffered death."]]},
  {num:8,words:[["Ma o lenei o le uso o ia o le na mafatia i le oti,", "And now the brother of him that suffered death,"], ["(ma o lona igoa o Nimara) sa ita i lona tamā ona o lena mea na faia e lona tamā i lona uso.", "(and his name was Nimrah) was angry with his father because of that which his father had done unto his brother."]]},
  {num:9,words:[["Ma sa oo ina faapotopoto e Nimara se aofai toaitiiti o tagata,", "And it came to pass that Nimrah gathered together a small number of men,"], ["ma sosola ese i fafo o le laueleele,", "and fled out of the land,"], ["ma o mai i luga ma ua nonofo faatasi ma Omera.", "and came over and dwelt with Omer."]]},
  {num:10,words:[["Ma sa oo ina fanauina e Akiso isi atalii,", "And it came to pass that Akish begat other sons,"], ["ma sa fiafia le nuu ia te i latou,", "and they won the hearts of the people,"], ["e ui ina sa latou tauto ia te ia o le a latou faia amioletonu uiga eseese uma e tusa ma mea sa manao i ai o ia.", "notwithstanding they had sworn unto him to do all manner of iniquity according to that which he desired."]]},
  {num:11,words:[["O lenei sa mananao tagata o Akiso i oa,", "Now the people of Akish were desirous for gain,"], ["e pei ona manao Akiso i le pule;", "even as Akish was desirous for power;"], ["o le mea lea,", "wherefore,"], ["na tuu atu ai ia te i latou e atalii o Akiso o tupe,", "the sons of Akish did offer them money,"], ["o se ala lea na latou faatosina ese atu ai le vaega tele o tagata ia mulimuli atu ia te i latou.", "by which means they drew away the more part of the people after them."]]},
  {num:12,words:[["Ma sa amata ona i ai o se taua i le va o atalii o Akiso ma Akiso,", "And there began to be a war between the sons of Akish and Akish,"], ["lea sa tumau mo le va o tausaga e tele,", "which lasted for the space of many years,"], ["ioe,", "yea,"], ["seia oo ina toetoe a faaumatia ai tagata uma o le malo,", "unto the destruction of nearly all the people of the kingdom,"], ["ioe,", "yea,"], ["tagata uma lava,", "even all,"], ["vagana ai ni tagata e tolusefulu,", "save it were thirty souls,"], ["ma i latou o e na sosola faatasi ma le aiga o Omera.", "and they who fled with the house of Omer."]]},
  {num:13,words:[["O le mea lea na toefuatai ai Omera i le laueleele o lona tofi.", "Wherefore, Omer was restored again to the land of his inheritance."]]},
  {num:14,words:[["Ma sa oo ina amata ona toeaina o Omera;", "And it came to pass that Omer began to be old;"], ["e ui i lea,", "nevertheless,"], ["sa fanauina e ia Emera i tausaga o lona toeaina;", "in his old age he begat Emer;"], ["ma sa ia faauuina Emera e avea ma tupu e nofo e sui ia te ia.", "and he anointed Emer to be king to reign in his stead."]]},
  {num:15,words:[["Ma ina ua uma ona ia faauuina o Emera e avea ma tupu sa vaai o ia i le filemu i le laueleele mo le va o le lua tausaga,", "And after that he had anointed Emer to be king he saw peace in the land for the space of two years,"], ["ma oti ai o ia,", "and he died,"], ["ina ua mavae lea ona vaai i le tele o aso,", "having seen exceedingly many days,"], ["ia sa tumu i le faanoanoa. Ma sa oo ina nofo Emera e sui ia te ia,", "which were full of sorrow. And it came to pass that Emer did reign in his stead,"], ["ma sa mulimuli o ia i tulaga o lona tamā.", "and did fill the steps of his father."]]},
  {num:16,words:[["Ma sa toe amata ona aveese e le Alii le fetuu mai le laueleele,", "And the Lord began again to take the curse from off the land,"], ["ma sa manuia tele lava le aiga o Emera i lalo o le nofoaiga a Emera;", "and the house of Emer did prosper exceedingly under the reign of Emer;"], ["ma i le va o le ono sefulu ma le lua o tausaga sa avea i latou ma ni tagata malolosi tele,", "and in the space of sixty and two years they had become exceedingly strong,"], ["sa oo ina latou matua mauoa lava—", "insomuch that they became exceedingly rich—"]]},
  {num:17,words:[["I le latou maua o fualaau aina eseese,", "Having all manner of fruit,"], ["ma saito,", "and of grain,"], ["ma silika,", "and of silks,"], ["ma lino lelei,", "and of fine linen,"], ["ma le auro,", "and of gold,"], ["ma le ario,", "and of silver,"], ["ma mea taua.", "and of precious things;"]]},
  {num:18,words:[["Ma ituaiga eseese uma o povi,", "And also all manner of cattle,"], ["o povi poa,", "of oxen,"], ["ma povi fafine,", "and cows,"], ["ma mamoe,", "and of sheep,"], ["ma puaa,", "and of swine,"], ["ma oti,", "and of goats,"], ["ma isi ituaiga o manu e tele sa aoga mo meaai a tagata.", "and also many other kinds of animals which were useful for the food of man."]]},
  {num:19,words:[["Ma sa i ai foi ia te i latou o solofanua ,", "And they also had horses,"], ["ma asini,", "and asses,"], ["ma sa i ai elefane ma kureloma ma kumoma;", "and there were elephants and cureloms and cumoms;"], ["o ni mea uma ia sa aoga i le tagata,", "all of which were useful unto man,"], ["ma aemaise lava elefane ma kureloma ma kumoma.", "and more especially the elephants and cureloms and cumoms."]]},
  {num:20,words:[["Ma sa faapea ona sasaa mai e le Alii ana faamanuiaga i luga o lenei laueleele,", "And thus the Lord did pour out his blessings upon this land,"], ["lea sa silisili ona lelei i luga o isi laueleele uma;", "which was choice above all other lands;"], ["ma ua ia poloaiina o soo se tasi na te mauaina le laueleele e tatau ona ia mauaina mo le Alii,", "and he commanded that whoso should possess the land should possess it unto the Lord,"], ["a leai o le a faaumatia i latou pe a latou matua i le amioletonu;", "or they should be destroyed when they were ripened in iniquity;"], ["ona o luga o i latou faapea,", "for upon such,"], ["ua fetalai mai ai le Alii:", "saith the Lord:"], ["O le a ou sasaa atu i ai le atoatoa o lou ita.", "I will pour out the fulness of my wrath."]]},
  {num:21,words:[["Ma sa fai e Emera faamasinoga i le amiotonu i ona aso uma,", "And Emer did execute judgment in righteousness all his days,"], ["ma sa fanauina e ia atalii ma afafine e toatele;", "and he begat many sons and daughters;"], ["ma sa fanauina e ia Korianetumu,", "and he begat Coriantum,"], ["ma sa ia faauuina Korianetumu e suitulaga ia te ia.", "and he anointed Coriantum to reign in his stead."]]},
  {num:22,words:[["Ma ina ua uma ona faauu e ia Korianetumu e suitulaga ia te ia,", "And after he had anointed Coriantum to reign in his stead he lived four years,"], ["sa soifua o ia i tausaga e fa,", "and he saw peace in the land;"], ["ma sa vaai o ia i le filemu i le laueleele; ioe,", "yea,"], ["ma sa vaai lava o ia i le Atalii o le Amiotonu,", "and he even saw the Son of Righteousness,"], ["ma sa olioli ma vivii e uiga i lona aso;", "and did rejoice and glory in his day;"], ["ma sa maliu filemu o ia.", "and he died in peace."]]},
  {num:23,words:[["Ma sa oo ina savali Korianetumu i tulaga o lona tamā,", "And it came to pass that Coriantum did walk in the steps of his father,"], ["ma ia fausia aai tetele e tele,", "and did build many mighty cities,"], ["ma faia i lona nuu mea lelei i ona aso uma. Ma sa oo ina sa leai sana fanau seia oo ina toeaina lava o ia.", "and did administer that which was good unto his people in all his days. And it came to pass that he had no children even until he was exceedingly old."]]},
  {num:24,words:[["Ma sa oo ina maliu lana ava,", "And it came to pass that his wife died,"], ["ina ua selau ma le lua ona tausaga.", "being an hundred and two years old."], ["Ma sa oo ina ave e Korianetumu,", "And it came to pass that Coriantum took to wife,"], ["e avea ma ana ava,", "in his old age,"], ["ina ua toeaina o ia, se tamaitai talavou,", "a young maid,"], ["ma fanauina ai ni atalii ma afafine;", "and begat sons and daughters;"], ["o le mea lea sa soifua o ia seia oo i le selau fa sefulu ma le lua tausaga o lona matua.", "wherefore he lived until he was an hundred and forty and two years old."]]},
  {num:25,words:[["Ma sa oo ina fanauina e ia Komi,", "And it came to pass that he begat Com,"], ["ma sa nofo Komi e sui ia te ia;", "and Com reigned in his stead;"], ["ma sa nofotupu o ia i tausaga e fa sefulu ma le iva,", "and he reigned forty and nine years,"], ["ma sa fanauina ai e ia Hetu;", "and he begat Heth;"], ["ma sa ia fanauina foi ni isi atalii ma afafine.", "and he also begat other sons and daughters."]]},
  {num:26,words:[["Ma sa toe salalau atu le nuu i luga o le laueleele atoa,", "And the people had spread again over all the face of the land,"], ["ma sa toe amata ona i ai o le amioleaga tele i luga o le laueleele,", "and there began again to be an exceedingly great wickedness upon the face of the land,"], ["ma sa amata e Hetu ona toe opogi o fuafuaga faalilolilo mai anamua,", "and Heth began to embrace the secret plans again of old,"], ["e faaumatia ai lona tamā.", "to destroy his father."]]},
  {num:27,words:[["Ma sa oo ina aveese e ia lona tamā mai le nofoalii,", "And it came to pass that he did dethrone his father,"], ["aua sa ia fasioti ia te ia i lana lava pelu;", "for he slew him with his own sword;"], ["ma sa nofo o ia i lona tulaga.", "and he did reign in his stead."]]},
  {num:28,words:[["Ma sa i ai perofeta sa toe o mai i le laueleele,", "And there came prophets in the land again,"], ["ma alaga mai le salamo ia te i latou—e faapea e ao ina latou teuteu le ala o le Alii a leai o le a oo mai se fetuu i luga o le laueleele;", "crying repentance unto them—that they must prepare the way of the Lord or there should come a curse upon the face of the land;"], ["ioe,", "yea,"], ["o le a oo mai lava se oge tele,", "even there should be a great famine,"], ["lea o le a faaumatia ai i latou pe afai latou te le salamo.", "in which they should be destroyed if they did not repent."]]},
  {num:29,words:[["Peitai sa le talitonu tagata i upu a perofeta,", "But the people believed not the words of the prophets,"], ["ae sa latou tutuli i latou i fafo;", "but they cast them out;"], ["ma o ni isi o i latou sa latou lafo i totonu o lua ma tuu i latou ia fano ai. Ma sa oo ina latou faia nei mea uma e tusa ma le poloaiga a le tupu,", "and some of them they cast into pits and left them to perish. And it came to pass that they did all these things according to the commandment of the king,"], ["o Hetu.", "Heth."]]},
  {num:30,words:[["Ma sa oo ina amata ona i ai o se lamala tele i luga o le laueleele,", "And it came to pass that there began to be a great dearth upon the land,"], ["ma sa amata ona faaumatia vave tagata ona o le lamala,", "and the inhabitants began to be destroyed exceedingly fast because of the dearth,"], ["ona ua leai se timu i luga o le laueleele.", "for there was no rain upon the face of the earth."]]},
  {num:31,words:[["Ma sa o mai ni gata uogo i luga o le laueleele,", "And there came forth poisonous serpents also upon the face of the land,"], ["ma ona ai tagata e toatele. Ma sa oo ina amata ona sosola o a latou lafu i luma o gata uogo,", "and did poison many people. And it came to pass that their flocks began to flee before the poisonous serpents,"], ["agai i le laueleele i saute,", "towards the land southward,"], ["lea sa taua e sa Nifaē o Sara'emila .", "which was called by the Nephites Zarahemla."]]},
  {num:32,words:[["Ma sa oo ina fano le tele o i latou i le ala;", "And it came to pass that there were many of them which did perish by the way;"], ["e ui i lea,", "nevertheless,"], ["e i ai ni isi sa sosola atu i le laueleele i saute.", "there were some which fled into the land southward."]]},
  {num:33,words:[["Ma sa oo ina faia e le Alii ia le toe tuliloaina i latou e gata uogo,", "And it came to pass that the Lord did cause the serpents that they should pursue them no more,"], ["ae ia latou punitia le ala ina ia le mafai e tagata ona ui atu ai,", "but that they should hedge up the way that the people could not pass,"], ["ina ia mafai ai ona pau i gata uoga soo se tasi e taumafai e ui atu ai.", "that whoso should attempt to pass might fall by the poisonous serpents."]]},
  {num:34,words:[["Ma sa oo ina mulimuli atu tagata i le ala o manu,", "And it came to pass that the people did follow the course of the beasts,"], ["ma ai tino o i latou na pauu i le ala,", "and did devour the carcasses of them which fell by the way,"], ["seia oo ina latou aia uma i latou. O lenei ina ua vaai tagata o le a latou fano sa amata ona latou salamo ia latou amioletonu ma tagi atu i le Alii.", "until they had devoured them all. Now when the people saw that they must perish they began to repent of their iniquities and cry unto the Lord."]]},
  {num:35,words:[["Ma sa oo ina ua lava lo latou faalotomaualalaloina o i latou lava i luma o le Alii sa toe auina mai e ia le timu i luga o le eleele;", "And it came to pass that when they had humbled themselves sufficiently before the Lord he did send rain upon the face of the earth;"], ["ma sa amata ona toe malolosi o tagata,", "and the people began to revive again,"], ["ma sa amata ona i ai o fualaau aina i laufanua i matu,", "and there began to be fruit in the north countries,"], ["ma laufanua e taamilo ai. Ma sa faaali mai e le Alii lona mana ia te i latou i le faasaoina o i latou mai le oge.", "and in all the countries round about. And the Lord did show forth his power unto them in preserving them from famine."]]},
];
renderVerseSet(et_ch_9_Verses, 'et-ch9-verses');

var et_ch_10_Verses = [
  {num:1,words:[["Ma sa oo ina amata Sesa,", "And it came to pass that Shez,"], ["o le na tupuga mai ia Hetu—aua sa fano Hetu i le oge,", "who was a descendant of Heth—for Heth had perished by the famine,"], ["ma lona aiga atoa vagana ai Sesa—o le mea lea,", "and all his household save it were Shez—wherefore,"], ["sa oo ina amata ai e Sesa ona toe atiae se nuu ua vaevaeina.", "Shez began to build up again a broken people."]]},
  {num:2,words:[["Ma sa oo ina manatua e Sesa le faaumatiaga o ona tamā,", "And it came to pass that Shez did remember the destruction of his fathers,"], ["ma sa ia atiae se malo amiotonu;", "and he did build up a righteous kingdom;"], ["ona sa ia manatua mea na faia e le Alii i le aumaia o Iareto ma lona uso e sopo mai i le moana;", "for he remembered what the Lord had done in bringing Jared and his brother across the deep;"], ["ma sa savali o ia i ala o le Alii;", "and he did walk in the ways of the Lord;"], ["ma sa ia fanauina atalii ma afafine.", "and he begat sons and daughters."]]},
  {num:3,words:[["Ma o lona atalii ulumatua,", "And his eldest son,"], ["o le o lona igoa o Sesa,", "whose name was Shez,"], ["sa fouvale ia te ia;", "did rebel against him;"], ["e ui i lea,", "nevertheless,"], ["sa taina Sesa e le lima o se faomea,", "Shez was smitten by the hand of a robber,"], ["ona o lona mauoa tele,", "because of his exceeding riches,"], ["lea na toe aumai ai le toafilemu i lona tamā.", "which brought peace again unto his father."]]},
  {num:4,words:[["Ma sa oo ina fausia e lona tamā aai e tele i luga o le laueleele,", "And it came to pass that his father did build up many cities upon the face of the land,"], ["ma sa toe amata ona salalau atu o tagata i luga o le laueleele atoa. Ma sa soifua Sesa seia oo i ni tausaga ua toeaina lava;", "and the people began again to spread over all the face of the land. And Shez did live to an exceedingly old age;"], ["ma sa fanauina e ia Ripelakiso. Ma sa maliu o ia,", "and he begat Riplakish. And he died,"], ["ma nofotupu ai Ripelakiso e sui ia te ia.", "and Riplakish reigned in his stead."]]},
  {num:5,words:[["Ma sa oo ina le faia e Ripelakiso mea sao i le silafaga a le Alii,", "And it came to pass that Riplakish did not do that which was right in the sight of the Lord,"], ["ona sa ia te ia ni ava ma ni palake e toatele,", "for he did have many wives and concubines,"], ["ma ia tuu i luga o tauau o tagata mea sa faigata ona tauaveina;", "and did lay that upon men’s shoulders which was grievous to be borne;"], ["ioe,", "yea,"], ["sa ia faalafogaina i latou i lafoga mamafa;", "he did tax them with heavy taxes;"], ["ma sa ia fausia i lafoga ni fale vateatea e tele.", "and with the taxes he did build many spacious buildings."]]},
  {num:6,words:[["Ma sa ia faatuina mo ia lava se nofoalii matagofie tele;", "And he did erect him an exceedingly beautiful throne;"], ["ma sa ia fausia ni falepuipui e tele,", "and he did build many prisons,"], ["ma o soo se tasi sa le manao e totogi le lafoga sa ia lafoina i le falepuipui;", "and whoso would not be subject unto taxes he did cast into prison;"], ["ma o soo se tasi sa le mafai ona ia totogia le lafoga sa ia lafoina i le falepuipui;", "and whoso was not able to pay taxes he did cast into prison;"], ["ma sa ia faatonu atu ia latou galulue pea mo lo latou tausiga;", "and he did cause that they should labor continually for their support;"], ["ma o soo se tasi sa musu e galue sa ia faatonu atu ia fasiotia.", "and whoso refused to labor he did cause to be put to death."]]},
  {num:7,words:[["O le mea lea na ia maua ai ana galuega matagofie uma,", "Wherefore he did obtain all his fine work,"], ["ioe,", "yea,"], ["e oo lava i ana auro lelei, sa ia faatonuina ia faamama i le falepuipui;", "even his fine gold he did cause to be refined in prison,"], ["ma o galuega taulima matagofie uma o ituaiga eseese sa ia faatonuina ia faia i le falepuipui.", "and all manner of fine workmanship he did cause to be wrought in prison."], ["Ma sa oo ina ia faapuapuagatia tagata i ana faitaaga ma mea inosia.", "And it came to pass that he did afflict the people with his whoredoms and abominations."]]},
  {num:8,words:[["Ma ina ua mavae le va o tausaga e fa sefulu ma le lua o nofotupu o ia sa oo ina sa tutulai ae tagata e fouvale e faasaga ia te ia;", "And when he had reigned for the space of forty and two years the people did rise up in rebellion against him;"], ["ma sa amata ona toe i ai o taua i le laueleele,", "and there began to be war again in the land,"], ["sa oo ina fasiotia ai Ripelakiso,", "insomuch that Riplakish was killed,"], ["ma tutuli ese ai ana fanau i fafo mai le laueleele.", "and his descendants were driven out of the land."]]},
  {num:9,words:[["Ma sa oo ina ua mavae le va o tausaga e tele,", "And it came to pass after the space of many years,"], ["sa faapotopoto faatasi e Morianetona,", "Morianton,"], ["(o ia o se e tupuga mai ia Ripelakiso) se autau mai tagata na tutuli ese,", "(he being a descendant of Riplakish) gathered together an army of out– casts,"], ["ma o atu ma tau ma le nuu;", "and went forth and gave battle unto the people;"], ["ma sa oo ina ia maua le pule i luga o aai e tele;", "and he gained power over many cities;"], ["ma sa oo ina matua faigata tele le taua,", "and the war became exceedingly sore,"], ["ma sa tumau mo le tele o tausaga;", "and did last for the space of many years;"], ["ma sa oo ina maua e ia le pule i luga o le laueleele atoa,", "and he did gain  power over all the land,"], ["ma ia faatu ai o ia lava o le tupu i luga oi le laueleele uma.", "and did establish himself king over all the land."]]},
  {num:10,words:[["Ma ina ua uma ona ia faatu o ia lava ma tupu,", "And after that he had established himself king he did ease the burden of the people,"], ["sa ia faamamaina le avega a le nuu, o se mea na lelei ai o ia i le vaaiga a tagata,", "by which he did gain favor in the eyes of the people,"], ["ma sa latou faauuina ai o ia e avea mo o latou tupu.", "and they did anoint him to be their king."]]},
  {num:11,words:[["Ma sa ia faia mea tonu i tagata,", "And he did do justice unto the people,"], ["ae sa ia le faia ia te ia lava, ona o ana faitaaga e tele;", "but not unto himself because of his many whoredoms;"], ["o le mea lea na vavae ese ai o ia mai luma o le Alii.", "wherefore he was cut off from the presence of the Lord."]]},
  {num:12,words:[["Ma sa oo ina atiae e Morianetona aai e tele,", "And it came to pass that Morianton built up many cities,"], ["ma sa oo ina mauoa tele tagata i lalo o lana nofoaiga,", "and the people became exceedingly rich under his reign,"], ["i fale,", "both in buildings,"], ["ma i auro ma ario,", "and in gold and silver,"], ["ma i le faatupuina o le saito,", "and in raising grain,"], ["ma i lafu,", "and in flocks,"], ["ma fagaga,", "and herds,"], ["ma mea faapena sa toefuatai mai ia te i latou.", "and such things which had been restored unto them."]]},
  {num:13,words:[["Ma sa ola Morianetona i tausaga e tele lava,", "And Morianton did live to an exceedingly great age,"], ["ona ia fanauina ai lea o Kimo;", "and then he begat Kim;"], ["ma sa nofo Kimo e sui i lona tamā;", "and Kim did reign in the stead of his father;"], ["ma sa nofotupu o ia mo tausaga e valu,", "and he did reign eight years,"], ["ma sa oti lona tamā. Ma sa oo ina le nofotupu Kimo i le amiotonu,", "and his father died. And it came to pass that Kim did not reign in righteousness,"], ["o le mea lea na le fiafia ai le Alii ia te ia.", "wherefore he was not favored of the Lord."]]},
  {num:14,words:[["Ma sa tulai ae lona uso e fouvale e faasaga ia te ia,", "And his brother did rise up in rebellion against him,"], ["lea na ia aumai ai o ia i le faatagataotaua;", "by which he did bring him into captivity;"], ["ma sa tumau o ia i le faatagataotauaina i ona aso uma;", "and he did remain in captivity all his days;"], ["ma sa ia fanauina atalii ma afafine ao faatagataotauaina;", "and he begat sons and daughters in captivity,"], ["ma i tausaga o lona toeaina lava na ia fanauina ai Levi;", "and in his old age he begat Levi;"], ["ma sa oti o ia.", "and he died."]]},
  {num:15,words:[["Ma sa oo ina auauna Levi i le faatagataotauaina ina ua mavae le oti o lona tamā,", "And it came to pass that Levi did serve in captivity after the death of his father,"], ["mo le va o le fa sefulu ma le lua tausaga. Ma sa ia sii taua e faasaga i le tupu o le laueleele,", "for the space of forty and two years. And he did make war against the king of the land,"], ["lea na ia maua ai mo ia lava le malo.", "by which he did obtain unto himself the kingdom."]]},
  {num:16,words:[["Ma ina ua uma ona ia maua o le malo mo ia sa ia faia mea sa tonu i le silafaga a le Alii;", "And after he had obtained unto himself the kingdom he did that which was right in the sight of the Lord;"], ["ma sa manuia tagata i luga o le laueleele;", "and the people did prosper in the land;"], ["ma sa ola o ia i se olaga umi lava,", "and he did live to a good old age,"], ["ma ia fanauina ni atalii ma afafine;", "and begat sons and daughters;"], ["ma sa fanauina foi e ia Koruma,", "and he also begat Corom,"], ["o le na ia faauuina e avea ma tupu e sui ia te ia.", "whom he anointed king in his stead."]]},
  {num:17,words:[["Ma sa oo ina faia e Koruma mea sa lelei i le silafaga a le Alii i ona aso uma;", "And it came to pass that Corom did that which was good in the sight of the Lord all his days;"], ["ma sa ia fanauina atalii ma afafine e toatele;", "and he begat many sons and daughters;"], ["ma ina ua mavae ona ia vaai i aso e tele sa oti o ia,", "and after he had seen many days he did pass away,"], ["e pei lava o tagata uma o le lalolagi;", "even like unto the rest of the earth;"], ["ma ua nofotupu Kiso e sui ia te ia.", "and Kish reigned in his stead."]]},
  {num:18,words:[["Ma sa oo ina maliu foi Kiso,", "And it came to pass that Kish passed away also,"], ["ma ua nofo Lipi e sui ia te ia.", "and Lib reigned in his stead."]]},
  {num:19,words:[["Ma sa oo foi ina faia e Lipi mea sa lelei i le silafaga a le Alii. Ma o aso o Lipi na faaumatia ai gata uogo. O le mea lea na latou o atu ai i le laueleele i saute,", "And it came to pass that Lib also did that which was good in the sight of the Lord. And in the days of Lib the poisonous serpents were destroyed. Wherefore they did go into the land southward,"], ["e saili meaai mo tagata o le laueleele,", "to hunt food for the people of the land,"], ["ona sa tumu le laueleele i manu o le vao. Ma sa avea foi Lipi lava ia ma tulimanu lelei tele.", "for the land was covered with animals of the forest. And Lib also himself became a great hunter."]]},
  {num:20,words:[["Ma sa latou atiina ae se aai tele i tafatafa o le ua vaitiiti o le laueleele,", "And they built a great city by the narrow neck of land,"], ["i tafatafa o le mea e vaelua ai e le sami le laueleele.", "by the place where the sea divides the land."]]},
  {num:21,words:[["Ma sa latou faasaosaoina le laueleele i saute e avea ma vao,", "And they did preserve the land southward for a wilderness,"], ["e tuli ai manu. Ma sa ufitia le laueleele atoa i matu i tagata.", "to get game. And the whole face of the land northward was covered with inhabitants."]]},
  {num:22,words:[["Ma sa latou toaaga tele,", "And they were exceedingly industrious,"], ["ma sa latou faatau mai ma faatau atu ma fefaatauai ma le tasi,", "and they did buy and sell and traffic one with another,"], ["ina ia latou maua le oa.", "that they might get gain."]]},
  {num:23,words:[["Ma sa latou faia galuega i ituaiga o oa eseese uma,", "And they did work in all manner of ore,"], ["ma sa latou faia auro,", "and they did make gold,"], ["ma ario,", "and silver,"], ["ma uamea ,", "and iron,"], ["ma apamemea,", "and brass,"], ["ma metala uiga eseese uma;", "and all manner of metals;"], ["ma sa latou elia i fafo mai le eleele; o le mea lea,", "and they did dig it out of the earth;"], ["na latou lafo ai i luga ni faaputuga tetele o le eleele ina ia maua ai oa,", "wherefore they did cast up mighty heaps of earth to get ore,"], ["auro,", "of gold,"], ["ma ario,", "and of silver,"], ["ma le uamea,", "and of iron,"], ["ma apamemea.", "and of copper."], ["Ma sa latou faia mea matagofie uiga eseese uma.", "And they did work all manner of fine work."]]},
  {num:24,words:[["Ma sa latou maua silika,", "And they did have silks,"], ["ma ie lino miloa lelei;", "and fine– twined linen;"], ["ma sa latou faia ie ituaiga eseese uma,", "and they did work all manner of cloth,"], ["ina ia mafai ona latou faaoofuina i latou mai lo latou le lavalava.", "that they might clothe themselves from their nakedness."]]},
  {num:25,words:[["Ma sa latou faia meafaigaluega o ituaiga eseese uma e galueaiina ai le eleele,", "And they did make all manner of tools to till the earth,"], ["e sua ma toto ai le eleele,", "both to plow and to sow,"], ["e selesele ma vele ai,", "to reap and to hoe,"], ["ma sasa ai le saito.", "and also to thrash."]]},
  {num:26,words:[["Ma sa latou faia meafaigaluega o ituaiga eseese uma sa latou faafaigaluega ai a latou manu.", "And they did make all manner of tools with which they did work their beasts."]]},
  {num:27,words:[["Ma sa latou faia auupega o ituaiga eseese uma o taua. Ma sa latou faia ituaiga uma o galuega taulima uiga eseese.", "And they did make all manner of weapons of war. And they did work all manner of work of exceedingly curious workmanship."]]},
  {num:28,words:[["Ma e leai se nuu sa faamanuiaina tele nai lo i latou,", "And never could be a people more blessed than were they,"], ["ma sili atu ona faatamaoaigaina tele e le aao o le Alii. Ma sa latou i ai i se laueleele sa silisili ona lelei i luga o laueleele uma,", "and more prospered by the hand of the Lord. And they were in a land that was choice above all lands,"], ["aua sa fetalai mai ai le Alii.", "for the Lord had spoken it."]]},
  {num:29,words:[["Ma sa oo ina ola Lipi i tausaga e tele,", "And it came to pass that Lib did live many years,"], ["ma ia fanauina ni atalii ma afafine;", "and begat sons and daughters;"], ["ma sa ia fanauina foi Heatoma.", "and he also begat Hearthom."]]},
  {num:30,words:[["Ma sa oo ina nofo Heatoma e sui i lona tamā. Ma ina ua lua sefulu ma le fa tausaga o nofotupu Heatoma,", "And it came to pass that Hearthom reigned in the stead of his father. And when Hearthom had reigned twenty and four years,"], ["faauta,", "behold,"], ["sa aveesea le malo mai ia te ia. Ma sa auauna o ia i tausaga e tele i le faatagataotauaina,", "the kingdom was taken away from him. And he served many years in captivity,"], ["ioe,", "yea,"], ["i ona aso uma lava na totoe.", "even all the remainder of his days."]]},
  {num:31,words:[["Ma sa ia fanauina Hetu,", "And he begat Heth,"], ["ma sa nofo Hetu i le faatagataotaua i ona aso uma. Ma sa fanauina e Hetu Arona,", "and Heth lived in captivity all his days. And Heth begat Aaron,"], ["ma sa nofo Arona i le faatagataotaua i ona aso uma;", "and Aaron dwelt in captivity all his days;"], ["ma sa ia fanauina Aminikata,", "and he begat Amnigaddah,"], ["ma sa nofo foi Aminikata i le faatagataotaua i ona aso uma;", "and Amnigaddah also dwelt in captivity all his days;"], ["ma sa ia fanauina Korianetumu,", "and he begat Coriantum,"], ["ma sa nofo Korianetumu i le faatagataotaua i ona aso uma;", "and Coriantum dwelt in captivity all his days;"], ["ma sa ia fanauina Komi.", "and he begat Com."]]},
  {num:32,words:[["Ma sa oo ina taia ese e Komi le afa o le malo. Ma sa nofotupu o ia i luga o le afa o le malo i tausaga e fa sefulu ma le lua;", "And it came to pass that Com drew away the half of the kingdom. And he reigned over the half of the kingdom forty and two years;"], ["ma sa alu atu o ia e faasaga tau i le tupu,", "and he went to battle against the king,"], ["o Aminikata,", "Amgid,"], ["ma sa tau i laua mo le va o tausaga e tele,", "and they fought for the space of many years,"], ["i le taimi lea na maua ai e Komi le pule i luga o Aminikata,", "during which time Com gained power over Amgid,"], ["ma maua ai e ia le pule i luga o le vaega na totoe o le malo.", "and obtained power over the remainder of the kingdom."]]},
  {num:33,words:[["Ma o aso o Komi na amata ona i ai o faomea i le laueleele;", "And in the days of Com there began to be robbers in the land;"], ["ma sa latou mulimuli i fuafuaga tuai,", "and they adopted the old plans,"], ["ma latou faia tautoga e mulimuli i le ala a tagata anamua,", "and administered oaths after the manner  of the ancients,"], ["ma toe saili e faaumatia le malo.", "and sought again to destroy the kingdom."]]},
  {num:34,words:[["O lenei sa tau tele Komi e faasaga ia te i latou;", "Now Com did fight against them much;"], ["e ui i lea,", "nevertheless,"], ["sa le manumalo o ia e faasaga ia te i latou.", "he did not prevail against them."]]},
];
renderVerseSet(et_ch_10_Verses, 'et-ch10-verses');

var et_ch_11_Verses = [
  {num:1,words:[["Ma sa o mai foi i aso o Komi perofeta e toatele,", "And there came also in the days of Com many prophets,"], ["ma valoia le faaumatiaina o lena nuu tele vagana ai ua latou salamo,", "and prophesied of the destruction of that great people except they should repent,"], ["ma liliu mai i le Alii,", "and turn unto the Lord,"], ["ma tuu lo latou fasioti tagata ma le amioleaga.", "and forsake their murders and wickedness."]]},
  {num:2,words:[["Ma sa oo ina teena e tagata perofeta,", "And it came to pass that the prophets were rejected by the people,"], ["ma sa latou sosola atu ia Komi mo se puipuiga,", "and they fled unto Com for protection,"], ["ona sa saili tagata e faaumatia i latou.", "for the people sought to destroy them."]]},
  {num:3,words:[["Ma sa latou vavalo atu ia Komi mea e tele;", "And they prophesied unto Com many things;"], ["ma sa faamanuiaina o ia i ona aso uma na totoe.", "and he was blessed in all the remainder of his days."]]},
  {num:4,words:[["Ma sa ola o ia i se soifuaga umi,", "And he lived to a good old age,"], ["ma ia fanauina Sepeloma;", "and begat Shiblom;"], ["ma sa nofo Sepeloma e sui ia te ia. Ma sa fouvale le uso o Sepeloma ia te ia,", "and Shiblom reigned in his stead. And the brother of Shiblom rebelled against him,"], ["ma sa amata ona i ai o se taua tele lava i le laueleele atoa.", "and there began to be an exceedingly great war in all the land."]]},
  {num:5,words:[["Ma sa oo ina faatonu e le uso o Sepeloma ia fasiotia perofeta uma o e na vavalo e uiga i le faaumatiaina o le nuu;", "And it came to pass that the brother of Shiblom caused that all the prophets who prophesied of the destruction of the people should be put to death;"]]},
  {num:6,words:[["Ma sa i ai se malaia tele i le laueleele atoa,", "And there was great calamity in all the land,"], ["ona sa latou molimau atu e i ai se fetuu tele o le a oo mai i luga o le laueleele,", "for they had testified that a great curse should come upon the land,"], ["ma i luga foi o tagata,", "and also upon the people,"], ["ma o le a i ai se faaumatiaga tele i totonu o i latou,", "and that there should be a great destruction among them,"], ["o se ituaiga e lei oo mai lava i luga o le lalolagi,", "such an one as never had been upon the face of the earth,"], ["ma o le a avea o latou ivi e pei o ni faaputuga eleele i luga o le laueleele vagana ai ua latou salamo ia latou amioleaga.", "and their bones should become as heaps of earth upon the face of the land except they should repent of their wickedness."]]},
  {num:7,words:[["Ma sa latou le faalogo i le siufofoga o le Alii,", "And they hearkened not unto the voice of the Lord,"], ["ona o a latou faapotopotoga amioleaga;", "because of their wicked combinations;"], ["o le mea lea na amata ai ona i ai o taua ma finauga i luga o le laueleele atoa,", "wherefore,"], ["ma oge foi e tele ma faamai,", "there began to be wars and conten– tions in all the land, and also many famines and pestilences,"], ["sa oo ina oo mai se faafanoga tele,", "insomuch that there was a great destruction,"], ["o se ituaiga e lei vaaia lava i luga o le lalolagi;", "such an one as never had been known upon the face of the earth;"], ["ma o nei mea uma na oo mai i aso o Sepeloma.", "and all this came to pass in the days of Shiblom."]]},
  {num:8,words:[["Ma sa amata ona salamo tagata i lo latou amioletonu; ma o le tulaga na oo i ai lo latou salamo ai,", "And the people began to repent of their iniquity;"], ["na alofa mutimutivale ai le Alii ia te i latou.", "and inasmuch as they did the Lord did have mercy on them."]]},
  {num:9,words:[["Ma sa oo ina fasiotia Sepeloma,", "And it came to pass that Shiblom was slain,"], ["ma sa aumai Setu i le faatagataotaua,", "and Seth was brought into captivity,"], ["ma sa nofo i le faatagataotaua i ona aso uma.", "and did dwell in captivity all his days."]]},
  {num:10,words:[["Ma sa oo ina maua e Asa,", "And it came to pass that Ahah,"], ["lona atalii,", "his son,"], ["le malo;", "did obtain the kingdom;"], ["ma sa nofotupu o ia i luga o le nuu i ona aso uma. Ma sa ia faia amioletonu uiga eseese uma i ona aso,", "and he did reign over the people all his days. And he did do all manner of iniquity in his days,"], ["ia na tupu ai mai ia te ia le faamasaa toto tele;", "by which he did cause the shedding of much blood;"], ["ma sa itiiti ona aso.", "and few were his days."]]},
  {num:11,words:[["Ma o Etema,", "And Ethem,"], ["ona o ia o se e tupuga mai ia Asa,", "being a descendant of Ahah,"], ["sa ia mauaina le malo;", "did obtain the kingdom;"], ["ma sa ia faia foi mea amioleaga i ona aso.", "and he also did do that which was wicked in his days."]]},
  {num:12,words:[["Ma sa oo ina o mai i aso o Etema,", "And it came to pass that in the days of Ethem there came many prophets,"], ["perofeta e toatele,", "and prophesied again unto the people;"], ["ma toe vavalo atu i tagata;", "yea,"], ["ioe sa latou vavalo atu o le a faaumatia ese atoa i latou e le Alii mai luga o le lalolagi vagana ai ua latou salamo ia latou amioletonu.", "they did prophesy that the Lord would utterly destroy them from off the face of the earth except they repented of their iniquities."]]},
  {num:13,words:[["Ma sa oo ina faamaaa e tagata o latou loto,", "And it came to pass that the people hardened their hearts,"], ["ma latou le fia faalogo ia latou upu;", "and would not hearken unto their words;"], ["ma sa faanoanoa perofeta ma o ese atu mai totonu o le nuu.", "and the prophets mourned and withdrew from among the people."]]},
  {num:14,words:[["Ma sa oo ina faia e Etema faamasinoga i le amioleaga i ona aso uma;", "And it came to pass that Ethem did execute judgment in wickedness all his days;"], ["ma sa ia fanauina Morona. Ma sa oo ina nofo Morona e sui ia te ia;", "and he begat Moron. And it came to pass that Moron did reign in his stead;"], ["ma sa faia e Morona mea sa amioleaga i luma o le Alii.", "and Moron did that which was wicked before the Lord."]]},
  {num:15,words:[["Ma sa oo ina tulai mai se fouvalega mai totonu o tagata,", "And it came to pass that there arose a rebellion among the people,"], ["ona o lena faapotopotoga faalilolilo lea sa faatuina ina ia maua ai le pule ma le oa;", "because of that secret combination which was built up to get power and gain;"], ["ma sa tulai mai totonu o i latou se tagata malosi i le amioletonu,", "and there arose a mighty man among them in iniquity,"], ["ma ua tau ma Morona,", "and gave battle unto Moron,"], ["lea na ia faatoilaloina ai le afa o le malo;", "in which he did overthrow the half of the kingdom;"], ["ma sa ia taofia le afa o le malo mo tausaga e tele.", "and he did maintain the half of the kingdom for many years."]]},
  {num:16,words:[["Ma sa oo ina faatoilalo o ia e Morona,", "And it came to pass that Moron did over– throw him,"], ["ma ia toe maua le malo.", "and did obtain the kingdom again."]]},
  {num:17,words:[["Ma sa oo ina tulai mai se isi tagata malosi;", "And it came to pass that there arose another mighty man;"], ["ma o ia o se e tupuga mai le uso o Iareto.", "and he was a descendant of the brother of Jared."]]},
  {num:18,words:[["Ma sa oo ina ia faatoilaloina Morona ma mauaina le malo;", "And it came to pass that he did overthrow Moron and obtain the kingdom;"], ["o le mea lea na nofo ai Morona i le faatagataotaua i ona aso uma na totoe;", "wherefore, Moron dwelt in captivity all the remainder of his days;"], ["ma sa ia fanauina Korianetoa.", "and he begat Coriantor."]]},
  {num:19,words:[["Ma sa oo ina nofo Korianetoa i le faatagataotaua i ona aso uma.", "And it came to pass that Coriantor dwelt in captivity all his days."]]},
  {num:20,words:[["Ma o ona po o Korianetoa na o mai ai foi perofeta e toatele,", "And in the days of Coriantor there also came many prophets,"], ["ma vavalo mai i mea tetele ma ofoofogia,", "and prophesied of great and marvelous things,"], ["ma alaga atu le salamo i tagata,", "and cried repentance unto the people,"], ["ma vagana ai ua latou salamo o le a faia e le Alii le Atua le faamasinoga e faasaga ia te i latou e oo ina faaumatia atoa ai i latou.", "and except they should repent the Lord God would execute judgment against them to their utter destruction;"]]},
  {num:21,words:[["Ma o le a auina mai pe aumai e le Alii le Atua se tasi nuu e umia le laueleele,", "And that the Lord God would send or bring forth another people to possess the land,"], ["i lona mana,", "by his power,"], ["e pei o le ala na ia aumai ai o latou tamā.", "after the manner by which he brought their fathers."]]},
  {num:22,words:[["Ma sa latou teena upu uma a perofeta,", "And they did reject all the words of the prophets,"], ["ona o la latou sosaiete faalilolilo ma mea inosia amioleaga.", "because of their secret society and wicked abominations."]]},
  {num:23,words:[["Ma sa oo ina fanauina e Korianetoa Eteru ,", "And it came to pass that Coriantor begat Ether,"], ["ma sa oti o ia,", "and he died,"], ["ina o nofo o ia i le faatagataotaua i ona aso uma.", "having dwelt in captivity all his days."]]},
];
renderVerseSet(et_ch_11_Verses, 'et-ch11-verses');

var et_ch_12_Verses = [
  {num:1,words:[["Ma sa oo ina sa i ai aso o Eteru i ona po o Korianetuma;", "And it came to pass that the days of Ether were in the days of Coriantumr;"], ["ma o Korianetuma sa tupu i le laueleele atoa.", "and Coriantumr was king over all the land."]]},
  {num:2,words:[["Ma sa avea Eteru o se perofeta a le Alii;", "And Ether was a prophet of the Lord;"], ["o le mea lea na alu atu ai Eteru i ona po o Korianetuma,", "wherefore Ether came forth in the days of Coriantumr,"], ["ma amata ona vavalo atu i tagata,", "and began to prophesy unto the  people,"], ["aua sa le mafai ona vaosia o ia ona o le Agaga o le Alii lea sa i totonu ia te ia.", "for he could not be restrained because of the Spirit of the Lord which was in him."]]},
  {num:3,words:[["Aua sa ia alaga atu mai le taeao,", "For he did cry from the morning,"], ["seia oo lava i le alu ifo i lalo o le la,", "even until the going down of the sun,"], ["ua apoapoai atu i tagata ia talitonu i le Atua ia salamo nei faaumatia i latou,", "exhorting the people to believe in God unto repentance lest they should be destroyed,"], ["ma fai atu ia te i latou o le faatuatua e faataunuu ai mea uma—", "saying unto them that by faith all things are fulfilled—"]]},
  {num:4,words:[["O le mea lea,", "Wherefore,"], ["soo se tasi e talitonu i le Atua e mafai moni lava ona faamoemoe mo se lalolagi sili atu ona lelei,", "whoso believeth in God might with surety hope for a better world,"], ["ioe,", "yea,"], ["se nofoaga lava i le aao taumatau o le Atua,", "even a place at the right hand of God,"], ["o le faamoemoe lea e sau mai le faatuatua,", "which hope cometh of faith,"], ["e fai ma taula i agaga o tagata,", "maketh an anchor to the souls of men,"], ["lea o le a latou mautinoa ma mausali ai,", "which would make them sure and steadfast,"], ["ma faatumulia ai pea i galuega lelei e le aunoa,", "always abounding in good works,"], ["ma taitaiina ai e viia le Atua.", "being led to glorify God."]]},
  {num:5,words:[["Ma sa oo ina perofeta atu e Eteru mea tetele ma ofoofogia i tagata,", "And it came to pass that Ether did prophesy great and marvelous things unto the people,"], ["ia sa latou le talitonu i ai,", "which they did not believe,"], ["ona sa latou le vaai atu i ai.", "because they saw them not."]]},
  {num:6,words:[["Ma o lenei,", "And now,"], ["o au,", "I,"], ["o Moronae,", "Moroni,"], ["ou te fia tautala atu teisi e uiga i nei mea;", "would speak somewhat concerning these things;"], ["ou te fia faaali atu i le lalolagi o le faatuatua o mea ia ua faamoemoe i ai ae ua le vaaia;", "I would show unto the world that faith is things which are hoped for and not seen;"], ["o le mea lea,", "wherefore,"], ["aua tou te masalosalo ona ua outou le vaaia,", "dispute not because ye see not,"], ["aua tou te le maua se molimau seia uma ona tofotofoina o lo outou faatuatua.", "for ye receive no witness until after the trial of your faith."]]},
  {num:7,words:[["Ona o le faatuatua na faaali mai ai e Keriso o ia lava i o tatou tamā,", "For it was by faith that Christ showed himself unto our fathers,"], ["ina ua uma ona toetu mai o ia mai le oti;", "after he had risen from the dead;"], ["ma sa ia le faaali mai o ia lava ia te i latou seia mavae ona latou faatuatua muamua ia te ia;", "and he showed not himself unto them until after they had faith in him;"], ["o le mea lea,", "wherefore,"], ["sa tatau ai ona i ai i ni isi le faatutua ia te ia,", "it must needs be that some had faith in him,"], ["ona sa ia le faaalia atu o ia lava i le lalolagi.", "for he showed himself not unto the world."]]},
  {num:8,words:[["Ae ona o le faatuatua o tagata o lea na ia faaali mai ai o ia lava i le lalolagi,", "But because of the faith of men he has shown himself unto the world,"], ["ma faamamaluina le suafa o le Tamā,", "and glorified the name of the Father,"], ["ma saunia se ala e mafai ai e isi ona tofusia i le meaalofa faalelagi,", "and prepared a way that thereby others might be partakers of the heavenly gift,"], ["ina ia mafai ona latou faamoemoe mo mea ia latou te lei vaai i ai.", "that they might hope for those things which they have not seen."]]},
  {num:9,words:[["O le mea lea,", "Wherefore,"], ["ia mafai ai foi ona outou maua o le faamoemoe,", "ye may also have hope,"], ["ma avea ma e e mauaina le meaalofa,", "and be partakers of the gift,"], ["pe afai e nao na outou faatuatua.", "if ye will but have faith."]]},
  {num:10,words:[["Faauta, o le faatuatua na valaauina ai i latou anamua, i le faatulagaga paia a le Atua.", "Behold it was by faith that they of old were called after the holy order of God."]]},
  {num:11,words:[["O le mea lea,", "Wherefore,"], ["o le faatuatua na tuuina mai ai le tulafono a Mose. Ae ua saunia e le Atua e ala i le meaalofa a lona Alo se ala e silisili ona lelei;", "by faith was the law of Moses given. But in the gift of his Son hath God prepared a more excellent way;"], ["ma o le faatuatua ua faataunuuina ai.", "and it is by faith that it hath been fulfilled."]]},
  {num:12,words:[["Aua afai e leai se faatuatua i totonu o le fanauga a tagata e le mafai e le Atua ona faia se vavega i totonu o i latou;", "For if there be no faith among the children of men God can do no miracle among them;"], ["o le mea lea,", "wherefore,"], ["na te le faaali mai o ia lava seia mavae ona latou faatuatua muamua.", "he showed not himself until after their faith."]]},
  {num:13,words:[["Faauta,", "Behold,"], ["o le faatuatua o Alema ma Amoleka na mafua ai ona solo o le falepuipui i le eleele.", "it was the faith of Alma and Amulek that caused the prison to tumble to the earth."]]},
  {num:14,words:[["Faauta,", "Behold,"], ["o le faatuatua o Nifae ma Liae na faia ai le liuga i luga o sa Lamanā,", "it was the faith of Nephi and Lehi that wrought the change upon the Lamanites,"], ["na papatisoina ai i latou i le afi ma le Agaga Paia.", "that they were baptized with fire and with the Holy Ghost."]]},
  {num:15,words:[["Faauta,", "Behold,"], ["o le faatuatua o Amona ma ona uso na faia ai se vavega tele lava i totonu o sa Lamanā.", "it was the faith of Ammon and his brethren which wrought so great a miracle among the Lamanites."]]},
  {num:16,words:[["Ioe,", "Yea,"], ["ma e oo ia i latou uma o e na faia vavega sa latou faia i le faatuatua ,", "and even all they who wrought miracles wrought them by faith,"], ["e oo ia i latou o e na muamua mai ia Keriso ma i latou foi o e na mulimuli mai ia te ia.", "even those who were before Christ and also those who were after."]]},
  {num:17,words:[["Ma o le faatuatua na maua ai e soo e toatolu se folafolaga o le a le tofo i latou i le oti;", "And it was by faith that the three disciples obtained a promise that they should not taste of death;"], ["ma sa le maua e i latou le folafolaga seia mavae ona latou faatuatua muamua.", "and they obtained not the promise until after their faith."]]},
  {num:18,words:[["Ma pe sa i ai se taimi na faia ai e se tasi ni vavega seia mavae ona latou faatuatua muamua;", "And neither at any time hath any wrought miracles until after their faith;"], ["o le mea lea sa muamua ona latou talitonu i le Alo o le Atua.", "wherefore they first believed in the Son of God."]]},
  {num:19,words:[["Ma sa i ai le toatele o e sa matua malosi tele lava lo latou faatuatua,", "And there were many whose faith was so exceedingly strong,"], ["i le taimi lava ae lei afio mai Keriso,", "even before Christ came,"], ["o e sa le mafai ona taofia mai totonu o le veli ,", "who could not be kept from within the veil,"], ["ae sa latou vaai moni lava ma o latou lava mata mea ia sa latou vaai i ai ma se mata o le faatuatua,", "but truly saw with their eyes the things which they had beheld with an eye of faith,"], ["ma sa latou fiafia.", "and they were glad."]]},
  {num:20,words:[["Faauta foi,", "And behold,"], ["ua tatou vaaia i lenei talafaamaumau,", "we have seen in this record that one of these was the brother of Jared;"], ["o se tasi o i latou ia o le uso lea o Iareto; ona sa matua tele lava lona faatuatua i le Atua,", "for so great was his faith in God,"], ["ina ua tuu mai e le Atua lona tamatamaiaao sa le mafai ona ia natiaina mai le vaai a le uso o Iareto,", "that when God put forth his finger he could not hide it from the sight of the brother of Jared,"], ["ona o lana fetalaiga na ia fetalai mai ia te ia,", "because of his word which he had spoken unto him,"], ["o le fetalaiga lea na ia maua i le faatuatua.", "which word he had obtained by faith."]]},
  {num:21,words:[["Ma ina ua uma ona vaai o le uso o Iareto i le tamatamaiaao o le Alii,", "And after the brother of Jared had beheld the finger of the Lord,"], ["ona o le folafolaga lea na maua e le uso o Iareto i le faatuatua,", "because of the promise which the brother of Jared had obtained by faith,"], ["sa le mafai e le Alii ona taofia se mea mai lana vaai;", "the Lord could not withhold anything from his sight;"], ["o le mea lea na ia faaali mai ai ia te ia mea uma,", "wherefore he showed him all things,"], ["ona sa le toe mafai ona taofia o ia i fafo o le veli .", "for he could no longer be kept without the veil."]]},
  {num:22,words:[["Ma o le faatuatua na maua ai e ou tamā le folafolaga o le a oo atu nei mea i o latou uso e ala i Nuuese;", "And it is by faith that my fathers have obtained the promise that these things should come unto their brethren through the Gentiles;"], ["o le mea lea ua poloaiina ai au e le Alii,", "therefore the Lord hath commanded me,"], ["ioe,", "yea,"], ["o Iesu Keriso lava lea.", "even Jesus Christ."]]},
  {num:23,words:[["Ma sa ou fai atu ia te ia:", "And I said unto him:"], ["Le Alii e,", "Lord,"], ["o le a faatauemu Nuuese i nei mea,", "the Gentiles will mock at these things,"], ["ona o lo matou vaivai i le tusitusi;", "because of our weakness in writing;"], ["aua le Alii e, ua e faamalosia i matou i le upu ona o le faatuatua,", "for Lord thou hast made us mighty in word by faith,"], ["ae ua e le faamalolosia i matou i le tusitusi;", "but thou hast not made us mighty in writing;"], ["ona ua e faia nei tagata uma ina ia mafai ona latou tautala tele,", "for thou hast made all this people that they could speak much,"], ["ona o le Agaga Paia lea na e tuuina mai ia te i latou;", "because of the Holy Ghost which thou hast given them;"]]},
  {num:24,words:[["Ma ua e faia i matou tau ina ia mafai ona matou tusitusi laitiiti,", "And thou hast made us that we could write but little,"], ["ona o le vasivasi o o matou lima. Faauta,", "because of the awkwardness of our hands. Behold,"], ["ua e le faia i matou ina ia matou malolosi i le tusitusi e pei o le uso o Iareto,", "thou hast not made us mighty in writing like unto the brother of Jared,"], ["ona ua e faia o ia ina ia malolosi mea ua ia tusia e pei lava o oe,", "for thou madest him that the things which he wrote were mighty even as thou art,"], ["seia oo ina lofituina ai le tagata e faitauina i latou.", "unto the overpowering of man to read them."]]},
  {num:25,words:[["Ua e faia foi a matou upu ia mamana ma malolosi,", "Thou hast also made our words powerful and great,"], ["ua oo lava ina le mafai ona matou tusia i latou;", "even that we cannot write them;"], ["o le mea lea a matou tusitusi ua matou vaai i lo matou vaivai,", "wherefore, when we write we behold our weakness,"], ["ma feseseai ona o le tuuga o a matou upu;", "and stumble because of the placing of our words;"], ["ma ou te fefe nei faatauemu Nuuese ia matou upu.", "and I fear lest the Gentiles shall mock at our words."]]},
  {num:26,words:[["Ma ina ua uma ona ou fai atu o nei upu,", "And when I had said this,"], ["sa fetalai mai le Alii ia te au,", "the Lord spake unto me,"], ["ua fofoga mai:", "saying:"], ["E faatauemu e ua valelea,", "Fools mock,"], ["ae o le a faanoanoa i latou;", "but they shall mourn;"], ["ma ua lava lou alofa tunoa mo e e agamalu,", "and my grace is sufficient for the meek,"], ["o le a latou le faaaoga ai lo outou vaivai;", "that they shall take no advantage of your weakness;"]]},
  {num:27,words:[["Ma afai e o mai tagata ia te au o le a ou faaali atu ia te i latou o latou vaivaiga . Ou te avatu i tagata ia vaivaiga ina ia faalotomaualalalo ai i latou;", "And if men come unto me I will show unto them their weakness. I give unto men weakness that they may be humble;"], ["ma ua lava lou alofa tunoa mo tagata uma o e e latou te faalotomaualalaloina i latou lava i ou luma;", "and my grace is sufficient for all men that humble themselves before me;"], ["aua afai latou te faalotomaualalaloina i latou lava i ou luma,", "for if they humble themselves before me,"], ["ma faatuatua mai ia te au,", "and have faith in me,"], ["ona ou faia lea o mea vaivai ia avea ma mea malolosi ia te i latou.", "then will I make weak things become strong unto them."]]},
  {num:28,words:[["Faauta, o le a ou faaali atu i Nuuese o latou vaivaiga,", "Behold,"], ["ma o le a ou faaali atu ia te i latou o le faatuatua ,", "I will show unto the Gentiles their weakness and I will show unto them that faith,"], ["faamoemoe, ma le alofa mama e aumai ai i latou ia te au—o le puna o le amiotonu uma.", "hope and charity bringeth unto me—the fountain of all righteousness."]]},
  {num:29,words:[["Ma o au,", "And I,"], ["o Moronae,", "Moroni,"], ["ina ua uma ona ou faalogoina o nei upu,", "having heard these words,"], ["sa faamafanafanaina au,", "was comforted,"], ["ma ou fai atu:", "and said:"], ["Le Alii e,", "O Lord,"], ["ia faia lou finagalo amiotonu,", "thy righteous will be done,"], ["aua ua ou iloa e te galue i le fanauga a tagata e tusa ma lo latou faatuatua;", "for I know that thou workest unto the children of men according to their faith;"]]},
  {num:30,words:[["Aua na fai atu le uso o Iareto i le mauga o Serima,", "For the brother of Jared said unto the mountain Zerin,"], ["Alu ese—ma sa alu ese lava. Ma a na fai e le ia te ia le faatuatua po ua le alu ese;", "Remove—and it was removed. And if he had not had faith it would not have moved;"], ["o le mea lea e te faia ai mea pe a mavae ona i ai muamua i tagata le faatuatua.", "wherefore thou workest after men have faith."]]},
  {num:31,words:[["Aua sa faapea ona e faaali mai o oe lava i ou soo;", "For thus didst thou manifest thyself unto thy disciples;"], ["aua ina ua uma ona i ai muamua ia te i latou le faatuatua ,", "for after they had faith,"], ["ma latou tautatala i lou suafa,", "and did speak in thy name,"], ["sa e faaali mai oe lava ia te i latou i le mana tele.", "thou didst show thyself unto them in great power."]]},
  {num:32,words:[["Ma ou te manatua foi na e fetalai mai ua uma ona e saunia se fale mo tagata,", "And I also remember that thou hast said that thou hast prepared a house for man,"], ["ioe,", "yea,"], ["i totonu lava o maota o lou Tamā,", "even among the mansions of thy Father,"], ["lea e mafai ai e le tagata ona maua o le faamoemoe lelei silisili atu;", "in which man might have a more excellent hope;"], ["o le mea lea e ao i le tagata ona faamoemoe i le tagata;", "where– fore man must hope,"], ["a leai e le mafai ona ia maua o se tofi i le nofoaga ua e saunia.", "or he cannot receive an inheritance in the place which thou hast prepared."]]},
  {num:33,words:[["O lenei foi,", "And again,"], ["ou te manatua na e fetalai mai ua e alofa i le lalolagi,", "I remember that thou hast said that thou hast loved the world,"], ["e oo lava i le tuuina i lalo o lou soifua mo le lalolagi,", "even unto the laying down of thy life for the world,"], ["ina ia mafai ona e toe aveina e te saunia ai se nofoaga mo le fanauga a tagata.", "that thou mightest take it again to prepare a place for the children of men."]]},
  {num:34,words:[["Ma o lenei ua ou iloa o lenei alofa ua ia te oe mo le fanauga a tagata o le alofa mama lea;", "And now I know that this love which thou hast had for the children of men is charity;"], ["o le mea lea,", "wherefore,"], ["vagana ai ua i ai i tagata le alofa mama e le mafai ona latou mautofi i lena nofoaga ua e saunia i maota o lou Tamā.", "except men shall have charity they cannot inherit that place which thou hast prepared in the mansions of thy Father."]]},
  {num:35,words:[["O le mea lea,", "Wherefore,"], ["ua ou iloa ai i lenei mea ua e fetalai mai ai,", "I know by this thing which thou hast said,"], ["e faapea afai e le i ai i Nuuese le alofa mama,", "that if the Gentiles have not charity,"], ["ona o o matou vaivaiga,", "because of our weakness,"], ["o le a e tofotofoina i latou,", "that thou wilt prove them,"], ["ma aveese la latou taleni ,", "and take away their talent,"], ["ioe,", "yea,"], ["o mea lava ia ua latou maua,", "even that which they have received,"], ["ma avatu ia te i latou o e o le a latou maua atili.", "and give unto them who shall have more abundantly."]]},
  {num:36,words:[["Ma sa oo ina ou tatalo atu i le Alii ia ona avatu i Nuuese le alofa tunoa,", "And it came to pass that I prayed unto the Lord that he would give unto the Gentiles grace,"], ["ina ia latou maua le alofa mama.", "that they might have charity."]]},
  {num:37,words:[["Ma sa oo ina fetalai mai le Alii ia te au:", "And it came to pass that the Lord said unto me:"], ["Afai e le i ai ia i latou le alofa mama e le afaina i lea mea ia te oe,", "If they have not charity it mattereth not unto thee,"], ["sa e faamaoni;", "thou hast been faithful;"], ["o le mea lea,", "wherefore,"], ["o le a faamamaina ou ofu. Ma ona ua e vaai i lou vaivai o le a faamalosia oe,", "thy garments shall be made clean. And because thou hast seen thy weakness thou shalt be made strong,"], ["e oo lava i le nofo i lalo i le nofoaga ua ou saunia i maota o lo'u Tamā.", "even unto the sitting down in the place which I have prepared in the mansions of my Father."]]},
  {num:38,words:[["Ma o lenei o au,", "And now I,"], ["o Moronae,", "Moroni,"], ["ou te faatofa atu i Nuuese,", "bid farewell unto the Gentiles,"], ["ioe,", "yea,"], ["ma i ou uso foi o e ua ou alofa i ai,", "and also unto my brethren whom I love,"], ["seia oo ina tatou feiloai i luma o le nofoa-faamasino o Keriso,", "until we shall meet before the judgment– seat of Christ,"], ["lea o le a iloa ai e tagata uma ua le pisia ou 'ofu i o outou toto.", "where all men shall know that my garments are not spotted with your blood."]]},
  {num:39,words:[["Ma ona outou iloa ai lea sa ou vaai ia Iesu,", "And then shall ye know that I have seen Jesus,"], ["ma sa ia fetalai mai ia te au faafesagai lava,", "and that he hath talked with me face to face,"], ["ma sa ia tau mai ia te au i upu faamaulalo manino,", "and that he told me in plain humility,"], ["e pei lava ona tau atu e se tagata i se tasi tagata i lau lava gagana,", "even as a man telleth another in mine own language,"], ["e uiga i nei mea;", "concerning these things;"]]},
  {num:40,words:[["Ma ua nao nai mea itiiti ua ou tusia,", "And only a few have I written,"], ["ona o lou vaivai i le tusitusi.", "because of my weakness in writing."]]},
  {num:41,words:[["Ma o lenei,", "And now,"], ["ou te apoapoai atu ia te outou ia outou saili lenei Iesu o le ua tusi i ai le au perofeta ma aposetolo,", "I would commend you to seek this Jesus of whom the prophets and apostles have written,"], ["ina ia i ai ma tumau ia te outou e faavavau le alofa tunoa o le Atua le Tamā,", "that the grace of God the Father, and also the Lord Jesus Christ,"], ["ma le Alii o Iesu Keriso,", "and the Holy Ghost,"], ["ma le Agaga Paia,", "which beareth record of them,"], ["o le ua molimau ia te i laua.", "may be and abide in you forever."], ["Amene.", "Amen."]]},
];
renderVerseSet(et_ch_12_Verses, 'et-ch12-verses');

var et_ch_13_Verses = [
  {num:1,words:[["Ma o lenei o au,", "And now I,"], ["o Moronae,", "Moroni,"], ["ou te faasolo ina faaiu lau talafaamaumau e uiga i le faaumatiaga o le nuu o e ua ou tusi e uiga i ai.", "proceed to finish my record concerning the destruction of the people of whom I have been writing."]]},
  {num:2,words:[["Aua faauta,", "For behold,"], ["sa latou teena upu uma a Eteru;", "they rejected all the words of Ether;"], ["aua sa ia tau atu moni lava ia te i latou e uiga i mea uma,", "for he truly told them of all things,"], ["mai le amataga o tagata;", "from the beginning of man;"], ["ma e faapea ina ua uma ona maui atu o le vai mai luga o lenei laueleele sa avea ma laueleele silisili ona lelei i luga o isi laueleele uma,", "and that after the waters had receded from off the face of this land it became a choice land above all other lands,"], ["o se laueleele filifilia o le Alii;", "a chosen land of the Lord;"], ["o le mea lea ua finagalo ai le Alii ia auauna atu ia te ia tagata uma o e e nonofo ai i ona luga;", "wherefore the Lord would have that all men should serve him who dwell upon the face thereof;"]]},
  {num:3,words:[["Ma o le nofoaga lea o le Ierusalema Fou,", "And that it was the place of the New Jerusalem,"], ["lea o le a alu ifo i lalo mai le lagi,", "which should come down out of heaven,"], ["ma o le afioaga paia lea o le Alii.", "and the holy sanctuary of the Lord."]]},
  {num:4,words:[["Faauta,", "Behold,"], ["sa vaai Eteru i aso o Keriso,", "Ether saw the days of Christ,"], ["ma sa ia tautala e uiga i se Ierusalema Fou i luga o lenei laueleele.", "and he spake concerning a New Jerusalem upon this land."]]},
  {num:5,words:[["Ma sa ia tautala foi e uiga i le aiga o Isaraelu,", "And he spake also concerning the house of Israel,"], ["ma le Ierusalema lea o le a sau ai Liae —e faapea a uma ona faaumatiaina o le a toe atiae,", "and the Jerusalem from whence Lehi should come—after it should be destroyed it should be built up again,"], ["e avea o se aai paia i le Alii;", "a holy city unto the Lord;"], ["o le mea lea,", "wherefore,"], ["e le mafai ai ona avea ma se Ierusalema fou ona sa i ai i se taimi anamua;", "it could not be a new Jerusalem for it had been in a time of old;"], ["ae o le a toe atiae,", "but it should be built up again,"], ["ma avea o se aai paia i le Alii;", "and become a holy city of the Lord;"], ["ma o le a atiae mo le aiga o Isaraelu—", "and it should be built unto the house of Israel."]]},
  {num:6,words:[["Ma e faapea o le a atiae se Ierusalema Fou i luga o le laueleele lenei,", "And that a New Jerusalem should be built upon this land,"], ["mo le toe vaega o le fanau a Iosefa ,", "unto the remnant of the seed of Joseph,"], ["o ni mea ua i ai se faatusa .", "for which things there has been a type."]]},
  {num:7,words:[["Aua e pei ona aumai e Iosefa lona tamā i lalo i le laueleele o Aikupito ,", "For as Joseph brought his father down into the land of Egypt,"], ["sa faapea lava ona maliu ai o ia iina;", "even so he died there;"], ["o le mea lea,", "wherefore,"], ["na aumai ai e le Alii i fafo mai le laueleele o Ierusalema se toe vaega o le fanau a Iosefa,", "the Lord brought a remnant of the seed of Joseph out of the land of Jerusalem,"], ["ina ia alofa mutimutivale o ia i le fanau a Iosefa ina ia latou le fano,", "that he might be merciful unto the seed of Joseph that they should perish not,"], ["e pei ona ia alofa mutimutivale i le tamā o Iosefa ina ia le fano o ia.", "even as he was merciful unto the father of Joseph that he should perish not."]]},
  {num:8,words:[["O le mea lea,", "Wherefore,"], ["o le a atiae i luga o le laueleele lenei le toe vaega o le aiga o Iosefa;", "the remnant of the house of Joseph shall be built upon this land;"], ["ma o le a avea o se laueleele o lo latou tofi;", "and it shall be a  land of their inheritance;"], ["ma o le a latou atiae se aai paia i le Alii,", "and they shall build up a holy city unto the Lord,"], ["e pei o le Ierusalema tuai;", "like unto the Jerusalem of old;"], ["ma o le a le toe faafememeaiina i latou,", "and they shall no more be confounded,"], ["seia oo mai le iuga pe a mavae atu le lalolagi.", "until the end come when the earth shall pass away."]]},
  {num:9,words:[["Ma o le a i ai se lagi fou ma se lalolagi fou;", "And there shall be a new heaven and a new earth;"], ["ma o le a pei i laua o le lagi tuai ma le lalolagi tuai vagana ai o mea tuai ua mavae atu,", "and they shall be like unto the old save the old have passed away,"], ["ma ua faafouina mea uma.", "and all things have become new."]]},
  {num:10,words:[["Ma ona oo mai ai lea o le Ierusalema Fou;", "And then cometh the New Jerusalem;"], ["ma amuia lava i latou o e e nonofo ai,", "and blessed are they who dwell therein,"], ["aua o i latou ia o e ua sinasina o latou ofu i le toto o le Tamai Mamoe;", "for it is they whose garments are white through the blood of the Lamb;"], ["ma o i latou ia o i latou o e ua faitauina i totonu o le toe vaega o le fanau a Iosefa,", "and they are they who are numbered among the remnant of the seed of Joseph,"], ["o e o le aiga o Isaraelu.", "who were of the house of Israel."]]},
  {num:11,words:[["Ma ona oo mai ai foi lea o le Ierusalema tuai;", "And then also cometh the Jerusalem of old;"], ["ma ona tagata,", "and the inhabitants thereof,"], ["amuia lava i latou,", "blessed are they,"], ["ona ua faamamaina i latou i le toto o le Tamai Mamoe;", "for they have been washed in the blood of the Lamb;"], ["ma o i latou ia o i latou o e sa faataapeape ma ua faapotopoto mai i itu e fa o le lalolagi,", "and they are they who were scattered and gathered in from the four quarters of the earth,"], ["ma mai atunuu i matu,", "and from the north countries,"], ["ma o e ua tofusia i le faataunuuina o le feagaiga lea na faia e le Atua ma lo latou tamā,", "and are partakers of the fulfilling of the covenant which God made with their father,"], ["o Aperaamo .", "Abraham."]]},
  {num:12,words:[["Ma a oo mai nei mea,", "And when these things come,"], ["ona faataunuuina lea o le mau ua fai mai,", "bringeth to pass the scripture which saith,"], ["e i ai i latou o e sa muamua ,", "there are they who were first,"], ["o e o le a mulimuli;", "who shall be last;"], ["ma e i ai i latou o e sa mulimuli,", "and there are they who were last,"], ["o e o le a muamua.", "who shall be first."]]},
  {num:13,words:[["Ma sa fai o le a ou tusi ni isi mea e tele atu,", "And I was about to write more,"], ["peitai sa faasaina au;", "but I am forbidden;"], ["ae sa tetele ma ofoofogia lava valoaga a Eteru;", "but great and marvelous were the prophecies of Ether;"], ["peitai sa latou manatu ia te ia o se meanoa,", "but they esteemed him as naught,"], ["ma tuli ese o ia i fafo;", "and cast him out;"], ["ma sa lafi o ia i le ana o se papa i le ao,", "and he hid himself in the cavity of a rock by day,"], ["ma i le po sa alu atu o ia ma vaai i mea o le a oo mai i luga o tagata.", "and by night he went forth viewing the things which should come upon the people."]]},
  {num:14,words:[["Ma ao nofo o ia i le ana o se papa sa ia faia le vaega na totoe o lenei talafaamaumau,", "And as he dwelt in the cavity of a rock he made the remainder of his record,"], ["ma vaai i faafanoga ia na oo mai i luga o tagata,", "viewing the destructions which came upon the people,"], ["i le po.", "by night."]]},
  {num:15,words:[["Ma sa oo i le tausaga lava lea na tuli ese ai o ia mai totonu o le nuu,", "And it came to pass that in that same year in which he was cast out from among the people there began to be a great war among the people,"], ["sa amata ona i ai o se taua tele i totonu o le nuu, ona sa i ai le toatele o e na tutu ae,", "for there were many who rose up,"], ["o e o ni tagata malolosi,", "who were mighty men,"], ["ma saili e faaumatia Korianetuma, e ala ia latou fuafuaga faalilolilo o le amioleaga,", "and sought to destroy Coriantumr by their secret plans of wickedness,"], ["ia ua uma ona talatala atu.", "of which hath been spoken."]]},
  {num:16,words:[["Ma o lenei o Korianetuma,", "And now Coriantumr,"], ["sa aoao ia lava,", "having studied,"], ["i tomai uma e uiga i taua ma le atamai uma o le lalolagi,", "himself, in all the arts of war and all the cunning of the world,"], ["o le mea lea na ia tau ai ma i latou o e na saili e faaumatia o ia.", "wherefore he gave battle unto them who sought to destroy him."]]},
  {num:17,words:[["Peitai,", "But he repented not,"], ["sa le salamo o ia,", "neither his fair sons nor daughters;"], ["po o ona atalii aulelei po o ona afafine; po o atalii ma afafine lalelei foi o Ko'oro;", "neither the fair sons and daughters of Cohor;"], ["po o atalii ma afafine lalelei foi o Kori'oa;", "neither the fair sons and daughters of Corihor;"], ["ma i se aotelega atoa,", "and in fine,"], ["sa leai ni atalii ma ni afafine lalelei i luga o le eleele atoa o e na salamo ia latou agasala.", "there were none of the fair sons and daughters upon the face of the whole earth who repented of their sins."]]},
  {num:18,words:[["O le mea lea,", "Wherefore,"], ["sa oo i le tausaga muamua na nofo ai Eteru i le ana o se papa,", "it came to pass that in the first year that Ether dwelt in the cavity of a rock,"], ["sa i ai le toatele o tagata o e na fasiotia i le pelu a i latou o faalapotopotoga faalilolilo,", "there were many people who were slain by the sword of those secret combinations,"], ["o e na tau e faasaga ia Korianetuma ina ia latou maua le malo.", "fighting  against Coriantumr that they might obtain the kingdom."]]},
  {num:19,words:[["Ma sa oo ina tele ona tau o atalii o Korianetuma ma tele foi lo latou toto na masaa.", "And it came to pass that the sons of Coriantumr fought much and bled much."]]},
  {num:20,words:[["Ma i le tausaga lona lua na oo mai ai le afioga a le Alii ia Eteru,", "And in the second year the word of the Lord came to Ether,"], ["e tatau ona alu atu o ia ma vavalo atu ia Korianetuma e faapea,", "that he should go and prophesy unto Coriantumr that,"], ["afai e salamo o ia,", "if he would repent,"], ["ma lona aiga uma,", "and all his household,"], ["o le a tuu mai e le Alii ia te ia lona malo ma faasaoina le nuu—", "the Lord would give unto him his kingdom and spare the people—"]]},
  {num:21,words:[["A leai o le a faaumatia i latou, ma lona aiga atoa,", "Otherwise they should be destroyed,"], ["vagana ai o ia lava.", "and all his household save it were himself."], ["Ma o le a nao ia e ola e vaai i le faataunuuina o valoaga ia ua uma ona fetalaia e uiga i se tasi nuu o le a latou mauaina le laueleele mo o latou tofi;", "And he should only live to see the fulfilling of the prophecies which had been spoken concerning another people receiving the land for their inheritance;"], ["ma o le a tanuina Korianetuma e i latou;", "and Coriantumr should receive a burial by them;"], ["ma o le a faaumatia tagata uma vagana ai Korianetuma .", "and every soul should be destroyed save it were Coriantumr."]]},
  {num:22,words:[["Ma sa oo ina le salamo Korianetuma,", "And it came to pass that Coriantumr repented not,"], ["po o lona aiga,", "neither his household,"], ["po o le nuu;", "neither the people;"], ["ma sa le taofia le taua;", "and the wars ceased not;"], ["ma sa latou saili e fasioti Eteru,", "and they sought to kill Ether,"], ["ae sa sola o ia mai luma o i latou ma toe lafi i le ana o le papa.", "but he fled from before them and hid again in the cavity of the rock."]]},
  {num:23,words:[["Ma sa oo ina tulai mai Sareto,", "And it came to pass that there arose up Shared,"], ["ma ia sii tau atu foi ia Korianetuma;", "and he also gave battle unto Coriantumr;"], ["ma sa ia faatoilaloina o ia,", "and he did beat him,"], ["sa oo ina ia ave o ia faatagataotaua i le tausaga lona tolu.", "insomuch that in the third year he did bring him into captivity."]]},
  {num:24,words:[["Ma i le tausaga lona fa,", "And the sons of Coriantumr,"], ["sa faatoilalo e atalii o Korianetuma Sareto,", "in the fourth year, did beat Shared,"], ["ma toe maua mai le malo mo lo latou tamā.", "and did obtain the kingdom again unto their father."]]},
  {num:25,words:[["O lenei sa amata ona i ai o se taua i luga o le laueleele atoa,", "Now there began to be a war upon all the face of the land,"], ["sa tau tagata taitoatasi ma lona lima mo mea sa ia manao i ai.", "every man with his band fighting for that which he desired."]]},
  {num:26,words:[["Ma ua i ai faomea,", "And there were robbers,"], ["ma i se aotelega,", "and in fine,"], ["sa i ai amioleaga uiga eseese uma i luga o le laueleele atoa.", "all manner of wickedness upon all the face of the land."]]},
  {num:27,words:[["Ma sa oo ina matua ita tele Korianetuma ia Sareto,", "And it came to pass that Coriantumr was exceedingly angry with Shared,"], ["ma sa ia alu atu faasaga ia te ma ana autau e tau ma ia;", "and he went against him with his armies to battle;"], ["ma sa latou fetaiai ma le feitagai tele,", "and they did meet in great anger,"], ["ma sa latou fetaiai i le vanu o Kilikala;", "and they did meet in the valley of Gilgal;"], ["ma sa matua tuga tele le taua.", "and the battle became exceedingly sore."]]},
  {num:28,words:[["Ma sa oo ina tau Sareto ma ia mo le va o aso e tolu. Ma sa oo ina faatoilalo o ia e Korianetuma,", "And it came to pass that Shared fought against him for the space of three days. And it came to pass that Coriantumr beat him,"], ["ma tuliloa o ia seia oo mai i laugatasi o Heselona.", "and did pursue him until he came to the plains of Heshlon."]]},
  {num:29,words:[["Ma sa oo ina toe tau Sareto ma ia i luga o laugatasi;", "And it came to pass that Shared gave him battle again upon the plains;"], ["faauta foi,", "and behold,"], ["sa ia faatoilaloina Korianetuma,", "he did beat Coriantumr,"], ["ma toe tuli mai o ia i tua i le vanu o Kilikala.", "and drove him back again to the valley of Gilgal."]]},
  {num:30,words:[["Ma sa toe tau Korianetuma ma Sareto i le vanu o Kilikala,", "And Coriantumr gave Shared battle again in the valley of Gilgal,"], ["lea na ia faatoilalo ai Sareto ma fasioti o ia.", "in which he beat Shared and slew him."]]},
  {num:31,words:[["Ma sa faamanua e Sareto ia Korianetuma i lona ogavae,", "And Shared wounded Coriantumr in his thigh,"], ["lea na le toe alu atu ai o ia e tau mo le va o le lua tausaga,", "that he did not go to battle again for the space of two years,"], ["o se taimi sa faia ai e tagata uma sa i luga o le laueleele le faamasaaina o le toto,", "in which time all the people upon the face of the land were shedding blood,"], ["ma sa leai se tasi e taofia i latou.", "and there was none to restrain them."]]},
];
renderVerseSet(et_ch_13_Verses, 'et-ch13-verses');

var et_ch_14_Verses = [
  {num:1,words:[["Ma o lenei sa amata ona i ai o se fetuu tele i luga o le laueleele atoa ona o le amioletonu o tagata,", "And now there began to be a great curse upon all the land because of the iniquity of the people,"], ["lea a tuu ai e se tagata sana meafaigaluega po o lana pelu i luga o lana fata,", "in which,"], ["po o luga o se mea e manao o ia e teu ai,", "if a man should lay his tool or his sword upon his shelf,"], ["faauta,", "or upon the place whither he would keep it, behold,"], ["o le aso e sosoo ai,", "upon the morrow,"], ["e le mafai ona ia toe mauaina,", "he could not find it,"], ["ona o le tetele tele o le fetuu i luga o le laueleele.", "so great was the curse upon the land."]]},
  {num:2,words:[["O le mea lea sa uumau ai e tagata taitoatasi ana lava mea,", "Wherefore every man did cleave unto that which was his own,"], ["i ona lima,", "with his hands,"], ["ma lē fia nono mai pe faaune atu e ia; ma sa taitasi le tagata ma uu le au o lana pelu i lona lima taumatau,", "and would not borrow neither would he lend;"], ["i le puipuiga o ana meatotino ma lona lava ola,", "and every man kept the hilt of his sword in his right hand,"], ["ma ola o ana ava ma fanau.", "in the defense of his property and his own life and of his wives and children."]]},
  {num:3,words:[["Ma o lenei,", "And now,"], ["ina ua mavae le va o le lua tausaga,", "after the space of two years,"], ["ma ina ua mavae le oti o Sareto,", "and after the death of Shared,"], ["faauta,", "behold,"], ["sa tu mai le uso o Sareto ma tau o ia ma Korianetuma,", "there arose the brother of Shared and he gave battle unto Coriantumr,"], ["lea na faatoilalo ai o ia e Korianetuma ma tuliloa ia te ia e oo atu i le vao o Akiso.", "in which Coriantumr did beat him and did pursue him to the wilderness of Akish."]]},
  {num:4,words:[["Ma sa oo ina tau le uso o Sareto ma ia i le vao o Akiso;", "And it came to pass that the brother of Shared did give battle unto him in the wilderness of Akish;"], ["ma sa oo ina matua tuga tele le taua,", "and the battle became exceedingly sore,"], ["ma e tele afe na pauu i le pelu.", "and many thousands fell by the sword."]]},
  {num:5,words:[["Ma sa oo ina sio e Korianetuma le vao;", "And it came to pass that Coriantumr did lay siege to the wilderness;"], ["ma sa savavali atu le uso o Sareto i fafo mai le vao i le po,", "and the brother of Shared did march forth out of the wilderness by night,"], ["ma fasioti se vaega o le autau a Korianetuma,", "and slew a part of the army of Corian– tumr,"], ["ao onana i latou.", "as they were drunken."]]},
  {num:6,words:[["Ma sa alu atu o ia i le laueleele o Morona,", "And he came forth to the land of Moron,"], ["ma ua nofo o ia lava i luga o le nofoalii o Korianetuma.", "and placed himself upon the throne of Coriantumr."]]},
  {num:7,words:[["Ma sa oo ina nonofo Korianetuma ma lana autau i le vao mo le va o le lua tausaga,", "And it came to pass that Coriantumr dwelt with his army in the wilderness for the space of two years,"], ["lea na ia maua ai se malosi tele i lana autau.", "in which he did receive great strength to his army."]]},
  {num:8,words:[["O lenei,", "Now the brother of Shared,"], ["o le uso o Sareto,", "whose name was Gilead,"], ["o lona igoa o Kiliata, sa ia maua foi se malosi tele i lana autau,", "also received great strength to his army,"], ["ona o faapotopotoga faalilolilo.", "because of secret combinations."]]},
  {num:9,words:[["Ma sa oo ina fasioti o ia e lana faitaulaga sili ao nofo o ia i luga o lona nofoalii.", "And it came to pass that his high priest murdered him as he sat upon his throne."]]},
  {num:10,words:[["Ma sa oo ina fasioti o ia e se tasi o faapotopotoga faalilolilo i totonu o se auala faalilolilo,", "And it came to pass that one of the secret combinations murdered him in a secret pass,"], ["ma ia maua ai mo ia lava le malo;", "and obtained unto himself the kingdom;"], ["ma o lona igoa o Lipi;", "and his name was Lib;"], ["ma o Lipi o se tagata tino ese maualuga,", "and Lib was a man of great stature,"], ["sa sili atu nai lo se isi lava tagata i totonu o le nuu atoa.", "more than any other man among all the people."]]},
  {num:11,words:[["Ma sa oo i le tausaga muamua o Lipi,", "And it came to pass that in the first year of Lib,"], ["na sau ai Korianetuma i luga i le laueleele o Morona,", "Coriantumr came up unto the land of Moron,"], ["ma tau ma Lipi.", "and gave battle unto Lib."]]},
  {num:12,words:[["Ma sa oo ina tau o ia ma Lipi,", "And it came to pass that he fought with Lib,"], ["lea na ta ai e Lipi i lona lima lea na manua ai o ia;", "in which Lib did smite upon his arm that he was wounded;"], ["e ui i lea,", "nevertheless,"], ["sa fetaomi atu i luma le autau a Korianetuma i luga o Lipi,", "the army of Coriantumr did press forward upon Lib,"], ["sa oo ina sola o ia i tuaoi i luga o le matafaga.", "that he fled to the borders upon the seashore."]]},
  {num:13,words:[["Ma sa oo ina tuliloa o ia e Korianetuma;", "And it came to pass that Coriantumr pursued him;"], ["ma sa tau o ia ma Lipi i luga o le matafaga.", "and Lib gave battle unto him upon the seashore."]]},
  {num:14,words:[["Ma sa oo ina taia e Lipi le autau a Korianetuma,", "And it came to pass that Lib did smite the army of Coriantumr,"], ["sa oo ina latou toe sosola i le vao o Akiso.", "that they fled again to the wilderness of Akish."]]},
  {num:15,words:[["Ma sa oo ina tuliloa o ia e Lipi seia oo ina oo mai o ia i laugatasi o Akosa.", "And it came to pass that Lib did pursue him until he came to the plains of Agosh."], ["Ma sa ave e Korianetuma tagata uma faatasi ma ia ao sola o ia i luma o Lipi, i le vaega lena o le laueleele na ia sola atu i ai.", "And Coriantumr had taken all the people with him as he fled before Lib in that quarter of the land whither he fled."]]},
  {num:16,words:[["Ma ina ua oo mai o ia i laugatasi o Akosa,", "And when he had come to the plains of Agosh he gave battle unto Lib,"], ["sa tau o ia ma Lipi,", "and he smote upon him until he died;"], ["ma sa ia taina o ia seia oo ina oti o ia; e ui i lea,", "nevertheless,"], ["sa sau le uso o Lipi e faasaga ia Korianetuma e sui ia te ia,", "the brother of Lib did come against Coriantumr in the stead thereof,"], ["ma sa oo ina matua tuga tele lava le taua,", "and the battle became exceedingly sore,"], ["lea na toe sola ai Korianetuma i luma o le autau a le uso o Lipi.", "in the which Coriantumr fled again before the army of the brother of Lib."]]},
  {num:17,words:[["O lenei o le igoa o le uso o Lipi sa taua o Sesa. Ma sa oo ina tuliloa e Sesa ia Korianetuma,", "Now the name of the brother of Lib was called Shiz. And it came to pass that Shiz pursued after Coriantumr,"], ["ma sa faatoilalo e ia aai e tele,", "and he did overthrow many cities,"], ["ma sa ia fasiotia fafine ma tamaiti,", "and he did slay both women and children,"], ["ma ia susunu aai.", "and he did burn the cities."]]},
  {num:18,words:[["Ma sa oo atu i le laueleele atoa le fefefe ia Sesa;", "And there went a fear of Shiz throughout all the land;"], ["ioe,", "yea,"], ["sa alu atu se alaga i le laueleele atoa—O ai e mafai ona tu atu i luma o le autau a Sesa? Faauta,", "a cry went forth throughout the land—Who can stand before the army of Shiz? Behold,"], ["ua tafi e ia le laueleele i ona luma!", "he sweepeth the earth before him!"]]},
  {num:19,words:[["Ma sa oo ina amata ona lolofi faatasi mai tagata i ana autau,", "And it came to pass that the people began to flock together in armies,"], ["i luga o le laueleele atoa.", "throughout all the face of the land."]]},
  {num:20,words:[["Ma sa vaeluaina i latou;", "And they were divided;"], ["o se vaega o i latou sa sosola atu i le autau a Sesa,", "and a part of them fled to the army of Shiz,"], ["ma o se vaega o i latou sa sosola atu i le autau a Korianetuma.", "and a part of them fled to the army of Coriantumr."]]},
  {num:21,words:[["Ma ona o le tetele tele ma le umi o le taua,", "And so great and lasting had been the war,"], ["ma umi ona avea ma vaaiga o le faamasaa toto ma tagata feoti,", "and so long had been the scene of bloodshed and carnage,"], ["sa oo ina ufitia ai luga o le laueleele atoa i tino o tagata oti.", "that the whole face of the land was covered with the bodies of the dead."]]},
  {num:22,words:[["Ma sa televave ma taalise tele le taua sa leai ni isi na totoe e tanuina tagata oti,", "And so swift and speedy was the war that there was none left to bury the dead,"], ["ae sa latou savavali atu i luma mai i le faamasaaina o le toto i le faamasaaina o le toto,", "but they did march forth from the shedding of blood to the shedding of blood,"], ["ma tuu ai tino o tane,", "leaving the bodies of both men,"], ["fafine,", "women,"], ["ma tamaiti e salalau solo i luga o le laueleele,", "and children strewed upon the face of the land,"], ["e fai ma vete a anufe o le tino.", "to become a prey to the worms of the flesh."]]},
  {num:23,words:[["Ma ua alu atu lo latou manogi i luga o le laueleele,", "And the scent thereof went forth upon the face of the land,"], ["ioe,", "even upon all the face of the land;"], ["i luga o le laueleele atoa uma lava; o le mea lea na mafatia ai tagata i le ao ma le po,", "wherefore the people became troubled by day and by night,"], ["ona o le manogi na i ai.", "because of the scent thereof."]]},
  {num:24,words:[["E ui i lea,", "Nevertheless,"], ["sa le tuua e Sesa le tuliloaina o Korianetuma;", "Shiz did not cease to pursue Coriantumr;"], ["ona sa tauto o ia o le a ia taui i luga o Korianetuma le toto o lona uso,", "for he had sworn to avenge himself upon Coriantumr of the blood of his brother,"], ["o le ua fasiotia,", "who had been slain,"], ["ma le fetalaiga a le Alii lea na oo mai ia Eteru e faapea o le a le oti lava Korianetuma i le pelu.", "and the word of the Lord which came to Ether that Coriantumr should not fall by the sword."]]},
  {num:25,words:[["Ma ua faapea ona tatou vaai ai sa asiasi mai lava le Alii ia te i latou i le atoatoa o lona toasa,", "And thus we see that the Lord did visit them in the fulness of his wrath,"], ["ma ua saunia e lo latou amioleaga ma a latou mea inosia se ala mo lo latou faaumatiaina e faavavau.", "and their wickedness and abominations had prepared a way for their everlasting destruction."]]},
  {num:26,words:[["Ma sa oo ina tuliloa e Sesa ia Korianetuma agai i sasae,", "And it came to pass that Shiz did pursue Coriantumr eastward,"], ["seia oo mai lava i tuaoi i tafatafa o le matafaga,", "even to the borders by the seashore,"], ["ma o iina na tau ai o ia ma Sesa mo le va o aso e tolu.", "and there he gave battle unto Shiz for the space of three days."]]},
  {num:27,words:[["Ma sa matua matautia tele le faafanoga i totonu o autau a Sesa sa amata ona matatau tagata,", "And so terrible was the destruction among the armies of Shiz that the people began to be frightened,"], ["ma amata ona sosola mai luma o autau a Korianetuma;", "and began to flee before the armies of Coriantumr;"], ["ma sa latou sosola atu i le laueleele o Kori'oa,", "and they fled to the land of Corihor,"], ["ma tafi ese mai o latou luma tagata sa nonofo ai,", "and swept off the inhabitants before them,"], ["i latou uma ia o e sa le fia au faatasi ma i latou.", "all them that would not join them."]]},
  {num:28,words:[["Ma sa latou faatutu o latou faleie i le vanu o Kori'oa;", "And they pitched their tents in the valley of Corihor;"], ["ma sa faatutu e Korianetuma ona faleie i le vanu o Suro. O lenei o le vanu o Suro sa latalata i le maupuepue o Kominoa;", "and Coriantumr pitched his tents in the valley of Shurr. Now the valley of Shurr was near the hill Comnor;"], ["o le mea lea,", "wherefore,"], ["na faapotopoto faatasi ai e Korianetuma ana autau i luga o le maupuepue o Kominoa,", "Coriantumr did gather his armies together upon the hill Comnor,"], ["ma ili atu se pu i autau a Sesa e valaau atu ai ia te i latou e o mai e tau.", "and did sound a trumpet unto the armies of Shiz to invite them forth to battle."]]},
  {num:29,words:[["Ma sa oo ina latou o mai,", "And it came to pass that they came forth,"], ["peitai sa toe tulia i latou;", "but were driven again;"], ["ma sa latou o mai faalua,", "and they came the second time,"], ["ma sa toe tulia foi i latou i le taimi lona lua. Ma sa oo ina latou toe o mai i le taimi lona tolu,", "and they were driven again the second time. And it came to pass that they came again the third time,"], ["ma sa oo ina tuga tele lava le taua.", "and the battle became exceedingly sore."]]},
  {num:30,words:[["Ma sa oo ina taia e Sesa ia Korianetuma sa oo ina ia faaoo atu ia te ia ni manua loloto e tele;", "And it came to pass that Shiz smote upon Coriantumr that he gave him many deep wounds;"], ["ma o Korianetuma,", "and Coriantumr,"], ["ona o le tele o lona toto ua masaa,", "having lost his blood,"], ["ua matapogia,", "fainted,"], ["ma sa aveese atu o ia e peiseai ua oti.", "and was carried away as though he were dead."]]},
  {num:31,words:[["O lenei ona o le tele tele o tane, fafine,", "Now the loss of men,"], ["ma tamaiti na fasiotia i itu uma e lua,", "women and children on both sides was so great that Shiz commanded his people that they should not pursue the armies of Coriantumr;"], ["o lea na faatonu atu ai Sesa i ona tagata ia aua nei o latou tuliloaina autau a Korianetuma;", "wherefore,"], ["o le mea lea, na latou toe foi atu ai i la latou togalauapi.", "they returned to their camp."]]},
];
renderVerseSet(et_ch_14_Verses, 'et-ch14-verses');

var et_ch_15_Verses = [
  {num:1,words:[["Ma sa oo ina ua toe malosi mai Korianetuma i ona manua,", "And it came to pass when Coriantumr had recovered of his wounds,"], ["sa amata ona ia manatua o upu na fetalai mai e Eteru ia te ia.", "he began to remember the words which Ether had spoken unto him."]]},
  {num:2,words:[["Sa ia vaai ua uma ona fasiotia i le pelu le toetoe o le lua miliona o ona tagata,", "He saw that there had been slain by the sword already nearly two millions of his people,"], ["ma sa amata ona ia faanoanoa i lona loto;", "and he began to sorrow in his heart;"], ["ioe,", "yea,"], ["ua uma ona fasiotia o le lua miliona o tane malolosi,", "there had been slain two millions of mighty men,"], ["ma a latou ava foi ma a latou fanau.", "and also their wives and their children."]]},
  {num:3,words:[["Sa amata ona salamo o ia i le leaga lea na ia faia;", "He began to repent of the evil which he had done;"], ["sa amata ona ia manatua o upu na fetalaia e fofoga o perofeta uma,", "he began to remember the words which had been spoken by the mouth of all the prophets,"], ["ma sa vaai o ia ua faataunuuina lava i latou, o upu uma taitasi,", "and he saw them that they were fulfilled thus far,"], ["e oo mai i lea lava taimi;", "every whit;"], ["ma sa faanoanoa lona agaga ma musu e faamafanafanaina.", "and his soul mourned and refused to be comforted."]]},
  {num:4,words:[["Ma sa oo ina ia tusi atu se tusi ia Sesa,", "And it came to pass that he wrote an epistle unto Shiz,"], ["e manao ia te ia ia faasaoina e ia tagata, ae o le a ia tuu atu le malo,", "desiring him that he would spare the people,"], ["mo ola o tagata.", "and he would give up the kingdom for the sake of the lives of the people."]]},
  {num:5,words:[["Ma sa oo ina ua maua e Sesa lana tusi ma sa ia tusi mai se tusi ia Korianetuma,", "And it came to pass that when Shiz had received his epistle he wrote an epistle unto Coriantumr,"], ["e faapea afai na te tuu atu o ia lava,", "that if he would give himself up,"], ["ina ia mafai ona ia fasiotia o ia i lana lava pelu,", "that he might slay him with his own sword,"], ["o le a ia faasaoina ola o tagata.", "that he would spare the lives of the people."]]},
  {num:6,words:[["Ma sa oo ina le salamo tagata i lo latou amioletonu;", "And it came to pass that the people repented not of their iniquity;"], ["ma sa faaosoina le ita o tagata o Korianetuma e faasaga i tagata o Sesa;", "and the people of Coriantumr were stirred up to anger against the people of Shiz;"], ["ma sa faaosoina le ita o tagata o Sesa e faasaga i tagata o Korianetuma;", "and the people of Shiz were stirred up to anger against the people of  Coriantumr;"], ["o le mea lea,", "wherefore,"], ["na sii taua atu ai tagata o Sesa i tagata o Korianetuma.", "the people of Shiz did give battle unto the people of Coriantumr."]]},
  {num:7,words:[["Ma ina ua vaai atu Korianetuma o le a pau o ia sa toe sola o ia mai luma o tagata o Sesa.", "And when Coriantumr saw that he was about to fall he fled again before the people of Shiz."]]},
  {num:8,words:[["Ma sa oo ina tau mai o ia i vai o Ripelianekuma,", "And it came to pass that he came to the waters of Ripliancum,"], ["o lona uiga, pe a faaliliu,", "which,"], ["e tele,", "by interpretation,"], ["pe sili atu i mea uma;", "is large,"], ["o le mea lea, ina ua latou tau mai i nei vai,", "or to exceed all;"], ["sa latou faatutu o latou faleie;", "wherefore,"], ["ma sa faatutu foi e Sesa ona faleie latalata ane ia te i latou;", "when they came to these waters they pitched their tents;"], ["ma o lea, o le aso na sosoo ai,", "and Shiz also pitched his tents near unto them;"], ["sa latou o mai e tau.", "and therefore on the morrow they did come to battle."]]},
  {num:9,words:[["Ma sa oo ina latou tau se taua tuga tele lava,", "And it came to pass that they fought an exceedingly sore battle,"], ["lea na toe manua ai Korianetuma,", "in which Coriantumr was wounded again,"], ["ma matapogia ai o ia i le toto na masaa.", "and he fainted with the loss of blood."]]},
  {num:10,words:[["Ma sa oo ina fetaomi atu autau a Korianetuma i luga o autau a Sesa sa oo ina latou faatoilaloina i latou,", "And it came to pass that the armies of Coriantumr did press upon the armies of Shiz that they beat them,"], ["ma sa oo ina latou faia ia te i latou ia sosola ai mai o latou luma;", "that they caused them to flee before them;"], ["ma sa latou sosola agai i saute,", "and they did flee southward,"], ["ma sa latou faatutu o latou faleie i le nofoaga lea sa taua o Okati.", "and did pitch their tents in a place which was called Ogath."]]},
  {num:11,words:[["Ma sa oo ina faatutu e autau a Korianetuma o latou faleie i tafatafa o le maupuepue o Rama;", "And it came to pass that the army of Coriantumr did pitch their tents by the hill Ramah;"], ["ma o le maupuepue lava lea na natia mau ai e lou tamā o Mamona talafaamaumau, ua paia,", "and it was that same hill where my father Mormon did hide up the records unto the Lord,"], ["mo le Alii.", "which were sacred."]]},
  {num:12,words:[["Ma sa oo ina laua faapotopoto faatasi tagata uma i luga o le laueleele atoa,", "And it came to pass that they did gather together all the people upon all the face of the land,"], ["o e sa lei fasiotia,", "who had not been slain,"], ["vagana ai Eteru.", "save it was Ether."]]},
  {num:13,words:[["Ma sa oo ina vaai Eteru i mea uma na fai e tagata;", "And it came to pass that Ether did behold all the doings of the people;"], ["ma sa ia vaai o tagata sa mo Korianetuma ua faapotopoto faatasi i le autau a Korianetuma;", "and he beheld that the people who were for Coriantumr were gathered together to the army of Coriantumr;"], ["ma o tagata sa mo Sesa ua faapotopoto faatasi i le autau a Sesa.", "and the people who were for Shiz were gathered together to the army of Shiz."]]},
  {num:14,words:[["O le mea lea,", "Wherefore,"], ["sa laua faapotopoto faatasi tagata mo le va o le fa tausaga,", "they were for the space of four years gathering together the people,"], ["ina ia mafai ona la maua tagata uma o e sa i luga o le laueleele,", "that they might get all who were upon the face of the land,"], ["ma ia mafai ona la maua le malosi uma e mafai ona la mauaina.", "and that they might receive all the strength which it was possible that they could receive."]]},
  {num:15,words:[["Ma sa oo ina ua uma ona latou faapotopoto faatasi uma,", "And it came to pass that when they were all gathered together,"], ["o tagata taitoatasi i le autau na manao i ai o ia,", "every one to the army which he would,"], ["faatasi ma a latou ava ma a latou fanau—o tane,", "with their wives and their children—both men women and children being armed with weapons of war,"], ["fafine ma fanau ua faaauupegaina i auupega o taua,", "having shields,"], ["ua i ai talita, ma ufifatafata ,", "and breastplates,"], ["ma pulou-tau;", "and head– plates,"], ["ma ua oofu e tusa ma ofu o le taua—sa latou savavali atu e faasasaga o le tasi i le isi e tau;", "and being clothed after the manner of war—they did march forth one against another to battle;"], ["ma sa latou tau i le aso atoa lena,", "and they fought all that day,"], ["ma sa le manumalo.", "and conquered not."]]},
  {num:16,words:[["Ma sa oo ina ua oo mai le po sa latou vaivai,", "And it came to pass that when it was night they were weary,"], ["ma malolo atu ia latou togalauapi;", "and retired to their camps;"], ["ma ina ua uma ona latou malolo atu i o latou togalauapi, sa amata ona latou uio ma laue mo le toesea o e ua fasiotia o o latou tagata;", "and after they had retired to their camps they took up a howling and a lamentation for the loss of the slain of their people;"], ["ma sa matua lava lo latou fetagisi,", "and so great were their cries,"], ["lo latou uio ma auega,", "their howlings and lamentations,"], ["sa latou matua saeia le ea.", "that they did rend the air exceedingly."]]},
  {num:17,words:[["Ma sa oo i le aso na sosoo ai,", "And it came to pass that on the morrow they did go again to battle,"], ["sa latou toe o atu e tau,", "and great and terrible was that day;"], ["ma sa tele ma matautia lena aso;", "nevertheless,"], ["e ui i lea,", "they conquered not,"], ["sa latou le manumalo, ma ina ua toe oo mai le po sa latou saeia le ea ia latou tagi,", "and  when the night came again they did rend the air with their cries,"], ["ma a latou uio,", "and their howlings,"], ["ma a latou faavauvauga,", "and their mournings,"], ["mo le toesea o o latou tagata ua fasiotia.", "for the loss of the slain of their people."]]},
  {num:18,words:[["Ma sa oo ina toe tusi atu e Korianetuma se tusi ia Sesa,", "And it came to pass that Coriantumr wrote again an epistle unto Shiz,"], ["ua manao mai ia aua nei toe sau e tau,", "desiring that he would not come again to battle,"], ["ae ia ona ave le malo,", "but that he would take the kingdom,"], ["ma faasao ola o tagata.", "and spare the lives of the people."]]},
  {num:19,words:[["Ae faauta,", "And behold,"], ["ua le toe taumafai le Agaga o le Alii ia te i latou,", "the Spirit of the Lord had ceased striving with them,"], ["ma ua maua e Satani le mana atoa i loto o tagata; ona ua tuu atu i latou i le maaa o o latou loto,", "and Satan had full power over the hearts of the people;"], ["ma le tauaso o o latou mafaufau,", "for they were given up unto the hardness of their hearts,"], ["ina ia faaumatiaina i latou;", "and the blindness of their minds that they might be destroyed;"], ["o le mea lea na latou toe o atu ai e tau.", "wherefore they went again to battle."]]},
  {num:20,words:[["Ma sa oo ina latou tau i lena aso atoa,", "And it came to pass that they fought all that day,"], ["ma ina ua oo mai le po sa latou momoe i luga o a latou pelu.", "and when the night came they slept upon their swords."]]},
  {num:21,words:[["Ma o le aso na sosoo ai sa latou tau seia oo mai le po.", "And on the morrow they fought even until the night came."]]},
  {num:22,words:[["Ma ina ua oo mai le po sa latou onana i le ita,", "And when the night came they were drunken with anger,"], ["e pei o se tagata o le ua ona i le uaina;", "even as a man who is drunken with wine;"], ["ma sa latou toe momoe i luga o a latou pelu.", "and they slept again upon their swords."]]},
  {num:23,words:[["Ma o le aso na sosoo ai sa latou toe tau;", "And on the morrow they fought again;"], ["ma ina ua oo mai le po ua latou pauu uma i le pelu vagana ai le lima sefulu ma le lua o tagata o Korianetuma,", "and when the night came they had all fallen by the sword save it were fifty and two of the people of Coriantumr,"], ["ma le ono sefulu ma le iva o tagata o Sesa.", "and sixty and nine of the people of Shiz."]]},
  {num:24,words:[["Ma sa oo ina latou momoe i luga o a latou pelu i le po lena,", "And it came to pass that they slept upon their swords that night,"], ["ma o le aso na sosoo ai sa latou toe tau,", "and on the morrow they fought again,"], ["ma sa latou tau ma lo latou malosi ia latou pelu ma a latou talita,", "and they contended in their might with their swords and with their shields,"], ["i le aso atoa lena.", "all that day."]]},
  {num:25,words:[["Ma ina ua oo mai le po sa totoe le tolu sefulu ma le lua o tagata o Sesa,", "And when the night came there were thirty and two of the people of Shiz,"], ["ma le lua sefulu ma le fitu o tagata o Korianetuma.", "and twenty and seven of the people of Coriantumr."]]},
  {num:26,words:[["Ma sa oo ina latou aai ma momoe,", "And it came to pass that they ate and slept,"], ["ma sauniuni mo le oti i le aso na sosoo ai. Ma o i latou o ni tagata tino tetele ma malolosi e tusa ma le malolosi o tagata.", "and prepared for death on the morrow. And they were large and mighty men as to the strength of men."]]},
  {num:27,words:[["Ma sa oo ina latou tau mo le va o le tolu itula,", "And it came to pass that they fought for the space of three hours,"], ["ma sa latou matapogia i le toto masaa.", "and they fainted with the loss of blood."]]},
  {num:28,words:[["Ma sa oo ina ua lava le malosi na maua e tagata o Korianetuma e mafai ai ona latou savavali,", "And it came to pass that when the men of Coriantumr had received sufficient strength that they could walk,"], ["sa fai o le a latou sosola mo o latou ola; ae faauta,", "they were about to flee for their lives;"], ["sa tu ae Sesa,", "but behold,"], ["ma ana tagata foi,", "Shiz arose,"], ["ma ia tauto i lona ita, o le a ia fasiotia Korianetuma,", "and also his men,"], ["a leai o le a fano o ia i le pelu.", "and he swore in his wrath that he would slay Coriantumr or he would perish by the sword."]]},
  {num:29,words:[["O le mea lea,", "Wherefore,"], ["na ia tuliloa ai i latou,", "he did pursue them,"], ["ma o le aso na sosoo ai na ia maua mai ai i latou;", "and on the morrow he did overtake them;"], ["ma sa latou toe tau i le pelu. Ma sa oo ina ua latou pauu uma i le pelu,", "and they fought again with the sword. And it came to pass that when they had all fallen by the sword,"], ["vagana ai Korianetuma ma Sesa,", "save it were Coriantumr and Shiz,"], ["faauta sa matapogia Sesa i le toto masaa.", "behold Shiz had fainted with the loss of blood."]]},
  {num:30,words:[["Ma sa oo ina ua uma ona totoo o Korianetuma i luga o lana pelu,", "And it came to pass that when Coriantumr had leaned upon his sword,"], ["seia malolo laitiiti o ia,", "that he rested a little,"], ["ona ia vavae ese lea o le ulu o Sesa.", "he smote off the head of Shiz."]]},
  {num:31,words:[["Ma sa oo ina ua uma ona ia vavae ese o le ulu o Sesa,", "And it came to pass that after he had smitten off the head of Shiz,"], ["sa tau tu tee ae Sesa i luga i ona lima ma pau ai;", "that Shiz raised upon his hands and fell;"], ["ina ua uma ona fiti o ia mo le manava,", "and after that he had struggled for breath,"], ["sa oti o ia.", "he died."]]},
  {num:32,words:[["Ma sa oo ina pau Korianetuma i le eleele,", "And it came to pass that Coriantumr fell to the earth,"], ["ma avea e peiseai ua leai se ola o ia te ia.", "and became as if he had no life."]]},
  {num:33,words:[["Ma sa fetalai mai le Alii ia Eteru,", "And the Lord spake unto Ether,"], ["ma fofoga mai ia te ia:", "and said unto him:"], ["Alu atu ia. Ma sa alu atu o ia,", "Go forth. And he went forth,"], ["ma vaai ua faataunuuina afioga uma a le Alii;", "and beheld that the words of the Lord had all been fulfilled;"], ["ma sa ia faaumaina lana talafaamaumau ;", "and he finished his record;"], ["(ma ua ou le tusia se tasi vaeselau) ma sa ia natiaina i latou i se ala na maua ai e tagata o Limae.", "(and the hundredth part I have not written) and he hid them in a manner that the people of Limhi did find them."]]},
  {num:34,words:[["O lenei o upu mulimuli nei na tusia e Eteru :", "Now the last words which are written by Ether are these:"], ["Pe finagalo le Alii ia ou liua,", "Whether the Lord will that I be translated,"], ["pe ou te mafatia i le finagalo o le Alii i la le tino,", "or that I suffer the will of the Lord in the flesh,"], ["e le afaina,", "it mattereth not,"], ["pe afai e faaolaina au i le malo o le Atua. Amene.", "if it so be that I am saved in the kingdom of God. Amen."]]},
];
renderVerseSet(et_ch_15_Verses, 'et-ch15-verses');

})();